_ACTIVE_OUTER_TASK_COUNT_ENV = "APEX_ACTIVE_OUTER_TASK_COUNT"
_WAITING_OUTER_TASK_COUNT_ENV = "APEX_WAITING_OUTER_TASK_COUNT"
_CLAUDE_INTERNET_MODE_MARKER = "internet-mode-used_DO_NOT_REMOVE_MANUALLY_SECURITY_RISK"
_DEFAULT_ROLLOUT_EXECUTOR_SHUTDOWN_GRACE_SECONDS = 30.0
_BROAD_QUICK_VERIFICATION_LOCKS: dict[str, threading.Lock] = {}
_BROAD_QUICK_VERIFICATION_LOCKS_GUARD = threading.Lock()


def _runtime_outer_task_parallelism(
    configured_outer_task_parallelism: int,
) -> tuple[int, Optional[int], Optional[int], bool]:
    configured = max(1, int(configured_outer_task_parallelism or 1))
    try:
        active_count = int(os.environ.get(_ACTIVE_OUTER_TASK_COUNT_ENV, "") or 0)
    except ValueError:
        active_count = 0
    try:
        waiting_count = int(os.environ.get(_WAITING_OUTER_TASK_COUNT_ENV, "") or 0)
    except ValueError:
        waiting_count = 0
    active = active_count if active_count > 0 else None
    waiting = waiting_count if waiting_count >= 0 else None
    if active is None:
        return configured, active, waiting, False
    if waiting_count > 0:
        return configured, active, waiting, False
    effective = max(1, min(configured, active))
    return effective, active, waiting, effective != configured


class _AbandonableThreadPoolExecutor(ThreadPoolExecutor):
    """Thread pool whose abandoned workers do not block interpreter shutdown."""

    def _adjust_thread_count(self) -> None:
        if _thread_pool_worker is None:
            super()._adjust_thread_count()
            return
        if self._idle_semaphore.acquire(timeout=0):
            return

        def weakref_cb(
            _,
            q=self._work_queue,
        ) -> None:
            q.put(None)

        num_threads = len(self._threads)
        if num_threads >= self._max_workers:
            return
        thread_name = "%s_%d" % (self._thread_name_prefix or self, num_threads)
        worker = threading.Thread(
            name=thread_name,
            target=_thread_pool_worker,
            args=(
                weakref.ref(self, weakref_cb),
                self._work_queue,
                self._initializer,
                self._initargs,
            ),
            daemon=True,
        )
        worker.start()
        self._threads.add(worker)


def _path_has_claude_internet_mode_marker(path: str | Path) -> bool:
    """Return True when Claude will block air-gapped runs under this path."""

    try:
        current = Path(path).expanduser().resolve(strict=False)
    except OSError:
        current = Path(path).expanduser().absolute()
    for candidate in (current, *current.parents):
        if (candidate / ".claude" / _CLAUDE_INTERNET_MODE_MARKER).exists():
            return True
    return False


def _config_may_run_air_gapped_claude(config: ApexConfig) -> bool:
    if str(os.environ.get("APEX_FORCE_CLI_INTERNET") or "").strip().lower() in {
        "1",
        "true",
        "yes",
        "on",
    }:
        return False
    for llm_config in list(getattr(config, "llm_configs", []) or []):
        if getattr(llm_config, "backend", None) is LLMBackend.CLAUDE_CLI:
            return True
    rollout_cfg = getattr(config, "rollout", None)
    for candidate in list(getattr(rollout_cfg, "standalone_anchor_candidates", []) or []):
        if isinstance(candidate, dict):
            backend = candidate.get("backend")
        else:
            backend = getattr(candidate, "backend", None)
        if str(backend or "").strip() == LLMBackend.CLAUDE_CLI.value:
            return True
    return False


def _detached_rollout_workspace_root() -> Path:
    override = str(os.environ.get("APEX_ROLLOUT_WORKSPACE_ROOT") or "").strip()
    if override:
        root = Path(override).expanduser()
    else:
        cli_state_home = str(os.environ.get("APEX_CLI_STATE_HOME") or "").strip()
        if cli_state_home:
            root = Path(cli_state_home).expanduser() / "rollout_workspaces"
        else:
            home = str(os.environ.get("HOME") or "").strip()
            if home:
                root = Path(home).expanduser() / ".cache" / "apex" / "rollout_workspaces"
            else:
                root = Path(tempfile.gettempdir()) / "apex" / "rollout_workspaces"
    root.mkdir(parents=True, exist_ok=True)
    return root


def _workspace_base_for_rollout_scratch(config: ApexConfig, configured_base: str | Path) -> str:
    base = Path(configured_base).expanduser()
    if _config_may_run_air_gapped_claude(config) and _path_has_claude_internet_mode_marker(base):
        detached_root = _detached_rollout_workspace_root()
        if not _path_has_claude_internet_mode_marker(detached_root):
            logger.info(
                "Using detached rollout workspace root %s because configured root %s is under "
                "a Claude internet-mode marker.",
                detached_root,
                base,
            )
            return str(detached_root)
    return str(base)


def _rollout_executor_shutdown_grace_seconds() -> float:
    raw = str(os.environ.get("APEX_ROLLOUT_EXECUTOR_SHUTDOWN_GRACE_SECONDS") or "").strip()
    if raw:
        try:
            return max(0.0, float(raw))
        except ValueError:
            logger.warning(
                "Ignoring invalid APEX_ROLLOUT_EXECUTOR_SHUTDOWN_GRACE_SECONDS=%r",
                raw,
            )
    return _DEFAULT_ROLLOUT_EXECUTOR_SHUTDOWN_GRACE_SECONDS


# Audit H2: every git subprocess in this module now flows through this
# default. The audit found ~30 ``_safe_subprocess_run(["git", ...])`` calls
# without ``timeout=``; on a hung ``git fetch`` or ``git apply`` the
# whole rollout would block indefinitely. 300s is generous enough for
# the largest commit0 / sympy / django repos but tight enough that a
# stuck operation surfaces a TimeoutExpired we can recover from.
# Headroom for giant from-stub patch generation: a `git diff --binary` over a
# 500+-changed-file tree (e.g. statsmodels solved from stubs) overran the old
# flat 300s and lost the candidate (run #62 rollout_3). This is a pure KILL
# ceiling for git subprocesses — never an accept signal and never affects
# correctness — so a generous bound only rescues legitimate large diffs while
# still bounding a truly-hung git; per-rollout progress liveness catches real
# deadlock independently. Layer-A general (size of any repo, not a Commit0 fact).
_GIT_SUBPROCESS_DEFAULT_TIMEOUT_SECONDS: float = 1200.0
_GENERIC_SUBPROCESS_DEFAULT_TIMEOUT_SECONDS: float = 60.0


def _safe_subprocess_run(
    cmd,
    *,
    default_timeout: float = _GENERIC_SUBPROCESS_DEFAULT_TIMEOUT_SECONDS,
    **kwargs,
):
    """Wrap ``subprocess.run`` with a default ``timeout=`` when the caller
    didn't supply one. The wrapped call still raises
    ``subprocess.TimeoutExpired`` on overrun so callers can convert it
    into a recoverable diagnostic. Any explicit ``timeout=`` is honored.

    The first argument's leading token decides the default: git commands
    get the (longer) git default; everything else gets the generic one.
    """

    if "timeout" not in kwargs or kwargs.get("timeout") is None:
        leading_token = ""
        try:
            leading_token = str(cmd[0]) if cmd else ""
        except Exception:
            leading_token = ""
        if leading_token == "git":
            kwargs["timeout"] = _GIT_SUBPROCESS_DEFAULT_TIMEOUT_SECONDS
        else:
            kwargs["timeout"] = default_timeout
    return subprocess.run(cmd, **kwargs)


