@dataclass
class RolloutResult:
    """Result from one rollout attempt."""

    rollout_id: int
    success: bool
    patch: Optional[str] = None
    explanation: Optional[str] = None
    changed_files: list[str] = field(default_factory=list)
    trajectory: list[dict[str, Any]] = field(default_factory=list)
    worktree_path: Optional[str] = None
    temperature: float = 0.0
    prompt_strategy: str = "comprehensive"
    llm_model: str = ""
    agent_mode: str = ""
    plan_title: str = ""
    allocation_key: str = ""
    total_tokens: int = 0
    duration_seconds: float = 0.0
    reproduction_artifact: dict[str, Any] = field(default_factory=dict)
    localization_artifact: dict[str, Any] = field(default_factory=dict)
    patch_artifact: dict[str, Any] = field(default_factory=dict)
    test_suite_artifact: dict[str, Any] = field(default_factory=dict)
    test_suite: Optional[str] = None
    test_descriptions: list[str] = field(default_factory=list)
    baseline_commit: Optional[str] = None
    best_checkpoint_id: Optional[str] = None
    execution_tree: Optional[dict[str, Any]] = None
    verification: Optional[dict[str, Any]] = None
    selection_diagnostics: dict[str, Any] = field(default_factory=dict)
    selected_for_submission: bool = False
    internally_accepted: bool = False
    officially_accepted: Optional[bool] = None
    salvaged_for_external_scoring: bool = False
    quick_verification: dict[str, Any] = field(default_factory=dict)
    progress_score: float = 0.0
    progress_details: dict[str, float] = field(default_factory=dict)
    failure_reason: Optional[str] = None
    is_synthetic: bool = False
    multi_agent_summary: dict[str, Any] = field(default_factory=dict)
    source_rollout_ids: list[int] = field(default_factory=list)
    search_metadata: dict[str, Any] = field(default_factory=dict)
    rollout_profile_index: Optional[int] = None
    rollout_profile_signature: list[str] = field(default_factory=list)
    stage_model_routing: dict[str, str] = field(default_factory=dict)
    validity: Optional[CandidateValidity] = None
    # Phase 0.1: coarse, orchestrator-wide failure taxonomy. Populated
    # when the rollout fails for an env / harness / agent reason; remains
    # ``None`` for successful rollouts. ``failure_class`` is a denormalised
    # mirror of ``failure_classification.failure_class`` for cheap filtering.
    failure_class: Optional["CoreFailureClass"] = None
    failure_classification: Optional["CoreClassificationResult"] = None

    def to_dict(self) -> dict[str, Any]:
        return {
            "rollout_id": self.rollout_id,
            "success": self.success,
            "patch": self.patch,
            "explanation": self.explanation,
            "changed_files": list(self.changed_files),
            "worktree_path": self.worktree_path,
            "temperature": self.temperature,
            "prompt_strategy": self.prompt_strategy,
            "llm_model": self.llm_model,
            "agent_mode": self.agent_mode,
            "plan_title": self.plan_title,
            "allocation_key": self.allocation_key,
            "total_tokens": self.total_tokens,
            "duration_seconds": self.duration_seconds,
            "reproduction_artifact": self.reproduction_artifact,
            "localization_artifact": self.localization_artifact,
            "patch_artifact": self.patch_artifact,
            "test_suite_artifact": self.test_suite_artifact,
            "test_suite": self.test_suite,
            "test_descriptions": list(self.test_descriptions),
            "baseline_commit": self.baseline_commit,
            "best_checkpoint_id": self.best_checkpoint_id,
            "execution_tree": self.execution_tree,
            "verification": self.verification,
            "selection_diagnostics": dict(self.selection_diagnostics),
            "selected_for_submission": bool(self.selected_for_submission),
            "internally_accepted": bool(self.internally_accepted),
            "officially_accepted": self.officially_accepted,
            "salvaged_for_external_scoring": bool(self.salvaged_for_external_scoring),
            "quick_verification": dict(self.quick_verification),
            "progress_score": self.progress_score,
            "progress_details": dict(self.progress_details),
            "failure_reason": self.failure_reason,
            "is_synthetic": self.is_synthetic,
            "multi_agent_summary": dict(self.multi_agent_summary),
            "source_rollout_ids": list(self.source_rollout_ids),
            "search_metadata": dict(self.search_metadata),
            "rollout_profile_index": self.rollout_profile_index,
            "rollout_profile_signature": list(self.rollout_profile_signature),
            "stage_model_routing": dict(self.stage_model_routing),
            "validity": (self.validity.as_dict() if self.validity is not None else None),
            "failure_class": (self.failure_class.value if self.failure_class is not None else None),
            "failure_classification": (
                self.failure_classification.to_dict()
                if self.failure_classification is not None
                else None
            ),
        }


