class _TestGenerationExecutionResult:
    """Structured result returned by milestone-aware test generation."""

    submission: dict[str, Any] = field(default_factory=dict)
    artifact: Optional[TestSuiteArtifact] = None
    tokens_used: int = 0
    trajectory: list[dict[str, Any]] = field(default_factory=list)
    loop_summary: dict[str, Any] = field(default_factory=dict)


class _CLIStageFailure(RuntimeError):
    """Structured failure from one CLI-backed rollout stage."""

    def __init__(
        self,
        reason: str,
        *,
        stage_name: str,
        timeout_audit: Optional[dict[str, Any]] = None,
        backend_anomaly: Optional[dict[str, Any]] = None,
        output_excerpt: str = "",
    ) -> None:
        super().__init__(reason)
        self.reason = str(reason or "")
        self.stage_name = str(stage_name or "")
        self.timeout_audit = dict(timeout_audit or {})
        self.backend_anomaly = dict(backend_anomaly or {})
        self.output_excerpt = str(output_excerpt or "")


class _RolloutCancelled(RuntimeError):
    """Cooperative cancellation signal for abandoned rollout workers."""

    def __init__(self, reason: str, *, phase: str = "orchestration") -> None:
        super().__init__(reason)
        self.reason = str(reason or "rollout cancelled by scheduler")
        self.phase = str(phase or "orchestration")


def _rollout_cancel_requested(cancel_check: Optional[Callable[[], bool]]) -> bool:
    if cancel_check is None:
        return False
    try:
        return bool(cancel_check())
    except Exception:  # noqa: BLE001 - cancellation probes must never break rollout work
        logger.exception("Rollout cancellation check failed.")
        return False


def _rollout_cancel_reason(
    cancel_reason: Optional[Callable[[], str]],
    *,
    default: str,
) -> str:
    if cancel_reason is None:
        return default
    try:
        reason = str(cancel_reason() or "").strip()
    except Exception:  # noqa: BLE001 - cancellation reason is diagnostic only
        logger.exception("Rollout cancellation reason lookup failed.")
        reason = ""
    return reason or default


def _raise_if_rollout_cancelled(
    cancel_check: Optional[Callable[[], bool]],
    cancel_reason: Optional[Callable[[], str]],
    *,
    phase: str,
    default_reason: str,
) -> None:
    if not _rollout_cancel_requested(cancel_check):
        return
    raise _RolloutCancelled(
        _rollout_cancel_reason(cancel_reason, default=default_reason),
        phase=phase,
    )


