def _request_workspace_seed_for_index(
    index: int,
    *,
    workspace_seed: Optional[WorkspaceSeed] = None,
    workspace_seeds: Optional[list[Optional[WorkspaceSeed]]] = None,
) -> Optional[WorkspaceSeed]:
    if workspace_seeds:
        return workspace_seeds[index % len(workspace_seeds)]
    return workspace_seed


@dataclass
class Discovery:
    """One append-only discovery shared across rollouts."""

    rollout_id: int
    timestamp: float
    insight_type: str
    description: str
    provenance: str = "agent_generated"
    confidence: float = 0.7
    file_paths: list[str] = field(default_factory=list)
    symbols: list[str] = field(default_factory=list)
    test_ids: list[str] = field(default_factory=list)
    stage_name: str = ""
    evidence_mode: str = ""
    negative: bool = False
    payload: dict[str, Any] = field(default_factory=dict)


_PRIOR_ROLLOUT_ID_SENTINEL = -1
"""Reserved rollout id used for cross-solve prior insights.

Persistent per-repo memory replays previously-validated rollout
discoveries on the next solve as ``Discovery`` records with a negative
rollout id. The query path filters these in/out via
``exclude_rollout_id`` and a callable predicate on ``rollout_id < 0`` so
that intra-solve consumers cannot mistake a prior for a fresh
observation made by a sibling rollout in this batch.
"""


class EpisodicMemoryBus:
    """Thread-safe append-only memory bus for rollout discoveries."""

    def __init__(self) -> None:
        self._discoveries: list[Discovery] = []
        self._lock = threading.Lock()
        self._prior_seed_count: int = 0

    @property
    def prior_seed_count(self) -> int:
        """Number of cross-solve prior insights currently in the bus.

        Persistent repo memory uses this to surface ``prior_insight_count``
        in the solve result so reviewers can audit how much of a benchmark
        score came from priors vs fresh inference.
        """

        return self._prior_seed_count

    def seed_priors(self, prior_insights: list[dict[str, Any]]) -> int:
        """Pre-load decayed prior insights from a persistent store.

        Each item must be a dict with ``insight_type``, ``description``,
        ``confidence``, and optional ``file_paths``/``symbols``/
        ``test_ids``/``stage_name``/``negative`` fields. Stored under a
        reserved negative ``rollout_id`` so intra-solve consumers can
        filter them with ``positive_only`` / ``negative_only`` while
        still benefiting from the priors during context formatting.
        """

        if not prior_insights:
            return 0
        added = 0
        with self._lock:
            for index, payload in enumerate(prior_insights):
                if not isinstance(payload, dict):
                    continue
                description = str(payload.get("description") or "").strip()
                insight_type = str(payload.get("insight_type") or "").strip()
                if not description or not insight_type:
                    continue
                self._discoveries.append(
                    Discovery(
                        rollout_id=_PRIOR_ROLLOUT_ID_SENTINEL - index,
                        timestamp=time.time(),
                        insight_type=insight_type,
                        description=description,
                        provenance=str(payload.get("provenance") or "verified").strip().lower(),
                        confidence=float(payload.get("confidence") or 0.0),
                        file_paths=self._normalize_strings(payload.get("file_paths")),
                        symbols=self._normalize_strings(payload.get("symbols")),
                        test_ids=self._normalize_strings(payload.get("test_ids")),
                        stage_name=str(payload.get("stage_name") or "").strip(),
                        evidence_mode=str(payload.get("evidence_mode") or "").strip(),
                        negative=bool(payload.get("negative")),
                        payload={
                            "from_persistent_store": True,
                            "support_count": int(payload.get("support_count") or 1),
                        },
                    )
                )
                added += 1
            self._prior_seed_count += added
        return added

    def extract_durable_insights(
        self,
        *,
        accepted_rollout_ids: Optional[set[int]] = None,
        min_confidence: float = 0.65,
        min_support_count: int = 1,
        max_items: int = 64,
    ) -> list[dict[str, Any]]:
        """Return high-quality insights worth persisting across solves.

        Insights are de-duplicated by signature first, support_count
        reflects how many distinct rollouts produced the same belief,
        and the result is sorted by ``(support_count desc, confidence
        desc)``. Prior-seeded entries (negative rollout ids) are
        included so that priors that DID get reconfirmed this solve
        keep their support count growing.
        """

        with self._lock:
            discoveries = list(self._discoveries)
        signature_to_payload: dict[tuple[Any, ...], dict[str, Any]] = {}
        for item in discoveries:
            description = str(item.description or "").strip()
            insight_type = str(item.insight_type or "").strip()
            if not description or not insight_type:
                continue
            if float(item.confidence) < min_confidence:
                continue
            signature = (
                insight_type.upper(),
                tuple(sorted(self._normalize_strings(item.file_paths))),
                tuple(sorted(self._normalize_strings(item.symbols))),
                tuple(sorted(self._normalize_strings(item.test_ids))),
                bool(item.negative),
                description.lower()[:80],
            )
            existing = signature_to_payload.get(signature)
            from_prior = item.rollout_id < 0
            rollout_set: set[int] = set()
            if existing is not None:
                rollout_set = set(existing.get("_rollout_ids") or set())
            if not from_prior:
                rollout_set.add(int(item.rollout_id))
            if existing is None:
                signature_to_payload[signature] = {
                    "insight_type": insight_type,
                    "description": description,
                    "confidence": float(item.confidence),
                    "file_paths": list(item.file_paths),
                    "symbols": list(item.symbols),
                    "test_ids": list(item.test_ids),
                    "stage_name": str(item.stage_name or ""),
                    "provenance": str(item.provenance or ""),
                    "evidence_mode": str(item.evidence_mode or ""),
                    "negative": bool(item.negative),
                    "_rollout_ids": rollout_set,
                    "_from_prior": from_prior and not rollout_set,
                    "_prior_support": (
                        int(item.payload.get("support_count") or 0)
                        if isinstance(item.payload, dict)
                        else 0
                    )
                    if from_prior
                    else 0,
                }
            else:
                existing["confidence"] = max(float(existing["confidence"]), float(item.confidence))
                existing["file_paths"] = self._normalize_strings(
                    list(existing["file_paths"]) + list(item.file_paths)
                )
                existing["symbols"] = self._normalize_strings(
                    list(existing["symbols"]) + list(item.symbols)
                )
                existing["test_ids"] = self._normalize_strings(
                    list(existing["test_ids"]) + list(item.test_ids)
                )
                existing["_rollout_ids"] = rollout_set
                if from_prior:
                    existing["_prior_support"] = max(
                        int(existing.get("_prior_support") or 0),
                        int(item.payload.get("support_count") or 0)
                        if isinstance(item.payload, dict)
                        else 0,
                    )
                else:
                    existing["_from_prior"] = False
        durable: list[dict[str, Any]] = []
        for payload in signature_to_payload.values():
            rollout_ids: set[int] = set(payload.pop("_rollout_ids", set()) or set())
            from_prior = bool(payload.pop("_from_prior", False))
            prior_support = int(payload.pop("_prior_support", 0) or 0)
            if accepted_rollout_ids is not None and rollout_ids:
                if not rollout_ids.intersection(accepted_rollout_ids):
                    # Allow priors to remain even without acceptance —
                    # they were accepted in a previous solve and decayed
                    # priors are still useful evidence.
                    if not from_prior:
                        continue
            support_count = max(1, len(rollout_ids) + (1 if from_prior else 0))
            if support_count < min_support_count and not from_prior:
                continue
            payload["support_count"] = support_count + max(0, prior_support - 1)
            durable.append(payload)
        durable.sort(
            key=lambda payload: (
                -int(payload.get("support_count") or 0),
                -float(payload.get("confidence") or 0.0),
                str(payload.get("description") or ""),
            ),
        )
        return durable[: max(1, int(max_items))]

    def broadcast(
        self,
        rollout_id: int,
        insight_type: str,
        description: str,
        confidence: float = 0.7,
        *,
        file_paths: Optional[list[str]] = None,
        symbols: Optional[list[str]] = None,
        test_ids: Optional[list[str]] = None,
        stage_name: str = "",
        provenance: str = "agent_generated",
        evidence_mode: str = "",
        negative: bool = False,
        payload: Optional[dict[str, Any]] = None,
    ) -> None:
        normalized_payload = self._normalize_payload(payload, rollout_id=rollout_id)
        with self._lock:
            self._discoveries.append(
                Discovery(
                    rollout_id=rollout_id,
                    timestamp=time.time(),
                    insight_type=insight_type,
                    description=description,
                    provenance=str(provenance or "agent_generated").strip().lower(),
                    confidence=confidence,
                    file_paths=self._normalize_strings(file_paths),
                    symbols=self._normalize_strings(symbols),
                    test_ids=self._normalize_strings(test_ids),
                    stage_name=stage_name.strip(),
                    evidence_mode=str(evidence_mode or "").strip(),
                    negative=bool(negative),
                    payload=normalized_payload,
                )
            )

    def query(
        self,
        exclude_rollout_id: int,
        since_timestamp: Optional[float] = None,
        min_confidence: float = 0.5,
        insight_types: Optional[list[str]] = None,
        file_paths: Optional[list[str]] = None,
        symbols: Optional[list[str]] = None,
        test_ids: Optional[list[str]] = None,
        preferred_file_paths: Optional[list[str]] = None,
        preferred_symbols: Optional[list[str]] = None,
        preferred_test_ids: Optional[list[str]] = None,
        stage_names: Optional[list[str]] = None,
        preferred_stage_names: Optional[list[str]] = None,
        negative_only: bool = False,
        positive_only: bool = False,
        max_items: Optional[int] = None,
    ) -> list[Discovery]:
        normalized_types = {item.strip().upper() for item in (insight_types or []) if item}
        normalized_paths = {item.strip() for item in (file_paths or []) if item}
        normalized_symbols = {item.strip() for item in (symbols or []) if item}
        normalized_test_ids = {item.strip() for item in (test_ids or []) if item}
        normalized_preferred_paths = {item.strip() for item in (preferred_file_paths or []) if item}
        normalized_preferred_symbols = {item.strip() for item in (preferred_symbols or []) if item}
        normalized_preferred_test_ids = {
            item.strip() for item in (preferred_test_ids or []) if item
        }
        normalized_stages = {item.strip().lower() for item in (stage_names or []) if item}
        normalized_preferred_stages = {
            item.strip().lower() for item in (preferred_stage_names or []) if item
        }
        with self._lock:
            discoveries = [
                item
                for item in self._discoveries
                if item.rollout_id != exclude_rollout_id
                and (since_timestamp is None or item.timestamp > since_timestamp)
                and item.confidence >= min_confidence
                and (not normalized_types or item.insight_type.upper() in normalized_types)
                and (not normalized_paths or bool(normalized_paths.intersection(item.file_paths)))
                and (not normalized_symbols or bool(normalized_symbols.intersection(item.symbols)))
                and (
                    not normalized_test_ids or bool(normalized_test_ids.intersection(item.test_ids))
                )
                and (not normalized_stages or item.stage_name.strip().lower() in normalized_stages)
                and (not negative_only or item.negative)
                and (not positive_only or not item.negative)
            ]
        discoveries.sort(
            key=lambda item: (
                -self._relevance_score(
                    item,
                    file_paths=normalized_preferred_paths or normalized_paths,
                    symbols=normalized_preferred_symbols or normalized_symbols,
                    test_ids=normalized_preferred_test_ids or normalized_test_ids,
                    stage_names=normalized_preferred_stages,
                ),
                -item.confidence,
                -item.timestamp,
                item.rollout_id,
            )
        )
        deduped: list[Discovery] = []
        merged_by_signature: dict[tuple[Any, ...], Discovery] = {}
        ordered_signatures: list[tuple[Any, ...]] = []
        for item in discoveries:
            signature = (
                item.insight_type,
                item.description,
                tuple(item.file_paths),
                tuple(item.symbols),
                tuple(item.test_ids),
                item.stage_name,
                item.negative,
            )
            existing = merged_by_signature.get(signature)
            if existing is None:
                merged_by_signature[signature] = Discovery(
                    rollout_id=item.rollout_id,
                    timestamp=item.timestamp,
                    insight_type=item.insight_type,
                    description=item.description,
                    provenance=item.provenance,
                    confidence=item.confidence,
                    file_paths=list(item.file_paths),
                    symbols=list(item.symbols),
                    test_ids=list(item.test_ids),
                    stage_name=item.stage_name,
                    evidence_mode=item.evidence_mode,
                    negative=item.negative,
                    payload=self._normalize_payload(item.payload, rollout_id=item.rollout_id),
                )
                ordered_signatures.append(signature)
                existing = merged_by_signature[signature]
            else:
                existing.timestamp = max(existing.timestamp, item.timestamp)
                existing.confidence = max(existing.confidence, item.confidence)
                existing.file_paths = self._normalize_strings(existing.file_paths + item.file_paths)
                existing.symbols = self._normalize_strings(existing.symbols + item.symbols)
                existing.test_ids = self._normalize_strings(existing.test_ids + item.test_ids)
                existing.payload = self._merge_payloads(
                    existing.payload, item.payload, rollout_id=item.rollout_id
                )
        for signature in ordered_signatures:
            deduped.append(merged_by_signature[signature])
            if max_items is not None and len(deduped) >= max_items:
                break
        return deduped

    def format_for_context(
        self,
        exclude_rollout_id: int,
        since_timestamp: Optional[float] = None,
        *,
        stage_name: str = "",
        file_paths: Optional[list[str]] = None,
        symbols: Optional[list[str]] = None,
        test_ids: Optional[list[str]] = None,
        existing_prompt: str = "",
        max_items: int = 8,
        positive_limit: int = 5,
        negative_limit: int = 3,
    ) -> str:
        positive = self.query(
            exclude_rollout_id=exclude_rollout_id,
            since_timestamp=since_timestamp,
            preferred_file_paths=file_paths,
            preferred_symbols=symbols,
            preferred_test_ids=test_ids,
            preferred_stage_names=[stage_name] if stage_name else None,
            positive_only=True,
            max_items=max(positive_limit, max_items),
        )
        negative = self.query(
            exclude_rollout_id=exclude_rollout_id,
            since_timestamp=since_timestamp,
            preferred_file_paths=file_paths,
            preferred_symbols=symbols,
            preferred_test_ids=test_ids,
            preferred_stage_names=[stage_name] if stage_name else None,
            negative_only=True,
            max_items=max(negative_limit, max_items),
        )
        discoveries = positive[:positive_limit] + negative[:negative_limit]
        if existing_prompt:
            prompt_lower = existing_prompt.lower()
            discoveries = [
                discovery
                for discovery in discoveries
                if not (
                    discovery.description and discovery.description.strip().lower() in prompt_lower
                )
            ]
            allowed_signatures = {
                (
                    discovery.insight_type,
                    discovery.description,
                    tuple(discovery.file_paths),
                    tuple(discovery.symbols),
                    tuple(discovery.test_ids),
                    discovery.stage_name,
                    discovery.negative,
                )
                for discovery in discoveries
            }
            positive = [
                discovery
                for discovery in positive
                if (
                    discovery.insight_type,
                    discovery.description,
                    tuple(discovery.file_paths),
                    tuple(discovery.symbols),
                    tuple(discovery.test_ids),
                    discovery.stage_name,
                    discovery.negative,
                )
                in allowed_signatures
            ]
            negative = [
                discovery
                for discovery in negative
                if (
                    discovery.insight_type,
                    discovery.description,
                    tuple(discovery.file_paths),
                    tuple(discovery.symbols),
                    tuple(discovery.test_ids),
                    discovery.stage_name,
                    discovery.negative,
                )
                in allowed_signatures
            ]
        if len(discoveries) > max_items:
            discoveries = discoveries[:max_items]
        if not discoveries:
            return ""
        lines = ["## Discoveries from parallel agents:"]
        if positive:
            lines.append("Reusable evidence:")
            for discovery in positive[:positive_limit]:
                lines.append(self._format_context_line(discovery))
        if negative:
            lines.append("Ruled-out paths:")
            for discovery in negative[:negative_limit]:
                lines.append(self._format_context_line(discovery))
        return "\n".join(lines)

    @staticmethod
    def _normalize_strings(values: Optional[list[str]]) -> list[str]:
        normalized = []
        for value in values or []:
            text = (value or "").strip()
            if text:
                normalized.append(text)
        return list(dict.fromkeys(normalized))

    @classmethod
    def _normalize_payload(
        cls,
        payload: Optional[dict[str, Any]],
        *,
        rollout_id: int,
    ) -> dict[str, Any]:
        raw = dict(payload or {})
        normalized: dict[str, Any] = {}
        for key, value in raw.items():
            if key == "source_rollout_ids":
                continue
            if isinstance(value, bool):
                normalized[key] = value
            elif isinstance(value, (int, float)) and key != "corroboration_count":
                normalized[key] = value
            elif isinstance(value, (list, tuple, set)):
                normalized[key] = cls._normalize_strings(
                    [str(item) for item in value if str(item).strip()]
                )
            elif value is not None:
                text = str(value).strip()
                if text:
                    normalized[key] = text
        source_rollout_ids = [
            int(item) for item in list(raw.get("source_rollout_ids") or []) if isinstance(item, int)
        ]
        source_rollout_ids.append(int(rollout_id))
        normalized["source_rollout_ids"] = list(dict.fromkeys(source_rollout_ids))
        normalized["corroboration_count"] = len(normalized["source_rollout_ids"])
        return normalized

    @classmethod
    def _merge_payloads(
        cls,
        left: dict[str, Any],
        right: Optional[dict[str, Any]],
        *,
        rollout_id: int,
    ) -> dict[str, Any]:
        merged = cls._normalize_payload(left, rollout_id=rollout_id)
        incoming = cls._normalize_payload(right, rollout_id=rollout_id)
        for key in set(merged).union(incoming):
            left_value = merged.get(key)
            right_value = incoming.get(key)
            if key == "source_rollout_ids":
                merged[key] = list(
                    dict.fromkeys(
                        [
                            int(item)
                            for item in list(left_value or []) + list(right_value or [])
                            if isinstance(item, int)
                        ]
                    )
                )
                continue
            if isinstance(left_value, list) or isinstance(right_value, list):
                merged[key] = cls._normalize_strings(
                    [
                        str(item)
                        for item in list(left_value or []) + list(right_value or [])
                        if str(item).strip()
                    ]
                )
                continue
            if isinstance(left_value, bool) or isinstance(right_value, bool):
                merged[key] = bool(left_value) or bool(right_value)
                continue
            if isinstance(left_value, (int, float)) or isinstance(right_value, (int, float)):
                merged[key] = max(float(left_value or 0.0), float(right_value or 0.0))
                continue
            merged[key] = str(left_value or right_value or "").strip()
        merged["corroboration_count"] = len(list(merged.get("source_rollout_ids") or []))
        return merged

    @staticmethod
    def _payload_preview(payload: dict[str, Any], key: str, *, limit: int = 2) -> str:
        value = payload.get(key)
        if isinstance(value, list):
            items = [str(item).strip() for item in value if str(item).strip()]
            return "; ".join(items[:limit])
        if isinstance(value, str):
            return value.strip()
        return ""

    def _relevance_score(
        self,
        discovery: Discovery,
        *,
        file_paths: set[str],
        symbols: set[str],
        test_ids: set[str],
        stage_names: set[str],
    ) -> float:
        score = float(discovery.confidence)
        corroboration_count = int(discovery.payload.get("corroboration_count") or 1)
        source_families = list(discovery.payload.get("source_families") or [])
        if stage_names and discovery.stage_name.strip().lower() in stage_names:
            score += 0.45
        if file_paths and file_paths.intersection(discovery.file_paths):
            score += 0.35
        if symbols and symbols.intersection(discovery.symbols):
            score += 0.25
        if test_ids and test_ids.intersection(discovery.test_ids):
            score += 0.25
        score += 0.12 * min(max(corroboration_count - 1, 0), 3)
        score += 0.08 * min(max(len(source_families) - 1, 0), 3)
        if bool(discovery.payload.get("independently_verified")):
            score += 0.12
        if not discovery.negative:
            score += 0.05
        return score

    def _format_context_line(self, discovery: Discovery) -> str:
        metadata = []
        corroboration_count = int(discovery.payload.get("corroboration_count") or 1)
        if corroboration_count > 1:
            metadata.append(f"corroborated: {corroboration_count}")
        if discovery.stage_name:
            metadata.append(f"stage: {discovery.stage_name}")
        if discovery.provenance:
            metadata.append(f"provenance: {discovery.provenance}")
        if discovery.evidence_mode:
            metadata.append(f"mode: {discovery.evidence_mode}")
        if discovery.file_paths:
            metadata.append("files: " + ", ".join(discovery.file_paths[:3]))
        if discovery.symbols:
            metadata.append("symbols: " + ", ".join(discovery.symbols[:3]))
        if discovery.test_ids:
            metadata.append("tests: " + ", ".join(discovery.test_ids[:3]))
        if bool(discovery.payload.get("independently_verified")):
            metadata.append("verified")
        suffix = f" ({'; '.join(metadata)})" if metadata else ""
        prefix = "ruled out" if discovery.negative else discovery.insight_type
        line = f"- [{prefix}] {discovery.description}{suffix}"
        evidence = self._payload_preview(discovery.payload, "evidence")
        decisions = self._payload_preview(discovery.payload, "decisions")
        assumptions = self._payload_preview(discovery.payload, "assumptions", limit=1)
        rejected = self._payload_preview(discovery.payload, "rejected_paths")
        if evidence:
            line += f" | evidence: {evidence}"
        if decisions:
            line += f" | decisions: {decisions}"
        if assumptions:
            line += f" | assumptions: {assumptions}"
        if rejected:
            line += f" | rejected: {rejected}"
        return line


@dataclass
class WorkspaceMetadata:
    """Bookkeeping for one rollout workspace."""

    mode: str
    branch_name: Optional[str]
    baseline_commit: str


@dataclass
class ExecutionNode:
    """One checkpointed state inside a rollout search tree."""

    node_id: str
    parent_id: Optional[str]
    commit_hash: str
    depth: int
    context_summary: str
    action_taken: str
    value_score: float = 0.0
    test_pass_count: int = 0
    test_fail_count: int = 0
    is_terminal: bool = False
    children: list[str] = field(default_factory=list)


class ExecutionTree:
    """Git-backed checkpoint tree for one rollout workspace."""

    def __init__(
        self,
        worktree_path: str,
        baseline_commit: str,
        max_depth: int = 5,
        max_branches: int = 3,
    ) -> None:
        self.worktree_path = Path(worktree_path).resolve()
        self.baseline_commit = baseline_commit
        self.max_depth = max_depth
        self.max_branches = max_branches
        self.nodes: dict[str, ExecutionNode] = {}
        self.root_id: Optional[str] = None
        self.current_node_id: Optional[str] = None
        self.best_terminal_id: Optional[str] = None

    def initialize(self, context_summary: str = "Initial state before any edits.") -> str:
        if self.root_id is not None:
            return self.root_id
        commit_hash = self._git_commit("APEX checkpoint: root")
        node_id = self._new_node_id()
        root = ExecutionNode(
            node_id=node_id,
            parent_id=None,
            commit_hash=commit_hash,
            depth=0,
            context_summary=context_summary,
            action_taken="root",
        )
        self.nodes[node_id] = root
        self.root_id = node_id
        self.current_node_id = node_id
        return node_id

    def checkpoint(
        self,
        *,
        context_summary: str,
        action_taken: str,
        value_score: float,
        test_pass: int = 0,
        test_fail: int = 0,
        is_terminal: Optional[bool] = None,
    ) -> tuple[str, bool]:
        if self.current_node_id is None:
            self.initialize()
        assert self.current_node_id is not None  # for type-checkers
        parent = self.nodes[self.current_node_id]
        if parent.depth >= self.max_depth or len(parent.children) >= self.max_branches:
            return parent.node_id, False

        commit_hash = self._git_commit(f"APEX checkpoint: {action_taken[:50]}")
        node_id = self._new_node_id()
        node = ExecutionNode(
            node_id=node_id,
            parent_id=parent.node_id,
            commit_hash=commit_hash,
            depth=parent.depth + 1,
            context_summary=context_summary,
            action_taken=action_taken,
            value_score=value_score,
            test_pass_count=max(test_pass, 0),
            test_fail_count=max(test_fail, 0),
            is_terminal=(
                is_terminal if is_terminal is not None else (test_fail == 0 and test_pass > 0)
            ),
        )
        self.nodes[node_id] = node
        parent.children.append(node_id)
        self.current_node_id = node_id
        self._consider_best(node)
        return node_id, True

    def mark_current_state(
        self,
        *,
        context_summary: str,
        action_taken: str,
        value_score: float,
        test_pass: int = 0,
        test_fail: int = 0,
        is_terminal: bool = False,
    ) -> str:
        if self.current_node_id is None:
            return self.initialize(context_summary=context_summary)
        node = self.nodes[self.current_node_id]
        node.context_summary = context_summary or node.context_summary
        node.action_taken = action_taken or node.action_taken
        node.value_score = max(node.value_score, value_score)
        node.test_pass_count = max(node.test_pass_count, test_pass)
        node.test_fail_count = (
            test_fail if test_fail or node.test_fail_count == 0 else node.test_fail_count
        )
        node.is_terminal = node.is_terminal or is_terminal
        self._consider_best(node)
        return node.node_id

    def list_checkpoint_ids(self) -> list[str]:
        return list(self.nodes)

    def has_workspace_changes(self) -> bool:
        return bool(
            list_git_changed_files(
                self.worktree_path,
                ignored_predicate=_is_ignored_artifact,
            )
        )

    def best_node_id(self) -> Optional[str]:
        if self.best_terminal_id is not None:
            return self.best_terminal_id
        candidates = [node for node in self.nodes.values() if node.node_id != self.root_id]
        if not candidates:
            return None
        best = max(
            candidates,
            key=lambda node: (
                node.value_score,
                node.test_pass_count,
                -node.test_fail_count,
                node.depth,
            ),
        )
        return best.node_id

    def restore_best_state(self) -> Optional[str]:
        target_node_id = self.best_node_id()
        if target_node_id is None:
            return None
        target = self.nodes[target_node_id]
        if target_node_id == self.current_node_id and self._workspace_matches_node(target):
            return target_node_id
        if self.backtrack(target_node_id):
            return target_node_id
        return None

    def _workspace_matches_node(self, node: ExecutionNode) -> bool:
        head = _safe_subprocess_run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            cwd=str(self.worktree_path),
            check=False,
        )
        if head.returncode != 0:
            return False
        if str(head.stdout or "").strip() != str(node.commit_hash or "").strip():
            return False
        return not self.has_workspace_changes()

    def backtrack(self, target_node_id: str) -> bool:
        if target_node_id not in self.nodes:
            return False
        target = self.nodes[target_node_id]
        reset = _safe_subprocess_run(
            ["git", "reset", "--hard", target.commit_hash],
            capture_output=True,
            cwd=str(self.worktree_path),
            check=False,
        )
        if reset.returncode != 0:
            return False
        _safe_subprocess_run(
            ["git", "clean", "-fd"],
            capture_output=True,
            cwd=str(self.worktree_path),
            check=False,
        )
        self.current_node_id = target_node_id
        return True

    def to_dict(self) -> dict[str, Any]:
        return {
            "baseline_commit": self.baseline_commit,
            "root_id": self.root_id,
            "current_node_id": self.current_node_id,
            "best_checkpoint_id": self.best_node_id(),
            "nodes": {
                node_id: {
                    "parent_id": node.parent_id,
                    "commit_hash": node.commit_hash,
                    "depth": node.depth,
                    "context_summary": node.context_summary,
                    "action_taken": node.action_taken,
                    "value_score": node.value_score,
                    "test_pass_count": node.test_pass_count,
                    "test_fail_count": node.test_fail_count,
                    "is_terminal": node.is_terminal,
                    "children": list(node.children),
                }
                for node_id, node in self.nodes.items()
            },
        }

    def _consider_best(self, node: ExecutionNode) -> None:
        if not node.is_terminal:
            return
        if self.best_terminal_id is None:
            self.best_terminal_id = node.node_id
            return
        best = self.nodes[self.best_terminal_id]
        if (
            node.value_score,
            node.test_pass_count,
            -node.test_fail_count,
        ) > (
            best.value_score,
            best.test_pass_count,
            -best.test_fail_count,
        ):
            self.best_terminal_id = node.node_id

    def _git_commit(self, message: str) -> str:
        self._ensure_git_identity()
        _safe_subprocess_run(
            ["git", "add", "-A", "--", ".", *ignored_change_pathspecs()],
            capture_output=True,
            cwd=str(self.worktree_path),
            check=False,
        )
        result = _safe_subprocess_run(
            ["git", "commit", "--allow-empty", "-m", message],
            capture_output=True,
            text=True,
            cwd=str(self.worktree_path),
            check=False,
        )
        if result.returncode != 0:
            raise RuntimeError(
                result.stderr.strip() or result.stdout.strip() or "git commit failed"
            )
        head = _safe_subprocess_run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            cwd=str(self.worktree_path),
            check=False,
        )
        return head.stdout.strip()

    def _ensure_git_identity(self) -> None:
        for key, value in {
            "user.email": "apex@example.com",
            "user.name": "APEX",
        }.items():
            existing = _safe_subprocess_run(
                ["git", "config", key],
                capture_output=True,
                text=True,
                cwd=str(self.worktree_path),
                check=False,
            )
            if existing.returncode == 0 and existing.stdout.strip():
                continue
            _safe_subprocess_run(
                ["git", "config", key, value],
                capture_output=True,
                cwd=str(self.worktree_path),
                check=False,
            )

    def _new_node_id(self) -> str:
        return uuid.uuid4().hex[:8]


def _resolve_head_commit(path: Path) -> str:
    result = _safe_subprocess_run(
        ["git", "rev-parse", "HEAD"],
        capture_output=True,
        text=True,
        cwd=str(path),
        check=False,
    )
    return result.stdout.strip()


class ConcurrentWorktreeError(RuntimeError):
    """Raised when two engines try to claim the same per-rollout workspace.

    Phase 2.1: ``GitWorktreeManager.create_worktree`` used to silently nuke
    the existing ``rollout_<id>`` directory if it found one, which meant two
    concurrent ``solve()`` calls sharing a workspace_dir destroyed each
    other's worktrees. We now hold an ``fcntl`` lock on the rollout id and
    raise this exception (rather than tearing down the live workspace) when
    the lock is already taken. Callers can choose to back off, retry with a
    different rollout id, or surface a hard failure.

    Attributes:
        rollout_id: The contended rollout id.
        owner_pid: PID of the lock holder, when it can be determined from
            ``/proc`` (Linux) or ``lsof`` (macOS). ``None`` on platforms
            where neither is available.
        lock_path: Filesystem path of the lockfile that was contended.
    """

    def __init__(
        self,
        rollout_id: Any,
        owner_pid: Optional[int] = None,
        lock_path: Optional[Path] = None,
    ) -> None:
        self.rollout_id = rollout_id
        self.owner_pid = owner_pid
        self.lock_path = lock_path
        owner = f"pid={owner_pid}" if owner_pid else "owner unknown"
        path = f" at {lock_path}" if lock_path else ""
        super().__init__(
            f"Worktree for rollout_id={rollout_id!r} is locked ({owner}){path}; "
            "two RolloutEngines may be sharing the same workspace_dir without "
            "shared_workspace=True."
        )


def _identify_lock_holder(lock_path: Path) -> Optional[int]:
    """Best-effort: identify the PID that holds an ``fcntl`` lock.

    Tries ``/proc/locks`` first (Linux only); falls back to ``lsof`` when
    available. Returns ``None`` on unsupported hosts. This is purely for
    operator diagnostics — losing the race never depends on knowing the
    holder.
    """
    if not lock_path or not lock_path.exists():
        return None
    proc_locks = Path("/proc/locks")
    if proc_locks.exists():
        try:
            stat = lock_path.stat()
        except OSError:
            stat = None
        if stat is not None:
            try:
                content = proc_locks.read_text(errors="replace")
            except OSError:
                content = ""
            target = f"{stat.st_dev:02x}:{stat.st_ino:02x}"
            for raw in content.splitlines():
                parts = raw.split()
                # Format: "1: POSIX  ADVISORY  WRITE 1234 fd:00:12345 0 EOF"
                if len(parts) < 6:
                    continue
                if any(target in field for field in parts):
                    try:
                        return int(parts[4])
                    except (ValueError, IndexError):
                        continue
    lsof = shutil.which("lsof")
    if lsof:
        try:
            result = subprocess.run(
                [lsof, "-t", str(lock_path)],
                capture_output=True,
                text=True,
                check=False,
                timeout=2.0,
            )
        except (subprocess.SubprocessError, OSError):
            return None
        for line in result.stdout.splitlines():
            line = line.strip()
            if line.isdigit():
                return int(line)
    return None


_BENCHMARK_HELPER_FILENAMES = (
    ".apex_expected_test_ids.txt",
    "_apex_expected_test_ids.txt",
    "_apex_expected_ids_filter.py",
    "_apex_run_expected_ids.py",
)


class GitWorktreeManager:
    """
    Creates isolated workspaces for rollouts.

    When the source repo is a clean git checkout, worktrees are used directly.
    Otherwise the manager snapshots the filesystem into a synthetic git repo so
    downstream tooling still has stable diffs and changed-file detection.

    Phase 2.1 hardening:

    * Each rollout id is guarded by an ``fcntl`` advisory lock on
      ``workspace_dir/.locks/rollout_<id>.lock``. ``create_worktree`` raises
      ``ConcurrentWorktreeError`` when the lock is already held instead of
      blindly removing the existing worktree directory. This protects
      concurrent ``solve()`` calls that share a ``workspace_dir`` from
      silently destroying each other's work.
    * Branch names are scoped by ``run_scope`` (a per-engine 8-char id) when
      provided: ``apex-{run_scope}-rollout-{id}`` instead of the bare
      ``apex-rollout-{id}``. Two engines using the same ``workspace_dir``
      no longer collide on the git branch namespace either.
    * Snapshot baseline commits are deterministic (fixed author / date /
      message format including the dirty content hash) so reruns produce
      bit-identical diff text for the same source state.
    """

    # Fixed identity for snapshot baseline commits. See Phase 2.4.
    _SNAPSHOT_AUTHOR_NAME = "APEX Snapshot"
    _SNAPSHOT_AUTHOR_EMAIL = "apex@local"
    _SNAPSHOT_AUTHOR_DATE = "2026-01-01T00:00:00+0000"

    def __init__(
        self,
        repo_path: str,
        workspace_dir: str,
        use_git_worktrees: bool = True,
        *,
        run_scope: Optional[str] = None,
        historyless_snapshots: bool = False,
    ):
        self.repo_path = Path(repo_path).resolve()
        self.workspace_dir = Path(workspace_dir).resolve()
        self.use_git_worktrees = use_git_worktrees
        self.historyless_snapshots = bool(historyless_snapshots)
        # Optional per-engine scope to disambiguate branch names across
        # concurrent solves that share a workspace_dir. Falls back to the
        # bare ``apex-rollout-<id>`` form when None for backwards compat
        # with tests that construct the manager directly.
        self.run_scope = (str(run_scope).strip() or None) if run_scope else None
        self.workspaces: dict[Path, WorkspaceMetadata] = {}
        # Phase 2.1: per-rollout fcntl lockfiles. We hold the lock for the
        # lifetime of the worktree (released in ``remove_worktree`` and
        # ``cleanup_all``) so a sibling engine cannot race in between
        # create_worktree returning and the caller actually using the path.
        self._lock_dir = self.workspace_dir / ".locks"
        self._locks: dict[Path, Any] = {}  # rollout-id-keyed lockfile fds
        self._lock_paths: dict[Path, Path] = {}  # worktree -> lockfile path
        self._lock_registry_lock = threading.Lock()

    def _branch_name(self, rollout_id: Any) -> str:
        """Compose a git branch name scoped by run_id, when present."""
        scope = self.run_scope
        if scope:
            return f"apex-{scope}-rollout-{rollout_id}"
        return f"apex-rollout-{rollout_id}"

    def _remove_stale_branch_worktrees(self, branch_name: str) -> None:
        """Remove stale worktrees that keep ``branch_name`` checked out."""
        result = _safe_subprocess_run(
            ["git", "worktree", "list", "--porcelain"],
            capture_output=True,
            text=True,
            cwd=str(self.repo_path),
            check=False,
        )
        if result.returncode != 0:
            return
        current_path: Optional[str] = None
        current_branch: Optional[str] = None

        def flush() -> None:
            nonlocal current_path, current_branch
            if current_path and current_branch == f"refs/heads/{branch_name}":
                _safe_subprocess_run(
                    ["git", "worktree", "remove", "--force", current_path],
                    capture_output=True,
                    cwd=str(self.repo_path),
                    check=False,
                )
            current_path = None
            current_branch = None

        for raw_line in result.stdout.splitlines():
            line = raw_line.strip()
            if not line:
                flush()
                continue
            if line.startswith("worktree "):
                current_path = line[len("worktree ") :]
            elif line.startswith("branch "):
                current_branch = line[len("branch ") :]
        flush()

    def _lock_file_path(self, rollout_id: Any) -> Path:
        return self._lock_dir / f"rollout_{rollout_id}.lock"

    def _acquire_rollout_lock(
        self,
        rollout_id: Any,
        worktree_path: Path,
    ) -> Any:
        """Acquire a non-blocking fcntl lock for ``rollout_id``.

        Returns the open file handle (caller stores it in ``self._locks``).
        Raises ``ConcurrentWorktreeError`` when the lock cannot be obtained.
        On hosts without ``fcntl`` (Windows / WASM) we fall back to a marker
        file so the same code path still produces a useful error if two
        engines collide; lockless mutual exclusion is best-effort there.
        """
        self._lock_dir.mkdir(parents=True, exist_ok=True)
        lock_path = self._lock_file_path(rollout_id)
        # Open the lockfile in read+write mode so concurrent attempts share
        # the same inode (required for fcntl semantics across processes).
        # We do NOT truncate here so a stale handle can read the prior PID.
        fd = open(lock_path, "a+")
        if _fcntl is None:
            # Windows fallback: best-effort marker file. Two POSIX engines
            # still get strong guarantees via fcntl below; this branch only
            # fires if apex is run on a non-POSIX host that we don't
            # officially support but shouldn't crash on either.
            try:
                fd.seek(0)
                existing = fd.read().strip()
            except OSError:
                existing = ""
            if existing and existing != str(os.getpid()):
                fd.close()
                raise ConcurrentWorktreeError(
                    rollout_id=rollout_id,
                    owner_pid=int(existing) if existing.isdigit() else None,
                    lock_path=lock_path,
                )
            try:
                fd.seek(0)
                fd.truncate()
                fd.write(str(os.getpid()))
                fd.flush()
            except OSError:
                pass
        else:
            try:
                _fcntl.flock(fd.fileno(), _fcntl.LOCK_EX | _fcntl.LOCK_NB)
            except OSError as exc:
                # EWOULDBLOCK / EAGAIN both surface as BlockingIOError on
                # current CPython. Anything else (EBADF, ENOSYS) is a real
                # bug; surface it as a ConcurrentWorktreeError rather than
                # crashing because the caller has no recovery path either
                # way.
                fd.close()
                if exc.errno not in {errno.EWOULDBLOCK, errno.EAGAIN, errno.EACCES}:
                    logger.warning(
                        "fcntl.flock for rollout %s at %s failed unexpectedly: %s",
                        rollout_id,
                        lock_path,
                        exc,
                    )
                owner = _identify_lock_holder(lock_path)
                raise ConcurrentWorktreeError(
                    rollout_id=rollout_id,
                    owner_pid=owner,
                    lock_path=lock_path,
                ) from exc
            # Stamp the PID into the lockfile so identify-holder calls from
            # other processes can attribute the contention to us. Best
            # effort; failures to write are non-fatal.
            try:
                fd.seek(0)
                fd.truncate()
                fd.write(str(os.getpid()))
                fd.flush()
            except OSError:
                pass
        with self._lock_registry_lock:
            self._locks[worktree_path] = fd
            self._lock_paths[worktree_path] = lock_path
        return fd

    def _release_rollout_lock(self, worktree_path: Path) -> None:
        """Release a previously-acquired rollout lock; idempotent."""
        with self._lock_registry_lock:
            fd = self._locks.pop(worktree_path, None)
            lock_path = self._lock_paths.pop(worktree_path, None)
        if fd is None:
            return
        try:
            if _fcntl is not None:
                try:
                    _fcntl.flock(fd.fileno(), _fcntl.LOCK_UN)
                except OSError:
                    pass
        finally:
            try:
                fd.close()
            except OSError:
                pass
        # Best-effort cleanup of the marker file. We don't unlink unless we
        # successfully released so a cross-process holder doesn't see a
        # missing file as "lock available".
        if lock_path is not None and lock_path.exists():
            try:
                lock_path.unlink()
            except OSError:
                pass

    def create_worktree(
        self,
        rollout_id: int,
        seed: Optional[WorkspaceSeed] = None,
    ) -> Path:
        worktree_path = self.workspace_dir / f"rollout_{rollout_id}"
        worktree_path.parent.mkdir(parents=True, exist_ok=True)

        # Phase 2.1: acquire the per-rollout lock BEFORE touching the
        # worktree path. If a sibling engine is mid-rollout we surface
        # ConcurrentWorktreeError instead of nuking their workspace.
        self._acquire_rollout_lock(rollout_id, worktree_path)
        try:
            # The lock guarantees no concurrent owner exists; safe to clean
            # up a stale directory left behind by a previous run.
            if worktree_path.exists():
                self.remove_worktree(worktree_path, _release_lock=False)
                # remove_worktree dropped the lock; reacquire so the
                # post-creation invariant holds.
                self._acquire_rollout_lock(rollout_id, worktree_path)

            if seed is not None:
                try:
                    self._create_seed_workspace(worktree_path, seed)
                except Exception as seed_exc:
                    if worktree_path.exists():
                        shutil.rmtree(worktree_path, ignore_errors=True)
                    logger.warning(
                        "Seed workspace setup failed for rollout %s from %s@%s; "
                        "falling back to a fresh workspace: %s",
                        rollout_id,
                        seed.repo_path,
                        seed.commit_hash[:12],
                        seed_exc,
                    )
                else:
                    self._sync_benchmark_helper_files(worktree_path)
                    self.workspaces[worktree_path] = WorkspaceMetadata(
                        mode="seed_clone",
                        branch_name=None,
                        baseline_commit=seed.baseline_commit,
                    )
                    logger.info(
                        "Created branched workspace for rollout %s from %s@%s",
                        rollout_id,
                        seed.repo_path,
                        seed.commit_hash[:12],
                    )
                    return worktree_path

            if self.use_git_worktrees and self._can_use_native_worktrees():
                branch_name = self._branch_name(rollout_id)
                self._remove_stale_branch_worktrees(branch_name)
                _safe_subprocess_run(
                    ["git", "branch", "-D", branch_name],
                    capture_output=True,
                    cwd=str(self.repo_path),
                )
                result = _safe_subprocess_run(
                    ["git", "worktree", "add", "-b", branch_name, str(worktree_path)],
                    capture_output=True,
                    text=True,
                    cwd=str(self.repo_path),
                )
                if result.returncode == 0:
                    relativize_git_worktree_metadata(worktree_path)
                    submodules = sync_git_submodules(worktree_path)
                    if submodules is not None and submodules.returncode != 0:
                        logger.warning(
                            "Native worktree submodule setup failed, falling back to snapshot: %s",
                            (submodules.stderr or submodules.stdout or "").strip(),
                        )
                        self.remove_worktree(worktree_path, _release_lock=False)
                    else:
                        self._sync_benchmark_helper_files(worktree_path)
                        self.workspaces[worktree_path] = WorkspaceMetadata(
                            mode="worktree",
                            branch_name=branch_name,
                            baseline_commit=_resolve_head_commit(worktree_path),
                        )
                        logger.info(
                            "Created git worktree for rollout %s at %s (branch=%s)",
                            rollout_id,
                            worktree_path,
                            branch_name,
                        )
                        return worktree_path
                logger.warning(
                    "Native worktree setup failed, falling back to snapshot: %s",
                    result.stderr.strip(),
                )

            self._create_snapshot_workspace(worktree_path)
            self._sync_benchmark_helper_files(worktree_path)
            self.workspaces[worktree_path] = WorkspaceMetadata(
                mode="snapshot",
                branch_name=None,
                baseline_commit=_resolve_head_commit(worktree_path),
            )
            logger.info(
                "Created snapshot workspace for rollout %s at %s",
                rollout_id,
                worktree_path,
            )
            return worktree_path
        except ConcurrentWorktreeError:
            # Lock was never installed on this codepath; never re-raise as a
            # double-release.
            raise
        except Exception:
            # Construction failed; release the lock so a retry (possibly with
            # a different rollout_id) can claim the slot.
            self._release_rollout_lock(worktree_path)
            raise

    def _create_seed_workspace(self, destination: Path, seed: WorkspaceSeed) -> None:
        clone = _safe_subprocess_run(
            ["git", "clone", str(seed.repo_path), str(destination)],
            capture_output=True,
            text=True,
            check=False,
        )
        if clone.returncode != 0:
            raise RuntimeError(
                clone.stderr.strip() or clone.stdout.strip() or "Failed to clone seed workspace."
            )
        checkout = _safe_subprocess_run(
            ["git", "checkout", "--detach", seed.commit_hash],
            capture_output=True,
            text=True,
            cwd=str(destination),
            check=False,
        )
        if checkout.returncode != 0:
            raise RuntimeError(
                checkout.stderr.strip()
                or checkout.stdout.strip()
                or "Failed to checkout seed commit."
            )
        _safe_subprocess_run(
            ["git", "clean", "-fd"],
            capture_output=True,
            cwd=str(destination),
            check=False,
        )
        patch_text = str(seed.patch_text or "")
        if patch_text.strip():
            applied = _safe_subprocess_run(
                ["git", "apply", "--binary", "--whitespace=nowarn"],
                input=patch_text.encode("utf-8", errors="replace"),
                capture_output=True,
                cwd=str(destination),
                check=False,
            )
            if applied.returncode != 0:
                raise RuntimeError(
                    applied.stderr.decode("utf-8", errors="replace").strip()
                    or applied.stdout.decode("utf-8", errors="replace").strip()
                    or "Failed to apply materialized seed patch."
                )

    def _sync_benchmark_helper_files(self, destination: Path) -> None:
        """Copy non-submission benchmark helper files into a rollout worktree.

        Commit0's public expected-test inventory is staged as ignored,
        untracked files in the task checkout. Native git worktrees and pool
        resets do not carry those files automatically, but the agent-visible
        test command may need them in every rollout workspace.
        """

        for filename in _BENCHMARK_HELPER_FILENAMES:
            source = self.repo_path / filename
            target = destination / filename
            if source.exists() or source.is_symlink():
                copy_path(source, target)
            elif target.exists() or target.is_symlink():
                remove_path(target)

    def remove_worktree(self, worktree_path: Path, *, _release_lock: bool = True) -> None:
        metadata = self.workspaces.get(
            worktree_path,
            WorkspaceMetadata(mode="snapshot", branch_name=None, baseline_commit=""),
        )
        if metadata.mode == "worktree":
            _safe_subprocess_run(
                ["git", "worktree", "remove", "--force", str(worktree_path)],
                capture_output=True,
                cwd=str(self.repo_path),
            )
            if metadata.branch_name:
                _safe_subprocess_run(
                    ["git", "branch", "-D", metadata.branch_name],
                    capture_output=True,
                    cwd=str(self.repo_path),
                )
        if worktree_path.exists():
            shutil.rmtree(worktree_path, ignore_errors=True)
        self.workspaces.pop(worktree_path, None)
        if _release_lock:
            self._release_rollout_lock(worktree_path)

    def cleanup_all(self) -> None:
        for worktree_path in list(self.workspaces):
            self.remove_worktree(worktree_path)
        # Release any locks we may still hold (e.g. from create_worktree
        # paths that bailed before remove_worktree was called).
        with self._lock_registry_lock:
            stale_paths = list(self._locks.keys())
        for stale_path in stale_paths:
            self._release_rollout_lock(stale_path)
        _safe_subprocess_run(
            ["git", "worktree", "prune"],
            capture_output=True,
            cwd=str(self.repo_path),
        )
        # Drop the .locks/ directory once empty so a subsequent solve in
        # the same workspace_dir starts from a clean slate. We never
        # delete individual lockfiles eagerly — _release_rollout_lock
        # already does that — so the directory is empty by the time we
        # land here in the common case.
        if self._lock_dir.exists():
            try:
                # rmdir succeeds only when the directory is empty; that's
                # the contract we want.
                self._lock_dir.rmdir()
            except OSError:
                # Another concurrent engine may still hold a lock; leave
                # the directory alone and let the next cleanup_all reap it.
                pass

    def get_baseline_commit(self, worktree_path: Path) -> str:
        metadata = self.workspaces.get(worktree_path)
        if metadata and metadata.baseline_commit:
            return metadata.baseline_commit
        return _resolve_head_commit(worktree_path)

    def get_diff(self, worktree_path: Path, baseline_ref: Optional[str] = None) -> str:
        baseline = baseline_ref or self.get_baseline_commit(worktree_path)
        _safe_subprocess_run(["git", "add", "-N", "."], capture_output=True, cwd=str(worktree_path))
        result = _safe_subprocess_run(
            [
                "git",
                "diff",
                "--binary",
                "--relative",
                baseline,
                "--",
                ".",
                *ignored_change_pathspecs(),
            ],
            capture_output=True,
            cwd=str(worktree_path),
        )
        return result.stdout.decode("utf-8", errors="replace")

    def list_changed_files(
        self, worktree_path: Path, baseline_ref: Optional[str] = None
    ) -> list[str]:
        baseline = baseline_ref or self.get_baseline_commit(worktree_path)
        return list_git_changed_files(
            worktree_path,
            baseline_ref=baseline,
            ignored_predicate=_is_ignored_artifact,
        )

    def _can_use_native_worktrees(self) -> bool:
        if not self._is_git_repo(self.repo_path):
            return False
        status = _safe_subprocess_run(
            ["git", "status", "--porcelain"],
            capture_output=True,
            text=True,
            cwd=str(self.repo_path),
        )
        return status.returncode == 0 and not status.stdout.strip()

    def _is_git_repo(self, path: Path) -> bool:
        result = _safe_subprocess_run(
            ["git", "rev-parse", "--show-toplevel"],
            capture_output=True,
            text=True,
            cwd=str(path),
        )
        return result.returncode == 0

    def _create_snapshot_workspace(self, destination: Path) -> None:
        snapshot_ignore = self._snapshot_copy_ignore()
        if self._is_git_repo(self.repo_path) and not self.historyless_snapshots:
            clone = _safe_subprocess_run(
                ["git", "clone", str(self.repo_path), str(destination)],
                capture_output=True,
                text=True,
                check=False,
            )
            if clone.returncode == 0:
                # Phase 2.4: detect whether the source repo had dirty
                # files BEFORE we overlay them. If everything is clean we
                # leave upstream HEAD as the baseline (no synthetic commit
                # at all) so downstream diffs trace cleanly back to the
                # original commit hash.
                source_is_dirty = bool(self._snapshot_overlay_paths()[0]) or bool(
                    self._snapshot_overlay_paths()[1]
                )
                self._sync_snapshot_files(destination)
                self._bootstrap_git_snapshot(
                    destination,
                    initialize_repo=False,
                    skip_commit=not source_is_dirty,
                )
                return
            logger.warning(
                "Snapshot clone failed, falling back to synthetic repo: %s",
                clone.stderr.strip(),
            )
            shutil.rmtree(destination, ignore_errors=True)

        copy_tree(
            self.repo_path,
            destination,
            ignore=snapshot_ignore,
        )
        # Synthetic repo path: there's no upstream HEAD to defer to, so we
        # always synthesise a deterministic baseline commit.
        self._bootstrap_git_snapshot(
            destination,
            initialize_repo=True,
            skip_commit=False,
        )

    def _sync_snapshot_files(self, destination: Path) -> None:
        snapshot_ignore = self._snapshot_copy_ignore()
        paths_to_copy, paths_to_remove = self._snapshot_overlay_paths()
        for rel_path in paths_to_remove:
            remove_path(destination / rel_path)
        for rel_path in paths_to_copy:
            source_path = self.repo_path / rel_path
            if not (source_path.exists() or source_path.is_symlink()):
                remove_path(destination / rel_path)
                continue
            copy_path(source_path, destination / rel_path, ignore=snapshot_ignore)

    def _snapshot_copy_ignore(self) -> Callable[[str, list[str]], set[str]]:
        return shutil.ignore_patterns(
            ".git",
            ".hg",
            ".jj",
            ".sl",
            ".svn",
            "__pycache__",
            "*.pyc",
            ".pytest_cache",
            ".mypy_cache",
        )

    def _snapshot_overlay_paths(self) -> tuple[list[str], list[str]]:
        result = _safe_subprocess_run(
            ["git", "status", "--porcelain"],
            capture_output=True,
            text=True,
            encoding="utf-8",
            errors="replace",
            cwd=str(self.repo_path),
            check=False,
        )
        if result.returncode != 0:
            return ["."], []

        copy_paths: list[str] = []
        remove_paths: list[str] = []
        for raw_line in result.stdout.splitlines():
            line = raw_line.rstrip()
            if len(line) < 3:
                continue
            status = line[:2]
            payload = line[3:].strip()
            old_path = payload
            new_path = payload
            if " -> " in payload:
                old_path, new_path = payload.split(" -> ", 1)
            old_path = normalize_changed_path(old_path)
            new_path = normalize_changed_path(new_path)

            if status == "??":
                if new_path and not is_ignored_change_path(new_path):
                    copy_paths.append(new_path)
                continue

            if "D" in status:
                if old_path and not is_ignored_change_path(old_path):
                    remove_paths.append(old_path)
                if new_path and new_path != old_path and not is_ignored_change_path(new_path):
                    copy_paths.append(new_path)
                continue

            if "R" in status or "C" in status:
                if old_path and old_path != new_path and not is_ignored_change_path(old_path):
                    remove_paths.append(old_path)
                if new_path and not is_ignored_change_path(new_path):
                    copy_paths.append(new_path)
                continue

            if new_path and not is_ignored_change_path(new_path):
                copy_paths.append(new_path)

        return _dedupe_strings(copy_paths), _dedupe_strings(remove_paths)

    def _bootstrap_git_snapshot(
        self,
        worktree_path: Path,
        *,
        initialize_repo: bool,
        skip_commit: bool = False,
    ) -> None:
        """Initialise a git baseline inside the snapshot workspace.

        Phase 2.4 makes the synthetic baseline commit deterministic: a
        fixed author identity, a fixed date, and a commit message that
        embeds both the source repo's HEAD and a hash over the dirty
        overlay content. The message deliberately avoids source filesystem
        paths so sandboxed agents cannot discover host workspace locations
        through ``git log``. Two snapshot workspaces created from the same
        source state therefore produce bit-identical commit SHAs and
        therefore bit-identical diff text for the same patch. ``skip_commit``
        opts out of the synthetic commit entirely (used when a fresh clone
        of a clean repo means upstream HEAD is already a perfectly good
        baseline).
        """
        if initialize_repo:
            _safe_subprocess_run(
                ["git", "init"],
                capture_output=True,
                cwd=str(worktree_path),
                check=False,
            )
        # We deliberately keep these config writes (rather than passing
        # GIT_AUTHOR_*/GIT_COMMITTER_* via env on the commit only) because
        # downstream tooling sometimes invokes git commands inside the
        # workspace and expects a non-empty user.name/email.
        _safe_subprocess_run(
            ["git", "config", "user.email", self._SNAPSHOT_AUTHOR_EMAIL],
            capture_output=True,
            cwd=str(worktree_path),
            check=False,
        )
        _safe_subprocess_run(
            ["git", "config", "user.name", self._SNAPSHOT_AUTHOR_NAME],
            capture_output=True,
            cwd=str(worktree_path),
            check=False,
        )
        info_exclude = worktree_path / ".git" / "info" / "exclude"
        info_exclude.parent.mkdir(parents=True, exist_ok=True)
        with info_exclude.open("a") as handle:
            handle.write("__pycache__/\n*.pyc\n")
        if skip_commit:
            # Fresh clone of a clean source repo — leave HEAD where it is.
            return
        _safe_subprocess_run(
            ["git", "add", "-A"],
            capture_output=True,
            cwd=str(worktree_path),
            check=False,
        )
        # Phase 2.4: deterministic message that records both the upstream
        # state and a hash of any dirty overlay without leaking host paths.
        source_head = self._source_head_short_sha()
        dirty_hash = self._dirty_overlay_content_hash(worktree_path)
        commit_message = f"apex: workspace snapshot @ {source_head}+{dirty_hash}"
        commit_env = {
            **os.environ,
            "GIT_AUTHOR_NAME": self._SNAPSHOT_AUTHOR_NAME,
            "GIT_AUTHOR_EMAIL": self._SNAPSHOT_AUTHOR_EMAIL,
            "GIT_AUTHOR_DATE": self._SNAPSHOT_AUTHOR_DATE,
            "GIT_COMMITTER_NAME": self._SNAPSHOT_AUTHOR_NAME,
            "GIT_COMMITTER_EMAIL": self._SNAPSHOT_AUTHOR_EMAIL,
            "GIT_COMMITTER_DATE": self._SNAPSHOT_AUTHOR_DATE,
        }
        commit = _safe_subprocess_run(
            ["git", "commit", "-m", commit_message],
            capture_output=True,
            text=True,
            cwd=str(worktree_path),
            check=False,
            env=commit_env,
        )
        if commit.returncode != 0:
            commit_output = (commit.stdout + commit.stderr).strip().lower()
            if "nothing to commit" not in commit_output:
                logger.warning(
                    "Snapshot baseline commit failed for %s: %s",
                    worktree_path,
                    (commit.stdout + commit.stderr).strip(),
                )

    def _source_head_short_sha(self) -> str:
        """Return upstream repo's HEAD SHA truncated to 8 chars.

        Returns ``"00000000"`` when the source isn't a git repo so the
        deterministic message format never depends on the call succeeding.
        """
        if not self._is_git_repo(self.repo_path):
            return "00000000"
        result = _safe_subprocess_run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            cwd=str(self.repo_path),
            check=False,
        )
        sha = (result.stdout or "").strip()
        return sha[:8] if sha else "00000000"

    def _dirty_overlay_content_hash(self, worktree_path: Path) -> str:
        """Hash the overlay content currently in ``worktree_path``.

        Computed from the sorted list of dirty file paths plus their byte
        contents. Two workspaces built from identical source dirty state
        produce identical hashes; the hash changes the moment a single
        byte of any tracked file changes. The hash is truncated to 8 hex
        chars so the commit message stays human-readable.
        """
        copy_paths, remove_paths = self._snapshot_overlay_paths()
        relevant_paths = sorted({*(copy_paths or []), *(remove_paths or [])})
        if not relevant_paths:
            return "00000000"
        digest = hashlib.sha256()
        for rel_path in relevant_paths:
            digest.update(rel_path.encode("utf-8", errors="replace"))
            digest.update(b"\x00")
            target = worktree_path / rel_path
            if target.is_file():
                try:
                    digest.update(target.read_bytes())
                except OSError:
                    digest.update(b"<unreadable>")
            else:
                digest.update(b"<absent>")
            digest.update(b"\x00")
        return digest.hexdigest()[:8]


def _is_ignored_artifact(path: str) -> bool:
    return is_ignored_change_path(path)


def _path_matches_test_conventions(path: str) -> bool:
    normalized = str(path or "").strip().replace("\\", "/")
    if not normalized:
        return False
    parts = {part.lower() for part in Path(normalized).parts}
    lowered_name = Path(normalized).name.lower()
    return (
        "tests" in parts
        or "test" in parts
        or "spec" in parts
        or "__tests__" in parts
        or "testdata" in parts
        or lowered_name == "conftest.py"
        or lowered_name.startswith("test_")
        or lowered_name.endswith("_test.py")
        or lowered_name.endswith("_test.go")
        or lowered_name.endswith("_test.rs")
        or lowered_name.endswith("_spec.rb")
        or ".test." in lowered_name
        or ".spec." in lowered_name
        or re.search(r"(?:^|[._-])test[s]?\.(?:java|kt|kts|scala|cs)$", lowered_name) is not None
        or re.search(r"(?:^|[._-])spec\.(?:java|kt|kts|scala|cs)$", lowered_name) is not None
        or re.search(r"test[s]?\.(?:java|kt|kts|scala|cs)$", Path(normalized).name) is not None
    )


def _test_writer_has_test_execution_signal(
    path: str,
    *,
    repo_context: Optional[RepoContext] = None,
) -> bool:
    normalized = normalize_changed_path(path)
    if not normalized or not _path_matches_test_conventions(normalized):
        return False

    lowered_name = Path(normalized).name.lower()
    lowered_parts = [part.lower() for part in Path(normalized).parts]
    direct_name_signal = (
        lowered_name == "conftest.py"
        or lowered_name.startswith("test_")
        or lowered_name.endswith("_test.py")
        or lowered_name.endswith("_test.go")
        or lowered_name.endswith("_test.rs")
        or lowered_name.endswith("_spec.rb")
        or ".test." in lowered_name
        or ".spec." in lowered_name
        or re.search(
            r"(?:^|[._-])test[s]?\.(?:java|kt|kts|scala|cs)$",
            lowered_name,
        )
        is not None
        or re.search(
            r"(?:^|[._-])spec\.(?:java|kt|kts|scala|cs)$",
            lowered_name,
        )
        is not None
    )
    if direct_name_signal:
        return True

    executable_manifest_dirs = {"tasks", "cases", "scenarios", "features"}
    support_or_internal_dirs = {
        "_internal",
        "internal",
        "support",
        "helpers",
        "helper",
        "fixtures",
        "fixture",
        "library",
    }
    test_tree_positions = [
        index
        for index, part in enumerate(lowered_parts)
        if part in {"test", "tests", "spec", "__tests__"}
    ]
    near_root_test_tree = any(index <= 2 for index in test_tree_positions)
    if any(part in {"test", "tests", "spec", "__tests__"} for part in lowered_parts) and any(
        part in executable_manifest_dirs for part in lowered_parts
    ):
        return True

    if any(part in support_or_internal_dirs for part in lowered_parts) and not direct_name_signal:
        return False

    symbol_based_signal = False
    if repo_context is not None and (
        near_root_test_tree or "tests" in lowered_parts or "__tests__" in lowered_parts
    ):
        file_info = repo_context.get_file_info(normalized)
        if file_info is not None:
            for symbol in list(file_info.symbols or []):
                name = str(symbol.name or "").strip().lower()
                if name.startswith("test") or name.startswith("it") or "should" in name:
                    symbol_based_signal = True
                    break
            if symbol_based_signal:
                return True

    if "tests" in lowered_parts or "__tests__" in lowered_parts:
        return True

    return False


def _is_test_path(path: str) -> bool:
    return _path_matches_test_conventions(path)


def _coverage_score(changed_files: set[str], targets: set[str]) -> float:
    if not targets:
        return 0.5
    if not changed_files:
        return 0.0
    overlap = len(changed_files.intersection(targets))
    if overlap <= 0:
        return 0.0
    return min(1.0, overlap / max(min(len(changed_files), len(targets)), 1))


def _artifact_value(artifact: Any, key: str) -> Any:
    if isinstance(artifact, dict):
        return artifact.get(key)
    return getattr(artifact, key, None)


def _artifact_strings(artifact: Any, key: str) -> list[str]:
    values = _artifact_value(artifact, key)
    if not isinstance(values, (list, tuple, set)):
        return []
    return [str(value) for value in values if value]


def _merge_test_generation_task_contract(*payloads: Any) -> dict[str, Any]:
    dictionaries = [dict(payload or {}) for payload in payloads if isinstance(payload, dict)]
    problem_statement = ""
    acceptance_requirements: list[str] = []
    interface_specification: list[str] = []
    for payload in dictionaries:
        if not problem_statement:
            problem_statement = str(payload.get("problem_statement") or "").strip()
        acceptance_requirements.extend(list(payload.get("acceptance_requirements") or []))
        interface_specification.extend(list(payload.get("interface_specification") or []))
    if not problem_statement and not acceptance_requirements and not interface_specification:
        return {}
    return {
        "problem_statement": problem_statement,
        "acceptance_requirements": _dedupe_strings(acceptance_requirements),
        "interface_specification": _dedupe_strings(interface_specification),
    }


def _planner_test_generation_design_payload(
    issue_plan: IssuePlan,
    *,
    issue_description: str,
    required_contract_targets: list[str],
    required_contract_axes: list[str],
) -> dict[str, Any]:
    planner_metadata = (
        issue_plan.planner_metadata if isinstance(issue_plan.planner_metadata, dict) else {}
    )
    task_state_context = (
        issue_plan.task_state_context if isinstance(issue_plan.task_state_context, dict) else {}
    )
    ledger = (
        task_state_context.get("test_generation_ledger")
        if isinstance(task_state_context.get("test_generation_ledger"), dict)
        else {}
    )
    derived = derive_test_generation_plan(
        issue_description or str(issue_plan.summary or ""),
        issue_summary=str(issue_plan.summary or "").strip(),
        success_criteria=_dedupe_strings(
            list(issue_plan.success_criteria or [])
            + list(issue_plan.test_context.expectations or [])
        ),
        behavioral_obligations=_dedupe_strings(
            list(issue_plan.test_context.expectations or [])
            + list(issue_plan.success_criteria or [])
        ),
        interface_targets=list(required_contract_targets or []),
        required_axes=list(required_contract_axes or []),
    )
    task_contract = _merge_test_generation_task_contract(
        dict(derived.get("task_contract") or {}),
        dict(planner_metadata.get("test_generation_contract") or {}),
        dict(ledger.get("task_contract") or {}),
    )
    milestones = [
        dict(item)
        for item in (
            list(ledger.get("milestones") or [])
            or list(planner_metadata.get("test_generation_milestones") or [])
            or list(derived.get("milestones") or [])
        )
        if isinstance(item, dict)
    ]
    test_objectives = [
        dict(item)
        for item in (
            list(ledger.get("test_objectives") or [])
            or list(planner_metadata.get("test_generation_objectives") or [])
            or list(derived.get("test_objectives") or [])
        )
        if isinstance(item, dict)
    ]
    return {
        "task_contract": task_contract,
        "milestones": milestones,
        "test_objectives": test_objectives,
    }


def _test_generation_execution_context(
    issue_plan: IssuePlan,
    *,
    issue_description: str,
    required_contract_targets: list[str],
    required_contract_axes: list[str],
) -> dict[str, Any]:
    design_payload = _planner_test_generation_design_payload(
        issue_plan,
        issue_description=issue_description,
        required_contract_targets=required_contract_targets,
        required_contract_axes=required_contract_axes,
    )
    task_state_context = (
        issue_plan.task_state_context if isinstance(issue_plan.task_state_context, dict) else {}
    )
    ledger = (
        task_state_context.get("test_generation_ledger")
        if isinstance(task_state_context.get("test_generation_ledger"), dict)
        else {}
    )
    milestones = [
        dict(item)
        for item in list(design_payload.get("milestones") or [])
        if isinstance(item, dict)
    ]
    test_objectives = [
        dict(item)
        for item in list(design_payload.get("test_objectives") or [])
        if isinstance(item, dict)
    ]
    ordered_milestone_ids = [
        str(item.get("milestone_id") or "").strip()
        for item in milestones
        if str(item.get("milestone_id") or "").strip()
    ]
    boundary_enforcement_enabled = bool(
        str(ledger.get("current_milestone_id") or "").strip()
        or list(ledger.get("milestones") or [])
        or list(ledger.get("test_objectives") or [])
        or list(ledger.get("regression_suite_artifacts") or [])
        or "strict_ready" in ledger
    )
    current_milestone_id = ""
    if boundary_enforcement_enabled:
        current_milestone_id = str(ledger.get("current_milestone_id") or "").strip()
        if current_milestone_id and current_milestone_id not in ordered_milestone_ids:
            current_milestone_id = ""
        if not current_milestone_id and ordered_milestone_ids:
            current_milestone_id = ordered_milestone_ids[0]
    milestone_map = {
        str(item.get("milestone_id") or "").strip(): dict(item)
        for item in milestones
        if str(item.get("milestone_id") or "").strip()
    }
    current_milestone = dict(milestone_map.get(current_milestone_id) or {})
    current_objective_ids = _dedupe_strings(list(current_milestone.get("objective_ids") or []))
    if not current_objective_ids and current_milestone_id:
        current_objective_ids = [
            str(item.get("objective_id") or "").strip()
            for item in test_objectives
            if str(item.get("milestone_id") or "").strip() == current_milestone_id
            and str(item.get("objective_id") or "").strip()
        ]
    current_objectives = [
        dict(item)
        for item in test_objectives
        if str(item.get("objective_id") or "").strip() in set(current_objective_ids)
    ]
    current_index = (
        ordered_milestone_ids.index(current_milestone_id)
        if current_milestone_id in ordered_milestone_ids
        else -1
    )
    completed_strict_ready_milestone_ids = [
        milestone_id
        for milestone_id in ordered_milestone_ids[: max(current_index, 0)]
        if bool(dict(milestone_map.get(milestone_id) or {}).get("strict_validation_ready"))
    ]
    return {
        "task_contract": dict(design_payload.get("task_contract") or {}),
        "milestones": milestones,
        "test_objectives": test_objectives,
        "boundary_enforcement_enabled": boundary_enforcement_enabled,
        "ordered_milestone_ids": ordered_milestone_ids,
        "current_milestone_id": current_milestone_id,
        "current_milestone": current_milestone,
        "current_objective_ids": list(current_objective_ids),
        "current_objectives": current_objectives,
        "current_milestone_validation_level": str(
            current_milestone.get("validation_level") or "strict"
        )
        .strip()
        .lower(),
        "completed_strict_ready_milestone_ids": completed_strict_ready_milestone_ids,
        "future_milestone_ids": (
            ordered_milestone_ids[current_index + 1 :] if current_index >= 0 else []
        ),
        "regression_suite_artifacts": _dedupe_strings(
            list(ledger.get("regression_suite_artifacts") or [])
        ),
        "ledger_strict_ready": bool(ledger.get("strict_ready")),
    }


def _test_generation_milestone_ready_for_required_level(
    *,
    milestone_summary: dict[str, Any],
    milestone: dict[str, Any],
) -> bool:
    if "ready_for_required_level" in milestone_summary:
        return bool(milestone_summary.get("ready_for_required_level"))
    required_level = (
        str(
            milestone_summary.get("validation_level")
            or milestone.get("validation_level")
            or "strict"
        )
        .strip()
        .lower()
    )
    if required_level == "core":
        return bool(milestone_summary.get("core_ready") or milestone.get("core_ready"))
    if required_level == "iso":
        return bool(milestone_summary.get("iso_ready") or milestone.get("iso_ready"))
    return bool(
        milestone_summary.get("strict_ready")
        or milestone.get("strict_ready")
        or milestone.get("strict_validation_ready")
    )


def _render_test_generation_milestone_boundary_prompt_block(
    execution_context: dict[str, Any],
) -> str:
    if not bool(execution_context.get("boundary_enforcement_enabled")):
        return ""
    current_milestone_id = str(execution_context.get("current_milestone_id") or "").strip()
    if not current_milestone_id:
        return ""
    current_milestone = dict(execution_context.get("current_milestone") or {})
    current_title = str(
        current_milestone.get("title") or current_milestone_id.replace("_", " ").title()
    ).strip()
    current_validation_level = (
        str(execution_context.get("current_milestone_validation_level") or "strict").strip().lower()
    )
    current_objectives = [
        dict(item)
        for item in list(execution_context.get("current_objectives") or [])
        if isinstance(item, dict)
    ]
    current_objective_lines = [
        (
            f"- {str(item.get('objective_id') or '').strip()}: "
            f"{str(item.get('objective') or '').strip() or 'objective pending'}"
            + (
                " | axes="
                + ", ".join(
                    str(axis).strip()
                    for axis in list(item.get("contract_axes") or [])
                    if str(axis).strip()
                )
                if list(item.get("contract_axes") or [])
                else ""
            )
        ).rstrip()
        for item in current_objectives
        if str(item.get("objective_id") or "").strip()
    ]
    completed_milestones = [
        str(item)
        for item in list(execution_context.get("completed_strict_ready_milestone_ids") or [])
        if str(item).strip()
    ]
    regression_suite_artifacts = [
        str(item)
        for item in list(execution_context.get("regression_suite_artifacts") or [])
        if str(item).strip()
    ]
    future_milestone_ids = [
        str(item)
        for item in list(execution_context.get("future_milestone_ids") or [])
        if str(item).strip()
    ]
    return (
        "\n\n# Current Milestone Boundary\n"
        f"Current execution milestone: {current_milestone_id}: {current_title}\n"
        f"Required validation level before advancing: {current_validation_level}\n"
        "Current milestone objectives:\n"
        f"{chr(10).join(current_objective_lines) if current_objective_lines else '- derive the active objectives from the task contract'}\n"
        "Previously STRICT-ready milestones already preserved in the ledger:\n"
        f"{chr(10).join(f'- {item}' for item in completed_milestones) if completed_milestones else '- none'}\n"
        "Cumulative regression-suite artifacts already carried forward:\n"
        f"{chr(10).join(f'- {item}' for item in regression_suite_artifacts[:8]) if regression_suite_artifacts else '- none'}\n"
        "Later milestones that are out of scope until this boundary clears:\n"
        f"{chr(10).join(f'- {item}' for item in future_milestone_ids) if future_milestone_ids else '- none'}\n"
        "Treat this milestone boundary as real execution state. Do not advance to later milestones until the current milestone reaches its required validation level. If a later behavior matters, keep it as plan metadata only for now rather than returning assertion-bearing artifacts for it prematurely.\n"
    )


def _overlay_test_generation_design(
    payload: dict[str, Any],
    *,
    design_payload: dict[str, Any],
) -> dict[str, Any]:
    merged = dict(payload or {})
    task_contract = _merge_test_generation_task_contract(
        dict(design_payload.get("task_contract") or {}),
        dict(merged.get("task_contract") or {}),
    )
    if task_contract:
        merged["task_contract"] = task_contract
    if not list(merged.get("milestones") or []):
        merged["milestones"] = [dict(item) for item in list(design_payload.get("milestones") or [])]
    if not list(merged.get("test_objectives") or []):
        merged["test_objectives"] = [
            dict(item) for item in list(design_payload.get("test_objectives") or [])
        ]
    if not list(merged.get("contract_hypotheses") or []) and isinstance(
        merged.get("task_contract"), dict
    ):
        merged["contract_hypotheses"] = list(
            dict(merged.get("task_contract") or {}).get("acceptance_requirements") or []
        )
    if not list(merged.get("reference_targets") or []) and isinstance(
        merged.get("task_contract"), dict
    ):
        merged["reference_targets"] = list(
            dict(merged.get("task_contract") or {}).get("interface_specification") or []
        )
    return merged


def _persist_test_generation_state(
    issue_plan: IssuePlan,
    *,
    output_dir: Optional[str],
) -> None:
    if not output_dir:
        return
    try:
        output_path = Path(output_dir)
        output_path.mkdir(parents=True, exist_ok=True)
        ledger = _test_generation_ledger(issue_plan)
        ledger_path = output_path / _TEST_GENERATION_LEDGER_FILENAME
        ledger_payload = json.dumps(ledger, indent=2, sort_keys=True)
        if ledger_payload and not ledger_payload.endswith("\n"):
            ledger_payload += "\n"
        from ..evaluation.checkpointing import atomic_write_text

        atomic_write_text(ledger_path, ledger_payload)
        issue_plan.save(output_path / _TEST_GENERATION_ISSUE_PLAN_FILENAME)
    except Exception as exc:
        logger.debug(
            "Failed to persist test generation ledger state into %s: %s",
            output_dir,
            exc,
        )


def _reload_test_generation_state_from_disk(
    issue_plan: IssuePlan,
    *,
    output_dir: Optional[str],
) -> bool:
    if not output_dir:
        return False
    issue_plan_path = Path(output_dir) / _TEST_GENERATION_ISSUE_PLAN_FILENAME
    if not issue_plan_path.exists():
        return False
    try:
        persisted_issue_plan = IssuePlan.load(issue_plan_path)
    except Exception as exc:
        logger.debug(
            "Failed to reload persisted test generation issue plan from %s: %s",
            issue_plan_path,
            exc,
        )
        return False
    for dataclass_field in fields(IssuePlan):
        setattr(
            issue_plan,
            dataclass_field.name,
            getattr(persisted_issue_plan, dataclass_field.name),
        )
    return True


def _persist_test_generation_portfolio_state(
    portfolio: Any,
    *,
    output_dir: Optional[str],
) -> None:
    if not output_dir:
        return
    try:
        output_path = Path(output_dir)
        output_path.mkdir(parents=True, exist_ok=True)
        portfolio_path = output_path / _TEST_GENERATION_PORTFOLIO_FILENAME
        portfolio_payload = dict(portfolio or {}) if isinstance(portfolio, dict) else {}
        rendered = json.dumps(portfolio_payload, indent=2, sort_keys=True)
        if rendered and not rendered.endswith("\n"):
            rendered += "\n"
        from ..evaluation.checkpointing import atomic_write_text

        atomic_write_text(portfolio_path, rendered)
    except Exception as exc:
        logger.debug(
            "Failed to persist test generation portfolio state into %s: %s",
            output_dir,
            exc,
        )


def _reload_test_generation_portfolio_state_from_disk(
    *,
    output_dir: Optional[str],
) -> dict[str, Any]:
    if not output_dir:
        return {}
    portfolio_path = Path(output_dir) / _TEST_GENERATION_PORTFOLIO_FILENAME
    if not portfolio_path.exists():
        return {}
    try:
        payload = json.loads(portfolio_path.read_text(encoding="utf-8"))
    except Exception as exc:
        logger.debug(
            "Failed to reload persisted test generation portfolio state from %s: %s",
            portfolio_path,
            exc,
        )
        return {}
    return dict(payload or {}) if isinstance(payload, dict) else {}


def _update_issue_plan_test_generation_ledger(
    issue_plan: IssuePlan,
    *,
    promoted_portfolio: dict[str, Any],
) -> None:
    task_state_context = dict(issue_plan.task_state_context or {})
    ledger = dict(task_state_context.get("test_generation_ledger") or {})
    regression_summary = dict(promoted_portfolio.get("regression_suite_summary") or {})
    milestones = [
        dict(item)
        for item in list(promoted_portfolio.get("milestones") or [])
        if isinstance(item, dict)
    ]
    milestone_ids = [
        str(item.get("milestone_id") or "").strip()
        for item in milestones
        if str(item.get("milestone_id") or "").strip()
    ]
    existing_current_milestone_id = str(ledger.get("current_milestone_id") or "").strip()
    boundary_enforcement = dict(promoted_portfolio.get("milestone_boundary_enforcement") or {})
    boundary_current_milestone_id = str(
        boundary_enforcement.get("current_milestone_id") or ""
    ).strip()
    next_current_milestone_id = ""
    if bool(regression_summary.get("strict_ready")):
        next_current_milestone_id = ""
    elif boundary_current_milestone_id and boundary_current_milestone_id in milestone_ids:
        # Finalizing a portfolio may confirm or prune the active boundary, but it should
        # not implicitly advance the milestone pointer. Boundary progression belongs to the
        # milestone executor/checkpoint loop.
        next_current_milestone_id = boundary_current_milestone_id
    elif existing_current_milestone_id and existing_current_milestone_id in milestone_ids:
        next_current_milestone_id = existing_current_milestone_id
    else:
        next_current_milestone_id = str(
            next(
                (
                    dict(item).get("milestone_id")
                    for item in milestones
                    if not bool(dict(item).get("strict_validation_ready"))
                ),
                dict(milestones[0]).get("milestone_id", "") if milestones else "",
            )
            or ""
        ).strip()
    ledger.update(
        {
            "task_contract": dict(promoted_portfolio.get("task_contract") or {}),
            "milestones": milestones,
            "test_objectives": [
                dict(item) for item in list(promoted_portfolio.get("test_objectives") or [])
            ],
            "regression_suite_artifacts": _dedupe_strings(
                list(ledger.get("regression_suite_artifacts") or [])
                + list(regression_summary.get("artifact_paths") or [])
            ),
            "strict_ready": bool(regression_summary.get("strict_ready")),
            "current_milestone_id": next_current_milestone_id,
            "executor_requested_replans": {
                str(key).strip(): int(value or 0)
                for key, value in dict(ledger.get("executor_requested_replans") or {}).items()
                if str(key).strip()
            },
            "executor_replan_history": [
                dict(item)
                for item in list(ledger.get("executor_replan_history") or [])
                if isinstance(item, dict)
            ][-12:],
            "last_executor_replan_reason": str(
                ledger.get("last_executor_replan_reason") or ""
            ).strip(),
        }
    )
    task_state_context["test_generation_ledger"] = ledger
    issue_plan.task_state_context = task_state_context

    issue_plan.planner_metadata = dict(issue_plan.planner_metadata or {})
    issue_plan.planner_metadata.update(
        {
            "test_generation_contract": dict(promoted_portfolio.get("task_contract") or {}),
            "test_generation_milestones": [
                dict(item) for item in list(promoted_portfolio.get("milestones") or [])
            ],
            "test_generation_objectives": [
                dict(item) for item in list(promoted_portfolio.get("test_objectives") or [])
            ],
            "test_generation_strict_ready": bool(regression_summary.get("strict_ready")),
        }
    )


def _test_generation_ledger(issue_plan: IssuePlan) -> dict[str, Any]:
    task_state_context = (
        issue_plan.task_state_context if isinstance(issue_plan.task_state_context, dict) else {}
    )
    ledger = task_state_context.get("test_generation_ledger")
    return dict(ledger or {}) if isinstance(ledger, dict) else {}


def _test_generation_milestone_loop_enabled(issue_plan: IssuePlan) -> bool:
    ledger = _test_generation_ledger(issue_plan)
    return bool(
        str(ledger.get("current_milestone_id") or "").strip()
        or list(ledger.get("milestones") or [])
        or list(ledger.get("test_objectives") or [])
    )


def _test_generation_public_artifacts(payload: Any) -> list[dict[str, Any]]:
    normalized = normalize_test_suite_artifact_payload(payload)
    entries = [
        dict(entry)
        for entry in list(normalized.get("test_artifacts") or [])
        if isinstance(entry, dict)
    ]
    public_entries = [
        entry
        for entry in entries
        if str(entry.get("promotion_status") or "").strip().lower()
        in {"promoted", "candidate_public"}
    ]
    if public_entries:
        return public_entries

    candidate_ids = {
        str(item).strip()
        for item in list(normalized.get("candidate_artifact_ids") or [])
        if str(item).strip()
    }
    if candidate_ids:
        return [
            entry
            for entry in entries
            if str(entry.get("artifact_id") or "").strip() in candidate_ids
        ]

    regression_suite_paths = {
        normalize_changed_path(str(item).strip()) or str(item).strip()
        for item in list(
            dict(normalized.get("regression_suite_summary") or {}).get("artifact_paths") or []
        )
        if str(item).strip()
    }
    if regression_suite_paths:
        return [
            entry
            for entry in entries
            if (
                normalize_changed_path(str(entry.get("path") or "").strip())
                or str(entry.get("path") or "").strip()
            )
            in regression_suite_paths
        ]
    return entries


def _test_generation_usable_submission_summary(payload: Any) -> dict[str, Any]:
    """Whether a testgen portfolio is worth handing to execution now.

    This is intentionally cheaper and weaker than final F2P/coverage/mutation:
    once we have at least one assertion-bearing artifact with complete design
    metadata, benchmark loops should hand it to the dual-state oracle instead
    of spending the whole task budget enriching later milestones.
    """
    usable_paths: list[str] = []
    blocked: list[dict[str, Any]] = []
    for artifact in _test_generation_public_artifacts(payload):
        path = str(artifact.get("path") or "").strip()
        content = str(artifact.get("content") or "")
        if not path or not content.strip():
            continue
        if not re.search(
            r"\b(assert|expect|should|verify|throws|equals|deepEquals|Fatalf?|Errorf?)\b",
            content,
        ):
            blocked.append({"path": path, "reason": "no_concrete_assertion"})
            continue
        metadata_gaps = _artifact_design_metadata_gaps(artifact)
        if metadata_gaps:
            blocked.append(
                {
                    "path": path,
                    "reason": "design_metadata_gaps",
                    "missing_fields": list(metadata_gaps),
                }
            )
            continue
        usable_paths.append(path)
    return {
        "usable": bool(usable_paths),
        "usable_paths": usable_paths,
        "blocked": blocked[:8],
    }


def _test_generation_artifact_key(artifact: dict[str, Any]) -> tuple[str, str, str]:
    path = (
        normalize_changed_path(str(artifact.get("path") or "").strip())
        or str(artifact.get("path") or "").strip()
    )
    objective_id = str(artifact.get("objective_id") or "").strip()
    artifact_id = str(artifact.get("artifact_id") or "").strip()
    materialization_mode = str(artifact.get("materialization_mode") or "replace").strip().lower()
    return (
        path,
        objective_id or artifact_id or str(artifact.get("summary") or "").strip(),
        materialization_mode or "replace",
    )


def _merge_cumulative_test_generation_submission(
    cumulative_portfolio: Any,
    submission: Any,
) -> dict[str, Any]:
    base_payload = (
        dict(cumulative_portfolio or {}) if isinstance(cumulative_portfolio, dict) else {}
    )
    submission_payload = dict(submission or {}) if isinstance(submission, dict) else {}
    base_entries = _test_generation_public_artifacts(base_payload)
    normalized_submission = normalize_test_suite_artifact_payload(submission_payload)
    new_entries = [
        dict(entry)
        for entry in list(normalized_submission.get("test_artifacts") or [])
        if isinstance(entry, dict)
    ]

    merged_entries: list[dict[str, Any]] = []
    merged_index: dict[tuple[str, str, str], int] = {}
    for entry in base_entries:
        key = _test_generation_artifact_key(entry)
        if key in merged_index:
            merged_entries[merged_index[key]] = dict(entry)
            continue
        merged_index[key] = len(merged_entries)
        merged_entries.append(dict(entry))
    for entry in new_entries:
        key = _test_generation_artifact_key(entry)
        if key in merged_index:
            merged_entries[merged_index[key]] = dict(entry)
            continue
        merged_index[key] = len(merged_entries)
        merged_entries.append(dict(entry))

    merged_payload = dict(submission_payload)
    for stale_field in (
        "validation_summary",
        "portfolio_summary",
        "promotion_summary",
        "regression_suite_summary",
        "minimization_summary",
        "promoted_artifact_ids",
        "candidate_artifact_ids",
        "exploratory_artifact_ids",
    ):
        merged_payload.pop(stale_field, None)
    merged_payload["test_artifacts"] = merged_entries
    merged_payload["changed_files"] = _dedupe_strings(
        [
            str(path).strip()
            for path in (
                list(base_payload.get("changed_files") or [])
                + list(submission_payload.get("changed_files") or [])
                + [
                    str(entry.get("path") or "").strip()
                    for entry in merged_entries
                    if str(entry.get("path") or "").strip()
                ]
            )
            if str(path).strip()
        ]
    )
    merged_payload["test_descriptions"] = _dedupe_strings(
        list(base_payload.get("test_descriptions") or [])
        + list(submission_payload.get("test_descriptions") or [])
    )
    merged_payload["contract_hypotheses"] = _dedupe_strings(
        list(base_payload.get("contract_hypotheses") or [])
        + list(submission_payload.get("contract_hypotheses") or [])
    )
    merged_payload["reference_targets"] = _dedupe_strings(
        list(base_payload.get("reference_targets") or [])
        + list(submission_payload.get("reference_targets") or [])
    )
    if not str(merged_payload.get("summary") or "").strip():
        merged_payload["summary"] = str(base_payload.get("summary") or "").strip()
    return merged_payload


def _materialize_test_generation_artifacts(
    *,
    worktree_path: str,
    artifacts: list[dict[str, Any]],
    quarantined_paths: Optional[dict[str, str]] = None,
) -> list[str]:
    worktree = Path(worktree_path)
    materialized_paths: list[str] = []
    for raw_artifact in _drop_quarantined_artifacts(
        list(artifacts or []),
        quarantined_paths or {},
    ):
        artifact = dict(raw_artifact or {})
        rel_path = safe_materialize_test_artifact(worktree, artifact)
        if rel_path:
            materialized_paths.append(rel_path)
    return _dedupe_strings(materialized_paths)


def _drop_quarantined_artifacts(
    artifacts: list[dict[str, Any]],
    quarantined_paths: dict[str, str],
) -> list[dict[str, Any]]:
    if not quarantined_paths:
        return [dict(item) for item in list(artifacts or []) if isinstance(item, dict)]
    blocked = {
        normalize_generated_test_path(path) or str(path or "").strip().replace("\\", "/")
        for path in quarantined_paths
        if str(path or "").strip()
    }
    kept: list[dict[str, Any]] = []
    for raw_artifact in list(artifacts or []):
        if not isinstance(raw_artifact, dict):
            continue
        rel_path = normalize_generated_test_path(raw_artifact.get("path"))
        if rel_path and rel_path in blocked:
            continue
        kept.append(dict(raw_artifact))
    return kept


def _capture_existing_test_generation_artifacts(
    *,
    worktree_path: str,
    artifacts: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    worktree = Path(worktree_path)
    git_probe = _safe_subprocess_run(
        ["git", "rev-parse", "--show-toplevel"],
        cwd=str(worktree),
        capture_output=True,
        text=True,
    )
    if git_probe.returncode == 0:
        return []
    preserved: list[dict[str, Any]] = []
    seen: set[str] = set()
    for raw_artifact in list(artifacts or []):
        if not isinstance(raw_artifact, dict):
            continue
        rel_path = normalize_generated_test_path(raw_artifact.get("path"))
        if not rel_path or rel_path in seen:
            continue
        target = worktree / rel_path
        if not target.exists() or not target.is_file() or target.is_symlink():
            continue
        try:
            content = target.read_text(encoding="utf-8")
        except UnicodeDecodeError:
            content = target.read_text(encoding="utf-8", errors="ignore")
        except OSError:
            continue
        preserved.append(
            {
                "path": rel_path,
                "content": content,
                "materialization_mode": "replace",
                "_apex_preserved_existing_test": True,
            }
        )
        seen.add(rel_path)
    return preserved


def _advance_test_generation_ledger_after_milestone(
    issue_plan: IssuePlan,
    *,
    promoted_portfolio: dict[str, Any],
) -> dict[str, Any]:
    ledger = _test_generation_ledger(issue_plan)
    milestones = [
        dict(item)
        for item in list(promoted_portfolio.get("milestones") or ledger.get("milestones") or [])
        if isinstance(item, dict)
    ]
    ordered_milestone_ids = [
        str(item.get("milestone_id") or "").strip()
        for item in milestones
        if str(item.get("milestone_id") or "").strip()
    ]
    previous_current_milestone_id = str(ledger.get("current_milestone_id") or "").strip()
    if previous_current_milestone_id not in ordered_milestone_ids:
        previous_current_milestone_id = ordered_milestone_ids[0] if ordered_milestone_ids else ""
    milestone_map = {
        str(item.get("milestone_id") or "").strip(): dict(item)
        for item in milestones
        if str(item.get("milestone_id") or "").strip()
    }
    current_milestone = dict(milestone_map.get(previous_current_milestone_id) or {})
    current_ready = _test_generation_milestone_ready_for_required_level(
        milestone_summary=current_milestone,
        milestone=current_milestone,
    )
    regression_suite_summary = dict(promoted_portfolio.get("regression_suite_summary") or {})
    if not previous_current_milestone_id or (
        not current_ready and not bool(regression_suite_summary.get("strict_ready"))
    ):
        return {
            "advanced": False,
            "previous_current_milestone_id": previous_current_milestone_id,
            "next_current_milestone_id": previous_current_milestone_id,
            "strict_ready": bool(regression_suite_summary.get("strict_ready")),
        }

    current_index = ordered_milestone_ids.index(previous_current_milestone_id)
    next_current_milestone_id = next(
        (
            milestone_id
            for milestone_id in ordered_milestone_ids[current_index + 1 :]
            if not bool(dict(milestone_map.get(milestone_id) or {}).get("strict_validation_ready"))
        ),
        "",
    )
    task_state_context = (
        dict(issue_plan.task_state_context or {})
        if isinstance(issue_plan.task_state_context, dict)
        else {}
    )
    updated_ledger = dict(task_state_context.get("test_generation_ledger") or {})
    updated_ledger["current_milestone_id"] = next_current_milestone_id
    updated_ledger["strict_ready"] = bool(regression_suite_summary.get("strict_ready"))
    task_state_context["test_generation_ledger"] = updated_ledger
    issue_plan.task_state_context = task_state_context
    return {
        "advanced": next_current_milestone_id != previous_current_milestone_id,
        "previous_current_milestone_id": previous_current_milestone_id,
        "next_current_milestone_id": next_current_milestone_id,
        "strict_ready": bool(regression_suite_summary.get("strict_ready")),
    }


def _record_test_generation_executor_replan_attempt(
    issue_plan: IssuePlan,
    *,
    milestone_id: str,
    reason: str,
) -> int:
    task_state_context = (
        dict(issue_plan.task_state_context or {})
        if isinstance(issue_plan.task_state_context, dict)
        else {}
    )
    ledger = (
        dict(task_state_context.get("test_generation_ledger") or {})
        if isinstance(task_state_context.get("test_generation_ledger"), dict)
        else {}
    )
    counts = {
        str(key).strip(): int(value or 0)
        for key, value in dict(ledger.get("executor_requested_replans") or {}).items()
        if str(key).strip()
    }
    normalized_milestone_id = str(milestone_id or "").strip()
    next_attempt = int(counts.get(normalized_milestone_id) or 0) + 1
    counts[normalized_milestone_id] = next_attempt
    history = [
        dict(item)
        for item in list(ledger.get("executor_replan_history") or [])
        if isinstance(item, dict)
    ]
    history.append(
        {
            "milestone_id": normalized_milestone_id,
            "reason": str(reason or "").strip(),
            "attempt_index": next_attempt,
        }
    )
    ledger["executor_requested_replans"] = counts
    ledger["executor_replan_history"] = history[-12:]
    ledger["last_executor_replan_reason"] = str(reason or "").strip()
    task_state_context["test_generation_ledger"] = ledger
    issue_plan.task_state_context = task_state_context
    return next_attempt


def _test_generation_executor_replan_request(
    *,
    config: ApexConfig,
    issue_plan: IssuePlan,
    execution_context: dict[str, Any],
    stage_trajectory: dict[str, Any],
) -> dict[str, Any]:
    feedback = dict(stage_trajectory.get("test_generation_executor_feedback") or {})
    multi_agent_usage = dict(stage_trajectory.get("multi_agent_usage") or {})
    current_milestone_id = str(
        feedback.get("active_milestone_id") or execution_context.get("current_milestone_id") or ""
    ).strip()
    boundary_pressure_count = int(multi_agent_usage.get("boundary_pressure_count") or 0)
    threshold = max(
        1,
        int(getattr(config.planning, "delegation_boundary_pressure_threshold", 0) or 0) or 1,
    )
    boundary_requested_files = _dedupe_strings(
        [
            str(item).strip()
            for item in list(multi_agent_usage.get("boundary_requested_files") or [])
            if str(item).strip()
        ]
    )
    boundary_interface_symbols = _dedupe_strings(
        [
            str(item).strip()
            for item in list(multi_agent_usage.get("boundary_interface_symbols") or [])
            if str(item).strip()
        ]
    )
    boundary_followups = _dedupe_strings(
        [
            str(item).strip()
            for item in list(multi_agent_usage.get("boundary_followups") or [])
            if str(item).strip()
        ]
    )
    missing_contract_axes = _dedupe_strings(
        [
            str(item).strip()
            for item in list(feedback.get("missing_contract_axes") or [])
            if str(item).strip()
        ]
    )
    coverage_deferral_detected = bool(feedback.get("coverage_deferral_detected"))
    preferred_test_anchor_gap_detected = bool(feedback.get("preferred_test_anchor_gap_detected"))
    missing_issue_surface_targets = _dedupe_strings(
        [
            str(item).strip()
            for item in list(feedback.get("missing_issue_surface_targets") or [])
            if str(item).strip()
        ]
    )
    supplemental_issue_surface_artifacts = [
        dict(item)
        for item in list(feedback.get("supplemental_issue_surface_artifacts") or [])
        if isinstance(item, dict)
    ]
    observable_behavior_gap_detected = bool(feedback.get("observable_behavior_gap_detected"))
    observable_behavior_gap_artifacts = [
        dict(item)
        for item in list(feedback.get("observable_behavior_gap_artifacts") or [])
        if isinstance(item, dict)
    ]
    schema_constraint_drift_detected = bool(feedback.get("schema_constraint_drift_detected"))
    schema_constraint_drift_artifacts = [
        dict(item)
        for item in list(feedback.get("schema_constraint_drift_artifacts") or [])
        if isinstance(item, dict)
    ]
    field_path_negative_shape_detected = bool(feedback.get("field_path_negative_shape_detected"))
    field_path_negative_shape_gaps = _dedupe_strings(
        [
            str(item).strip()
            for item in list(feedback.get("field_path_negative_shape_gaps") or [])
            if str(item).strip()
        ]
    )
    blocking_objectives = _dedupe_strings(
        [
            str(item).strip()
            for item in list(feedback.get("active_milestone_blocking_objectives") or [])
            if str(item).strip()
        ]
    )
    design_missing_objective_ids = _dedupe_strings(
        [
            str(item).strip()
            for item in list(feedback.get("design_missing_objective_ids") or [])
            if str(item).strip()
        ]
    )
    design_missing_milestone_ids = _dedupe_strings(
        [
            str(item).strip()
            for item in list(feedback.get("design_missing_milestone_ids") or [])
            if str(item).strip()
        ]
    )
    design_artifact_metadata_gap_count = int(
        feedback.get("design_artifact_metadata_gap_count") or 0
    )
    design_artifact_metadata_gaps = [
        dict(item)
        for item in list(feedback.get("design_artifact_metadata_gaps") or [])
        if isinstance(item, dict)
    ]
    replan_reason = ""
    if boundary_pressure_count >= threshold and (
        boundary_requested_files or boundary_interface_symbols or blocking_objectives
    ):
        replan_reason = "executor_boundary_pressure"
    elif (
        design_missing_objective_ids
        or design_missing_milestone_ids
        or design_artifact_metadata_gap_count > 0
    ):
        replan_reason = "executor_design_gap"
    elif (
        coverage_deferral_detected
        or preferred_test_anchor_gap_detected
        or missing_issue_surface_targets
        or supplemental_issue_surface_artifacts
        or observable_behavior_gap_detected
        or schema_constraint_drift_detected
        or field_path_negative_shape_detected
        or missing_contract_axes
    ):
        replan_reason = "executor_issue_surface_gap"

    ledger = _test_generation_ledger(issue_plan)
    replan_counts = {
        str(key).strip(): int(value or 0)
        for key, value in dict(ledger.get("executor_requested_replans") or {}).items()
        if str(key).strip()
    }
    attempt_count = int(replan_counts.get(current_milestone_id) or 0)
    capped = attempt_count >= _MAX_TEST_GENERATION_EXECUTOR_REPLANS_PER_MILESTONE
    requested = bool(
        current_milestone_id
        and replan_reason
        and not bool(feedback.get("active_milestone_ready_for_required_level"))
        and not bool(feedback.get("design_portfolio_strict_ready"))
        and not capped
    )
    return {
        "requested": requested,
        "reason": replan_reason,
        "attempted": False,
        "attempt_count": attempt_count,
        "max_attempts_per_milestone": _MAX_TEST_GENERATION_EXECUTOR_REPLANS_PER_MILESTONE,
        "capped": capped,
        "boundary_pressure_count": boundary_pressure_count,
        "threshold": threshold,
        "boundary_requested_files": boundary_requested_files,
        "boundary_interface_symbols": boundary_interface_symbols,
        "boundary_followups": boundary_followups,
        "missing_contract_axes": missing_contract_axes,
        "coverage_deferral_detected": coverage_deferral_detected,
        "preferred_test_anchor_gap_detected": preferred_test_anchor_gap_detected,
        "missing_issue_surface_targets": missing_issue_surface_targets,
        "supplemental_issue_surface_artifacts": supplemental_issue_surface_artifacts,
        "observable_behavior_gap_detected": observable_behavior_gap_detected,
        "observable_behavior_gap_artifacts": observable_behavior_gap_artifacts,
        "schema_constraint_drift_detected": schema_constraint_drift_detected,
        "schema_constraint_drift_artifacts": schema_constraint_drift_artifacts,
        "field_path_negative_shape_detected": field_path_negative_shape_detected,
        "field_path_negative_shape_gaps": field_path_negative_shape_gaps,
        "active_milestone_blocking_objectives": blocking_objectives,
        "design_missing_objective_ids": design_missing_objective_ids,
        "design_missing_milestone_ids": design_missing_milestone_ids,
        "design_artifact_metadata_gap_count": design_artifact_metadata_gap_count,
        "design_artifact_metadata_gaps": design_artifact_metadata_gaps,
        "boundary_context": {
            "replan_reason": replan_reason,
            "current_milestone_id": current_milestone_id,
            "completed_strict_ready_milestone_ids": [
                str(item).strip()
                for item in list(
                    execution_context.get("completed_strict_ready_milestone_ids") or []
                )
                if str(item).strip()
            ],
            "future_milestone_ids": [
                str(item).strip()
                for item in list(execution_context.get("future_milestone_ids") or [])
                if str(item).strip()
            ],
            "regression_suite_artifacts": [
                str(item).strip()
                for item in list(execution_context.get("regression_suite_artifacts") or [])
                if str(item).strip()
            ],
            "boundary_requested_files": boundary_requested_files,
            "boundary_interface_symbols": boundary_interface_symbols,
            "boundary_followups": boundary_followups,
            "missing_contract_axes": missing_contract_axes,
            "coverage_deferral_detected": coverage_deferral_detected,
            "preferred_test_anchor_gap_detected": preferred_test_anchor_gap_detected,
            "missing_issue_surface_targets": missing_issue_surface_targets,
            "supplemental_issue_surface_artifacts": supplemental_issue_surface_artifacts,
            "observable_behavior_gap_detected": observable_behavior_gap_detected,
            "observable_behavior_gap_artifacts": observable_behavior_gap_artifacts,
            "schema_constraint_drift_detected": schema_constraint_drift_detected,
            "schema_constraint_drift_artifacts": schema_constraint_drift_artifacts,
            "field_path_negative_shape_detected": field_path_negative_shape_detected,
            "field_path_negative_shape_gaps": field_path_negative_shape_gaps,
            "active_milestone_blocking_objectives": blocking_objectives,
            "design_missing_objective_ids": design_missing_objective_ids,
            "design_missing_milestone_ids": design_missing_milestone_ids,
            "design_artifact_metadata_gap_count": design_artifact_metadata_gap_count,
            "design_artifact_metadata_gaps": design_artifact_metadata_gaps,
        },
    }


def _refresh_test_generation_issue_plan_at_boundary(
    *,
    config: ApexConfig,
    issue_plan: IssuePlan,
    issue_description: str,
    worktree_path: str,
    test_command: Optional[str],
    boundary_context: Optional[dict[str, Any]] = None,
) -> tuple[IssuePlan, Optional[RepoContext], dict[str, Any]]:
    refresh_details = {
        "attempted": True,
        "refreshed": False,
        "error": "",
        "design_source": "",
        "reason": str(
            dict(boundary_context or {}).get("replan_reason") or "milestone_boundary"
        ).strip(),
    }
    try:
        boundary_execution_context = _test_generation_execution_context(
            issue_plan,
            issue_description=issue_description,
            required_contract_targets=[],
            required_contract_axes=[],
        )
        ledger = _test_generation_ledger(issue_plan)
        default_boundary_context = {
            "replan_reason": "milestone_boundary",
            "current_milestone_id": str(
                boundary_execution_context.get("current_milestone_id") or ""
            ).strip(),
            "completed_strict_ready_milestone_ids": [
                str(item).strip()
                for item in list(
                    boundary_execution_context.get("completed_strict_ready_milestone_ids") or []
                )
                if str(item).strip()
            ],
            "future_milestone_ids": [
                str(item).strip()
                for item in list(boundary_execution_context.get("future_milestone_ids") or [])
                if str(item).strip()
            ],
            "regression_suite_artifacts": [
                str(item).strip()
                for item in list(ledger.get("regression_suite_artifacts") or [])
                if str(item).strip()
            ],
        }
        merged_boundary_context = dict(default_boundary_context)
        provided_boundary_context = (
            dict(boundary_context or {}) if isinstance(boundary_context, dict) else {}
        )
        for key, value in provided_boundary_context.items():
            if key in {
                "completed_strict_ready_milestone_ids",
                "future_milestone_ids",
                "regression_suite_artifacts",
                "boundary_requested_files",
                "boundary_interface_symbols",
                "boundary_followups",
                "active_milestone_blocking_objectives",
                "design_missing_objective_ids",
                "design_missing_milestone_ids",
                "design_artifact_metadata_gap_count",
            }:
                if key == "design_artifact_metadata_gap_count":
                    merged_boundary_context[key] = max(
                        int(merged_boundary_context.get(key) or 0),
                        int(value or 0),
                    )
                else:
                    merged_boundary_context[key] = _dedupe_strings(
                        list(merged_boundary_context.get(key) or []) + list(value or [])
                    )
            elif key == "design_artifact_metadata_gaps" and isinstance(value, list):
                merged_boundary_context[key] = [
                    dict(item)
                    for item in list(merged_boundary_context.get(key) or []) + list(value or [])
                    if isinstance(item, dict)
                ]
            elif value not in (None, "", []):
                merged_boundary_context[key] = value
        refresh_details["reason"] = str(
            merged_boundary_context.get("replan_reason") or "milestone_boundary"
        ).strip()
        refreshed_repo_context = RepoAnalyzer(str(worktree_path)).analyze()
        planner = IssuePlanner(config)
        refreshed_issue_plan = planner.enrich_issue_plan(
            issue_plan,
            issue_description=issue_description,
            repo_context=refreshed_repo_context,
            test_command=test_command,
            baseline_result=None,
            force_test_generation_design_replan=True,
            test_generation_boundary_context=merged_boundary_context,
        )
        refresh_details["refreshed"] = True
        refresh_details["design_source"] = str(
            dict(refreshed_issue_plan.planner_metadata or {}).get("test_generation_design_source")
            or ""
        ).strip()
        return refreshed_issue_plan, refreshed_repo_context, refresh_details
    except Exception as exc:
        refresh_details["error"] = str(exc)
        logger.warning(
            "Test-generation boundary refresh failed for %s: %s",
            worktree_path,
            exc,
        )
        return issue_plan, None, refresh_details


def _model_source_family(model: str) -> str:
    token = str(model or "").strip().lower()
    if not token:
        return ""
    if token.startswith("openai/") or "gpt" in token or "codex" in token:
        return "openai"
    if token.startswith("anthropic/") or "claude" in token or token == "opus":
        return "anthropic"
    if token.startswith("gemini") or token.startswith("google/"):
        return "google"
    if token.startswith("meta/") or "llama" in token or "avocado" in token:
        return "meta"
    return token.split("/", 1)[0].split("-", 1)[0]


def _compute_rollout_progress(
    result: RolloutResult,
    issue_plan: IssuePlan,
) -> tuple[float, dict[str, float]]:
    relevant_files = set(issue_plan.relevant_files or [])
    risk_files = set(issue_plan.risk_files or [])
    visible_targets = set(
        list(issue_plan.test_context.failing_test_ids or [])
        + list(issue_plan.test_context.focus_test_files or [])
    )

    changed_files = set(
        result.changed_files or _artifact_strings(result.patch_artifact, "changed_files")
    )
    localized_files = set(_artifact_strings(result.localization_artifact, "files"))
    localized_symbols = set(_artifact_strings(result.localization_artifact, "symbols"))
    test_signals = set(_artifact_strings(result.patch_artifact, "tests_run"))
    test_signals.update(result.test_descriptions or [])

    reproduction_fields = [
        _artifact_value(result.reproduction_artifact, "command"),
        _artifact_value(result.reproduction_artifact, "summary"),
        _artifact_value(result.reproduction_artifact, "script_path"),
        _artifact_value(result.reproduction_artifact, "script_content"),
        _artifact_value(result.reproduction_artifact, "observed_output"),
    ]
    reproduction_signal = 0.0
    if any(isinstance(value, str) and value.strip() for value in reproduction_fields[:3]):
        reproduction_signal = 0.7
    if any(isinstance(value, str) and value.strip() for value in reproduction_fields):
        reproduction_signal = max(reproduction_signal, 1.0 if reproduction_signal else 0.4)

    localization_alignment = _coverage_score(
        localized_files,
        relevant_files.union(risk_files),
    )
    localization_signal = 0.0
    if localized_files or localized_symbols:
        localization_signal = min(
            1.0,
            0.15
            + (0.25 * localization_alignment)
            + (0.05 if localized_files.intersection(risk_files) else 0.0)
            + (0.05 if localized_symbols else 0.0),
        )

    implementation_targets = relevant_files.union(risk_files)
    implementation_alignment = _coverage_score(
        changed_files,
        implementation_targets,
    )
    source_changes = {path for path in changed_files if not _is_test_path(path)}
    changed_test_files = {path for path in changed_files if _is_test_path(path)}
    allowed_test_changes = {
        str(path) for path in list(issue_plan.test_context.incomplete_test_files or []) if path
    }
    implementation_signal = 0.0
    if changed_files:
        implementation_signal = min(
            1.0,
            0.25
            + (0.45 * implementation_alignment)
            + (0.20 if source_changes else 0.05)
            + (0.10 if len(changed_files) <= 6 else 0.0),
        )

    if visible_targets:
        if test_signals:
            overlap = len(test_signals.intersection(visible_targets))
            test_alignment = min(
                1.0,
                overlap / max(min(len(test_signals), len(visible_targets)), 1),
            )
        else:
            test_alignment = 0.0
    else:
        test_alignment = 0.6 if test_signals else 0.4

    confidence = _artifact_value(result.patch_artifact, "confidence")
    if isinstance(confidence, (int, float)):
        patch_confidence = max(0.0, min(float(confidence), 1.0))
    elif result.success and result.patch:
        patch_confidence = 0.6
    else:
        patch_confidence = 0.0
    recovered_patch = bool(
        isinstance(result.patch_artifact, dict)
        and result.patch_artifact.get("_apex_recovered_patch")
    )

    patch_signal = 0.0
    if result.success and result.patch and changed_files:
        patch_signal = max(0.7, min(1.0, 0.4 + (0.6 * patch_confidence)))
    elif changed_files or _artifact_value(result.patch_artifact, "summary"):
        patch_signal = min(
            0.8,
            0.25 + (0.40 * patch_confidence) + (0.15 if changed_files else 0.0),
        )
    if recovered_patch:
        patch_signal = min(patch_signal, 0.35 + (0.20 * patch_confidence))

    quick_verification_signal = 0.0
    quick_verification = (
        dict(result.quick_verification) if isinstance(result.quick_verification, dict) else {}
    )
    broad_validation = _issue_plan_requires_broad_validation(issue_plan)
    quick_pass_rate = quick_verification_signal_score(quick_verification)
    if quick_pass_rate is not None:
        quick_verification_signal = quick_pass_rate
        if quick_verification.get("scope") in {"failing_tests", "focus_test_files"}:
            quick_verification_signal = min(1.0, 0.15 + (0.85 * quick_verification_signal))
        if _quick_verification_has_failed_structural_precheck(quick_verification):
            quick_verification_signal = 0.0
    full_scope_timed_out = bool(quick_verification.get("full_scope_timed_out"))
    if full_scope_timed_out:
        quick_verification_signal = min(
            quick_verification_signal, 0.6 if broad_validation else 0.75
        )

    collection_error_failures = {
        str(test_id)
        for test_id in list(quick_verification.get("failed_tests") or [])
        if _looks_like_collection_error_test_id(str(test_id))
    }
    stability_penalty = 0.0
    if collection_error_failures:
        stability_penalty += min(0.14, 0.04 * len(collection_error_failures))
    if full_scope_timed_out:
        stability_penalty += 0.08 if broad_validation else 0.04
    if changed_test_files:
        unexpected_test_changes = changed_test_files.difference(allowed_test_changes)
        only_allowed_placeholder_changes = bool(changed_test_files) and not unexpected_test_changes
        if not source_changes and not only_allowed_placeholder_changes:
            stability_penalty += 0.12
        elif unexpected_test_changes:
            stability_penalty += 0.06
        if unexpected_test_changes:
            stability_penalty += min(0.12, 0.04 * len(unexpected_test_changes))
        if broad_validation:
            if collection_error_failures:
                stability_penalty += 0.08
            elif isinstance(quick_pass_rate, (int, float)) and float(quick_pass_rate) < 0.999:
                stability_penalty += 0.06
            elif quick_verification and not isinstance(quick_pass_rate, (int, float)):
                stability_penalty += 0.04

    overall = (
        (0.12 * reproduction_signal)
        + (0.23 * implementation_signal)
        + (0.14 * test_alignment)
        + (0.22 * patch_signal)
        + (0.29 * quick_verification_signal)
    )
    if result.success and result.patch:
        if recovered_patch:
            overall = max(
                overall,
                0.28 + (0.20 * patch_confidence) + (0.40 * quick_verification_signal),
            )
        else:
            overall = max(overall, 0.65 + (0.25 * patch_confidence))
        if quick_verification_signal > 0.0 and not recovered_patch:
            overall = max(overall, 0.55 + (0.30 * quick_verification_signal))
    elif changed_files and reproduction_signal > 0.0:
        overall = max(overall, 0.25 + (0.25 * implementation_alignment))
        if quick_verification_signal > 0.0:
            overall = max(overall, 0.20 + (0.35 * quick_verification_signal))

    overall -= stability_penalty
    overall = max(0.0, min(overall, 0.98))
    details = {
        "reproduction": round(reproduction_signal, 4),
        "localization": round(localization_signal, 4),
        "implementation": round(implementation_signal, 4),
        "test_alignment": round(test_alignment, 4),
        "patch_signal": round(patch_signal, 4),
        "quick_verification": round(quick_verification_signal, 4),
        "stability_penalty": round(stability_penalty, 4),
        "overall": round(overall, 4),
    }
    return overall, details


def _normalize_quick_verification_helper_files(paths: list[str]) -> list[str]:
    normalized: list[str] = []
    seen: set[str] = set()
    for raw_path in paths:
        value = str(raw_path or "").strip().replace("\\", "/")
        if not value or value.startswith("/") or value.startswith("../"):
            continue
        parts = [part for part in value.split("/") if part and part != "."]
        if not parts or any(part == ".." for part in parts):
            continue
        rel_path = "/".join(parts)
        if rel_path in seen:
            continue
        seen.add(rel_path)
        normalized.append(rel_path)
    return normalized


def _sync_quick_verification_helper_files(
    *,
    source_repo_path: str,
    worktree_path: str,
    helper_files: list[str],
) -> None:
    for rel_path in _normalize_quick_verification_helper_files(helper_files):
        source = Path(source_repo_path) / rel_path
        target = Path(worktree_path) / rel_path
        try:
            if not source.exists() and not source.is_symlink():
                continue
            target.parent.mkdir(parents=True, exist_ok=True)
            if target.exists() or target.is_symlink():
                if target.is_dir() and not target.is_symlink():
                    shutil.rmtree(target, ignore_errors=True)
                else:
                    target.unlink()
            shutil.copy2(source, target, follow_symlinks=False)
        except OSError as exc:
            logger.debug(
                "Failed to sync quick-verification helper %s into %s: %s",
                rel_path,
                worktree_path,
                exc,
            )


