def _run_scaffold_patcher_stage(
    *,
    llm_config: Any,
    config: ApexConfig,
    repo_context: RepoContext,
    issue_description: str,
    issue_plan: IssuePlan,
    brief: Any,
    worktree_path: str,
    strategy: Any,
    test_command: Optional[str],
    reproduction_artifact: Optional[ReproductionArtifact],
    localization_artifact: Optional[LocalizationArtifact],
    memory_bus: Optional[EpisodicMemoryBus],
    rollout_id: int,
    resolved_baseline: Optional[str],
    execution_tree: Optional[ExecutionTree],
    temperature: float,
    status_output_dir: Optional[str] = None,
    wallclock_deadline: Optional[float] = None,
    cancel_check: Optional[Callable[[], bool]] = None,
    cancel_reason: Optional[Callable[[], str]] = None,
    component_ablation: Optional[dict[str, Any]] = None,
) -> tuple[dict[str, Any], int, dict[str, Any]]:
    def _run_once(active_llm_config: LLMConfig) -> tuple[dict[str, Any], int, dict[str, Any]]:
        _raise_if_rollout_cancelled(
            cancel_check,
            cancel_reason,
            phase="patcher",
            default_reason="rollout cancelled before scaffolded patcher stage",
        )
        if active_llm_config.is_cli_backend and cli_backend_is_healthy(active_llm_config):
            followup_rounds = 1
            if config.rollout.enable_quick_verification and test_command:
                followup_rounds = _size_aware_followup_round_cap(config, issue_plan)
            first_round_llm_config = _select_collection_error_fast_path_first_round_llm_config(
                config,
                rollout_id,
                active_llm_config,
                issue_plan=issue_plan,
                brief=brief,
            )
            return _run_cli_patcher(
                config=config,
                llm_config=active_llm_config,
                first_round_llm_config=first_round_llm_config,
                worktree_path=worktree_path,
                baseline_commit=resolved_baseline,
                repo_path=repo_context.repo_path,
                issue_description=issue_description,
                issue_plan=issue_plan,
                brief=brief,
                strategy=strategy,
                test_command=test_command,
                use_concise_prompts=config.use_concise_prompts,
                reproduction_artifact=reproduction_artifact,
                localization_artifact=localization_artifact,
                memory_bus=memory_bus,
                rollout_id=rollout_id,
                quick_verification_timeout_seconds=config.rollout.quick_verification_timeout_seconds,
                quick_verification_max_tests=config.rollout.quick_verification_max_tests,
                max_followup_rounds=followup_rounds,
                enable_orchestrated_delegation=_patcher_delegate_subtasks_enabled(
                    config,
                    brief,
                    issue_plan,
                ),
                status_output_dir=status_output_dir,
                wallclock_deadline=wallclock_deadline,
                cancel_check=cancel_check,
                cancel_reason=cancel_reason,
                execution_tree=execution_tree,
                component_ablation=component_ablation,
            )
        _raise_if_rollout_cancelled(
            cancel_check,
            cancel_reason,
            phase="patcher",
            default_reason="rollout cancelled before API patcher stage",
        )
        if active_llm_config.is_cli_backend or not active_llm_config.has_api_key:
            raise RuntimeError(_llm_unavailable_reason(active_llm_config))

        patcher = _instantiate_agent(
            PatcherAgent,
            llm_config=active_llm_config,
            working_dir=worktree_path,
            aci_config=config.aci,
            agentic_search_config=config.agentic_search,
            context_config=config.context,
            repo_context=repo_context,
            rollout_id=rollout_id,
            memory_bus=memory_bus,
            execution_tree=execution_tree,
            baseline_commit=resolved_baseline,
            temperature=temperature,
            max_iterations=config.rollout.max_iterations_per_rollout,
            strategy=strategy,
            use_concise_prompts=config.use_concise_prompts,
            enable_subagents=_patcher_subagent_tools_enabled(config, issue_plan),
            enable_delegate_subtasks=_patcher_delegate_subtasks_enabled(
                config,
                brief,
                issue_plan,
            ),
        )
        patch_result = patcher.run(
            issue_description=issue_description,
            issue_plan=issue_plan,
            rollout_brief=brief,
            test_command=test_command,
            reproduction_artifact=reproduction_artifact,
            localization_artifact=localization_artifact,
        )
        return (
            patch_result.submission,
            patch_result.tokens_used,
            _build_agent_stage_trajectory("patcher", active_llm_config, patch_result),
        )

    return _run_with_llm_backend_failover(
        requested_llm_config=llm_config,
        config=config,
        purpose="rollout_patcher",
        runner=_run_once,
        allow_fallback=_brief_allows_llm_backend_fallback(config, brief),
    )


def _run_scaffold_test_writer_stage(
    *,
    llm_config: Any,
    config: ApexConfig,
    repo_context: RepoContext,
    issue_description: str,
    issue_plan: IssuePlan,
    brief: Any,
    worktree_path: str,
    reproduction_artifact: Optional[ReproductionArtifact],
    localization_artifact: Optional[LocalizationArtifact],
    memory_bus: Optional[EpisodicMemoryBus],
    rollout_id: int,
    resolved_baseline: Optional[str],
    execution_tree: Optional[ExecutionTree],
    temperature: float,
    preserved_test_artifacts: Optional[list[dict[str, Any]]] = None,
    status_output_dir: Optional[str] = None,
    wallclock_deadline: Optional[float] = None,
) -> tuple[dict[str, Any], int, dict[str, Any]]:
    effective_brief = _effective_test_writer_brief(brief, issue_plan)
    effective_test_command = str(issue_plan.test_context.command or "").strip()
    explicit_test_generation_design = _issue_plan_has_explicit_test_generation_design(issue_plan)
    runtime_execution_context = _test_generation_execution_context(
        issue_plan,
        issue_description=issue_description,
        required_contract_targets=[],
        required_contract_axes=[],
    )
    runtime_prompt_appendix = _build_test_writer_runtime_prompt_appendix(
        execution_context=runtime_execution_context
    )

    def _run_once(
        active_llm_config: LLMConfig,
        *,
        additional_prompt_appendix: str = "",
    ) -> tuple[dict[str, Any], int, dict[str, Any]]:
        if active_llm_config.is_cli_backend and cli_backend_is_healthy(active_llm_config):
            return _run_cli_test_writer(
                config=config,
                llm_config=active_llm_config,
                agentic_search_config=config.agentic_search,
                worktree_path=worktree_path,
                baseline_commit=resolved_baseline,
                issue_description=issue_description,
                issue_plan=issue_plan,
                brief=effective_brief,
                use_concise_prompts=config.use_concise_prompts,
                reproduction_artifact=reproduction_artifact,
                localization_artifact=localization_artifact,
                repo_context=repo_context,
                memory_bus=memory_bus,
                rollout_id=rollout_id,
                preserved_test_artifacts=preserved_test_artifacts,
                enable_orchestrated_delegation=_test_writer_delegate_subtasks_enabled(
                    config,
                    effective_brief,
                    issue_plan,
                ),
                status_output_dir=status_output_dir,
                additional_prompt_appendix=additional_prompt_appendix,
                wallclock_deadline=wallclock_deadline,
            )
        if active_llm_config.is_cli_backend or not active_llm_config.has_api_key:
            raise RuntimeError(_llm_unavailable_reason(active_llm_config))

        test_writer = _instantiate_agent(
            TestWriterAgent,
            llm_config=active_llm_config,
            working_dir=worktree_path,
            aci_config=config.aci,
            agentic_search_config=config.agentic_search,
            context_config=config.context,
            repo_context=repo_context,
            rollout_id=rollout_id,
            memory_bus=memory_bus,
            execution_tree=execution_tree,
            baseline_commit=resolved_baseline,
            temperature=temperature,
            max_iterations=min(config.selection.selector_max_iterations, 8),
            use_concise_prompts=config.use_concise_prompts,
            enable_subagents=_test_writer_subagent_tools_enabled(config, issue_plan),
            enable_delegate_subtasks=_test_writer_delegate_subtasks_enabled(
                config,
                effective_brief,
                issue_plan,
            ),
        )
        test_result = test_writer.run(
            issue_description=issue_description,
            issue_plan=issue_plan,
            rollout_brief=effective_brief,
            reproduction_artifact=reproduction_artifact,
            localization_artifact=localization_artifact,
            prompt_appendix="\n\n".join(
                section
                for section in [
                    runtime_prompt_appendix.strip(),
                    str(additional_prompt_appendix or "").strip(),
                ]
                if section
            ),
        )
        return (
            test_result.submission,
            test_result.tokens_used,
            _build_agent_stage_trajectory("test_writer", active_llm_config, test_result),
        )

    def _run_api_pass_then_invert_pipeline(
        active_llm_config: LLMConfig,
    ) -> tuple[dict[str, Any], int, dict[str, Any]]:
        pass_then_invert_pipeline: dict[str, Any] = {
            "attempted": True,
            "precursor_attempted": True,
            "precursor_validated": False,
            "used_precursor_for_inversion": False,
            "fallback_to_direct_generation": False,
            "active_milestone_id": str(
                runtime_execution_context.get("current_milestone_id") or ""
            ).strip(),
        }
        direct_appendix = runtime_prompt_appendix
        precursor_appendix = "\n\n".join(
            section
            for section in [
                runtime_prompt_appendix.strip(),
                _build_test_writer_pass_then_invert_precursor_appendix(
                    execution_context=runtime_execution_context
                ).strip(),
            ]
            if section
        )
        try:
            precursor_submission, precursor_tokens, _ = _run_once(
                active_llm_config,
                additional_prompt_appendix=precursor_appendix,
            )
            total_tokens = int(precursor_tokens or 0)
            pass_then_invert_pipeline["precursor_tokens"] = total_tokens
            precursor_payload, precursor_signal, _ = _finalize_candidate_submission(
                dict(precursor_submission or {}),
                active_llm_config,
            )
            precursor_validation_signal = _test_writer_pass_then_invert_precursor_signal(
                payload=precursor_payload,
                issue_plan=issue_plan,
                issue_description=issue_description,
            )
            pass_then_invert_pipeline.update(
                {
                    "precursor_summary": str(precursor_payload.get("summary") or "").strip(),
                    "precursor_artifact_paths": list(
                        precursor_validation_signal.get("artifact_paths") or []
                    ),
                    "precursor_artifact_count": int(
                        precursor_validation_signal.get("artifact_count") or 0
                    ),
                    "precursor_execution_success_count": int(
                        precursor_validation_signal.get("execution_success_count") or 0
                    ),
                    "precursor_baseline_preserving_count": int(
                        precursor_validation_signal.get("baseline_preserving_count") or 0
                    ),
                    "precursor_validation_feedback": dict(
                        precursor_validation_signal.get("validation_feedback") or {}
                    ),
                    "precursor_validated": bool(precursor_validation_signal.get("ready")),
                }
            )
            if bool(precursor_validation_signal.get("ready")):
                inversion_appendix = "\n\n".join(
                    section
                    for section in [
                        runtime_prompt_appendix.strip(),
                        _build_test_writer_pass_then_invert_inversion_appendix(
                            precursor_payload=precursor_payload,
                            precursor_signal=precursor_validation_signal,
                        ).strip(),
                    ]
                    if section
                )
                pass_then_invert_pipeline["inversion_attempted"] = True
                try:
                    submission, inversion_tokens, stage_trajectory = _run_once(
                        active_llm_config,
                        additional_prompt_appendix=inversion_appendix,
                    )
                    total_tokens += int(inversion_tokens or 0)
                    pass_then_invert_pipeline["inversion_tokens"] = int(inversion_tokens or 0)
                    pass_then_invert_pipeline["used_precursor_for_inversion"] = True
                except Exception as exc:
                    pass_then_invert_pipeline.update(
                        {
                            "fallback_to_direct_generation": True,
                            "inversion_error": str(exc),
                        }
                    )
                    submission, direct_tokens, stage_trajectory = _run_once(
                        active_llm_config,
                        additional_prompt_appendix=direct_appendix,
                    )
                    total_tokens += int(direct_tokens or 0)
                    pass_then_invert_pipeline["fallback_tokens"] = int(direct_tokens or 0)
            else:
                pass_then_invert_pipeline["fallback_to_direct_generation"] = True
                submission, direct_tokens, stage_trajectory = _run_once(
                    active_llm_config,
                    additional_prompt_appendix=direct_appendix,
                )
                total_tokens += int(direct_tokens or 0)
                pass_then_invert_pipeline["fallback_tokens"] = int(direct_tokens or 0)
        except Exception as exc:
            pass_then_invert_pipeline.update(
                {
                    "fallback_to_direct_generation": True,
                    "precursor_error": str(exc),
                }
            )
            submission, total_tokens, stage_trajectory = _run_once(
                active_llm_config,
                additional_prompt_appendix=direct_appendix,
            )
        stage_trajectory = dict(stage_trajectory or {})
        stage_trajectory["pass_then_invert_pipeline"] = dict(pass_then_invert_pipeline)
        return submission, total_tokens, stage_trajectory

    def _finalize_candidate_submission(
        candidate_submission: dict[str, Any],
        candidate_llm_config: LLMConfig,
    ) -> tuple[dict[str, Any], dict[str, Any], dict[str, Any]]:
        finalized_artifact = _finalize_generated_test_suite_artifact(
            candidate_submission,
            repo_path=repo_context.repo_path,
            worktree_path=worktree_path,
            issue_plan=issue_plan,
            issue_description=issue_description,
            llm_model=str(getattr(candidate_llm_config, "model", "") or ""),
            test_command=effective_test_command,
            changed_files=[],
            localization_artifact=localization_artifact,
            repo_context=repo_context,
            runtime_env_overrides=dict(
                getattr(candidate_llm_config, "cli_env_overrides", {}) or {}
            ),
        )
        payload = (
            finalized_artifact.to_dict()
            if finalized_artifact is not None
            else normalize_test_suite_artifact_payload(
                candidate_submission,
                default_framework=str(issue_plan.test_context.test_inventory_framework or ""),
                default_language=str(issue_plan.test_context.test_inventory_language or ""),
                test_command=effective_test_command,
            )
        )
        signal = _test_writer_issue_surface_repair_signal(
            submission=payload,
            worktree_path=worktree_path,
            issue_description=issue_description,
            issue_plan=issue_plan,
            reproduction_artifact=reproduction_artifact,
            localization_artifact=localization_artifact,
            repo_context=repo_context,
        )
        validation_feedback = _test_writer_validation_feedback_signal(
            payload=payload,
            issue_plan=issue_plan,
            issue_description=issue_description,
        )
        return payload, signal, validation_feedback

    def _apply_validation_feedback_repairs(
        *,
        candidate_llm_config: LLMConfig,
        submission: dict[str, Any],
        payload: dict[str, Any],
        signal: dict[str, Any],
        validation_feedback: dict[str, Any],
        stage_trajectory: dict[str, Any],
        tokens_used: int,
        include_issue_surface_feedback: bool = False,
    ) -> tuple[
        dict[str, Any],
        dict[str, Any],
        dict[str, Any],
        dict[str, Any],
        dict[str, Any],
        int,
        int,
    ]:
        current_submission = dict(submission or {})
        current_payload = dict(payload or {})
        current_signal = dict(signal or {})
        current_stage_trajectory = dict(stage_trajectory or {})
        current_validation_feedback = dict(validation_feedback or {})
        candidate_tokens = int(tokens_used or 0)
        validation_feedback_attempts: list[dict[str, Any]] = []
        max_validation_feedback_rounds = 2
        while len(validation_feedback_attempts) < max_validation_feedback_rounds:
            repair_appendix = _build_test_writer_post_finalization_repair_appendix(
                signal=current_signal if include_issue_surface_feedback else {},
                validation_feedback=current_validation_feedback,
            )
            if not repair_appendix.strip():
                break
            retry_reset_paths = _reset_test_writer_workspace_to_baseline(
                worktree_path=worktree_path,
                baseline_commit=resolved_baseline,
            )
            retry_restored_paths = _materialize_test_generation_artifacts(
                worktree_path=worktree_path,
                artifacts=[
                    dict(item)
                    for item in list(preserved_test_artifacts or [])
                    if isinstance(item, dict)
                ],
            )
            try:
                revised_submission, revised_tokens, revised_trajectory = _run_once(
                    candidate_llm_config,
                    additional_prompt_appendix=repair_appendix,
                )
            except Exception as exc:
                validation_feedback_attempts.append(
                    {
                        "attempt_index": len(validation_feedback_attempts) + 1,
                        "reset_paths_before_retry": list(retry_reset_paths),
                        "restored_preserved_paths": list(retry_restored_paths),
                        "repair_signal_initial": _test_writer_repair_signal_snapshot(
                            current_signal
                        ),
                        "initial": _test_writer_validation_feedback_snapshot(
                            current_validation_feedback
                        ),
                        "revised": {},
                        "repair_signal_revised": {},
                        "used_revised_submission": False,
                        "repair_retry_failed": True,
                        "repair_retry_error": str(exc),
                    }
                )
                break
            candidate_tokens += int(revised_tokens or 0)
            revised_payload, revised_signal, revised_validation_feedback = (
                _finalize_candidate_submission(
                    dict(revised_submission or {}),
                    candidate_llm_config,
                )
            )
            use_revised = _test_writer_candidate_is_better(
                candidate_signal=revised_signal,
                candidate_payload=revised_payload,
                baseline_signal=current_signal,
                baseline_payload=current_payload,
            )
            validation_feedback_attempts.append(
                {
                    "attempt_index": len(validation_feedback_attempts) + 1,
                    "reset_paths_before_retry": list(retry_reset_paths),
                    "restored_preserved_paths": list(retry_restored_paths),
                    "repair_signal_initial": _test_writer_repair_signal_snapshot(current_signal),
                    "initial": _test_writer_validation_feedback_snapshot(
                        current_validation_feedback
                    ),
                    "repair_signal_revised": _test_writer_repair_signal_snapshot(revised_signal),
                    "revised": _test_writer_validation_feedback_snapshot(
                        revised_validation_feedback
                    ),
                    "used_revised_submission": use_revised,
                }
            )
            if not use_revised:
                break
            current_submission = dict(revised_submission or {})
            current_payload = dict(revised_payload or {})
            current_signal = dict(revised_signal or {})
            current_stage_trajectory = _carry_forward_test_writer_pipeline_metadata(
                current_stage_trajectory,
                revised_trajectory,
            )
            current_validation_feedback = dict(revised_validation_feedback or {})

        if validation_feedback_attempts:
            current_stage_trajectory = dict(current_stage_trajectory or {})
            current_stage_trajectory["validation_feedback_repair"] = {
                "attempted": True,
                "attempt_count": len(validation_feedback_attempts),
                "attempts": validation_feedback_attempts,
                "initial": dict(validation_feedback_attempts[0].get("initial") or {}),
                "revised": dict(validation_feedback_attempts[-1].get("revised") or {}),
                "repair_signal_initial": dict(
                    validation_feedback_attempts[0].get("repair_signal_initial") or {}
                ),
                "repair_signal_revised": dict(
                    validation_feedback_attempts[-1].get("repair_signal_revised") or {}
                ),
                "triggered_by_issue_surface": bool(
                    include_issue_surface_feedback and signal.get("needs_repair")
                ),
                "triggered_by_validation_feedback": bool(validation_feedback.get("needs_repair")),
                "used_revised_submission": bool(
                    validation_feedback_attempts[-1].get("used_revised_submission")
                ),
                "repair_retry_failed": bool(
                    validation_feedback_attempts[-1].get("repair_retry_failed")
                ),
                "repair_retry_error": str(
                    validation_feedback_attempts[-1].get("repair_retry_error") or ""
                ),
            }
        return (
            current_submission,
            current_payload,
            current_signal,
            current_stage_trajectory,
            current_validation_feedback,
            candidate_tokens,
            len(validation_feedback_attempts),
        )

    candidate_llm_configs = _test_writer_candidate_llm_configs(
        requested_llm_config=llm_config,
        config=config,
        rollout_id=rollout_id,
        brief=effective_brief,
        issue_plan=issue_plan,
    )
    if len(candidate_llm_configs) <= 1:

        def _run_single_candidate(
            active_llm_config: LLMConfig,
        ) -> tuple[dict[str, Any], int, dict[str, Any]]:
            if explicit_test_generation_design and not active_llm_config.is_cli_backend:
                submission, tokens_used, stage_trajectory = _run_api_pass_then_invert_pipeline(
                    active_llm_config
                )
            else:
                submission, tokens_used, stage_trajectory = _run_once(active_llm_config)
            payload, signal, validation_feedback = _finalize_candidate_submission(
                dict(submission or {}),
                active_llm_config,
            )
            (
                _final_submission,
                payload,
                signal,
                stage_trajectory,
                validation_feedback,
                total_tokens,
                validation_feedback_repair_attempt_count,
            ) = _apply_validation_feedback_repairs(
                candidate_llm_config=active_llm_config,
                submission=dict(submission or {}),
                payload=payload,
                signal=signal,
                validation_feedback=validation_feedback,
                stage_trajectory=dict(stage_trajectory or {}),
                tokens_used=int(tokens_used or 0),
                include_issue_surface_feedback=explicit_test_generation_design,
            )
            candidate_record = {
                "candidate_index": 1,
                "backend": str(
                    getattr(
                        active_llm_config.backend,
                        "value",
                        active_llm_config.backend,
                    )
                    or ""
                ),
                "model": str(active_llm_config.model or ""),
                "vendor_family": _model_source_family(str(active_llm_config.model or "")),
                "reset_paths_before_candidate": [],
                "restored_preserved_paths": [],
                "tokens_used": total_tokens,
                "needs_repair": bool(signal.get("needs_repair")),
                "best_issue_target_alignment": float(
                    signal.get("best_issue_target_alignment") or 0.0
                ),
                "contract_matrix_target_coverage_ratio": float(
                    signal.get("contract_matrix_target_coverage_ratio") or 0.0
                ),
                "validation_summary": dict(payload.get("validation_summary") or {}),
                "validation_feedback": _test_writer_validation_feedback_snapshot(
                    validation_feedback
                ),
                "validation_feedback_repair_attempt_count": int(
                    validation_feedback_repair_attempt_count
                ),
                "design_summary": {
                    "objective_count": int(signal.get("design_objective_count") or 0),
                    "candidate_objective_count": int(
                        signal.get("design_candidate_objective_count") or 0
                    ),
                    "verified_objective_count": int(
                        signal.get("design_verified_objective_count") or 0
                    ),
                    "milestone_count": int(signal.get("design_milestone_count") or 0),
                    "core_ready_milestone_count": int(
                        signal.get("design_core_ready_milestone_count") or 0
                    ),
                    "iso_ready_milestone_count": int(
                        signal.get("design_iso_ready_milestone_count") or 0
                    ),
                    "strict_ready_milestone_count": int(
                        signal.get("design_strict_ready_milestone_count") or 0
                    ),
                    "portfolio_strict_ready": bool(signal.get("design_portfolio_strict_ready")),
                    "pass_then_invert_complete_count": int(
                        signal.get("design_pass_then_invert_complete_count") or 0
                    ),
                    "artifact_metadata_gap_count": int(
                        signal.get("design_artifact_metadata_gap_count") or 0
                    ),
                },
            }
            selected_submission = dict(payload)
            selected_submission["_apex_selected_llm_model"] = str(active_llm_config.model or "")
            selected_submission["_apex_selected_llm_backend"] = str(
                getattr(
                    active_llm_config.backend,
                    "value",
                    active_llm_config.backend,
                )
                or ""
            )
            selected_submission["_apex_selected_vendor_family"] = _model_source_family(
                str(active_llm_config.model or "")
            )
            selected_submission["_apex_selected_cli_env_overrides"] = {
                str(key): str(value)
                for key, value in dict(
                    getattr(active_llm_config, "cli_env_overrides", {}) or {}
                ).items()
                if str(key).strip()
            }
            selected_submission["_apex_test_writer_candidate_count"] = 1
            selected_submission["_apex_test_writer_candidates"] = [dict(candidate_record)]
            stage_trajectory = dict(stage_trajectory or {})
            stage_trajectory["portfolio_ensemble"] = {
                "attempted": False,
                "candidate_count": 1,
                "repo_visible_semantic_review_enabled": False,
                "selected_backend": str(
                    getattr(
                        active_llm_config.backend,
                        "value",
                        active_llm_config.backend,
                    )
                    or ""
                ),
                "selected_model": str(active_llm_config.model or ""),
                "selected_vendor_family": _model_source_family(str(active_llm_config.model or "")),
                "candidate_vendor_families": _dedupe_strings(
                    [str(candidate_record.get("vendor_family") or "").strip()]
                ),
                "candidates": [dict(candidate_record)],
            }
            return selected_submission, total_tokens, stage_trajectory

        return _run_with_llm_backend_failover(
            requested_llm_config=llm_config,
            config=config,
            purpose="rollout_test_writer",
            runner=_run_single_candidate,
            allow_fallback=_brief_allows_llm_backend_fallback(config, brief),
        )

    total_tokens = 0
    last_exc: Optional[Exception] = None
    candidate_records: list[dict[str, Any]] = []
    best_submission: Optional[dict[str, Any]] = None
    best_payload: Optional[dict[str, Any]] = None
    best_signal: Optional[dict[str, Any]] = None
    best_trajectory: Optional[dict[str, Any]] = None
    best_llm_config: Optional[LLMConfig] = None
    repo_visible_reference_portfolio = _build_test_writer_repo_visible_reference_portfolio(
        worktree_path=worktree_path,
        issue_description=issue_description,
        issue_plan=issue_plan,
        reproduction_artifact=reproduction_artifact,
        localization_artifact=localization_artifact,
        repo_context=repo_context,
    )
    semantic_review_enabled = bool(
        dict(repo_visible_reference_portfolio or {}).get("summary")
        or list(dict(repo_visible_reference_portfolio or {}).get("contract_hypotheses") or [])
        or list(dict(repo_visible_reference_portfolio or {}).get("test_descriptions") or [])
        or list(dict(repo_visible_reference_portfolio or {}).get("test_artifacts") or [])
    )
    semantic_review_config = (
        _build_test_writer_semantic_review_config(config) if semantic_review_enabled else None
    )
    semantic_review_packet = {
        "instance_id": f"rollout-{rollout_id}-test_writer",
        "repo": str(getattr(repo_context, "repo_path", "") or ""),
        "issue_description": issue_description,
        "required_contract_targets": [
            str(item).strip()
            for item in list(
                dict(repo_visible_reference_portfolio or {}).get("_apex_required_contract_targets")
                or []
            )
            if str(item).strip()
        ],
    }

    for candidate_index, candidate_llm_config in enumerate(candidate_llm_configs, start=1):
        reset_paths = []
        restored_preserved_paths: list[str] = []
        if candidate_index > 1:
            reset_paths = _reset_test_writer_workspace_to_baseline(
                worktree_path=worktree_path,
                baseline_commit=resolved_baseline,
            )
            restored_preserved_paths = _materialize_test_generation_artifacts(
                worktree_path=worktree_path,
                artifacts=[
                    dict(item)
                    for item in list(preserved_test_artifacts or [])
                    if isinstance(item, dict)
                ],
            )
        record: dict[str, Any] = {
            "candidate_index": candidate_index,
            "backend": str(
                getattr(candidate_llm_config.backend, "value", candidate_llm_config.backend) or ""
            ),
            "model": str(candidate_llm_config.model or ""),
            "vendor_family": _model_source_family(str(candidate_llm_config.model or "")),
            "reset_paths_before_candidate": list(reset_paths),
            "restored_preserved_paths": list(restored_preserved_paths),
        }
        try:
            if explicit_test_generation_design and not candidate_llm_config.is_cli_backend:
                submission, tokens_used, stage_trajectory = _run_api_pass_then_invert_pipeline(
                    candidate_llm_config
                )
            else:
                submission, tokens_used, stage_trajectory = _run_once(candidate_llm_config)
            payload, signal, validation_feedback = _finalize_candidate_submission(
                dict(submission or {}),
                candidate_llm_config,
            )
            (
                submission,
                payload,
                signal,
                stage_trajectory,
                current_validation_feedback,
                candidate_tokens,
                validation_feedback_repair_attempt_count,
            ) = _apply_validation_feedback_repairs(
                candidate_llm_config=candidate_llm_config,
                submission=dict(submission or {}),
                payload=payload,
                signal=signal,
                validation_feedback=validation_feedback,
                stage_trajectory=dict(stage_trajectory or {}),
                tokens_used=int(tokens_used or 0),
                include_issue_surface_feedback=explicit_test_generation_design,
            )
            total_tokens += candidate_tokens
            record.update(
                {
                    "tokens_used": candidate_tokens,
                    "needs_repair": bool(signal.get("needs_repair")),
                    "best_issue_target_alignment": float(
                        signal.get("best_issue_target_alignment") or 0.0
                    ),
                    "contract_matrix_target_coverage_ratio": float(
                        signal.get("contract_matrix_target_coverage_ratio") or 0.0
                    ),
                    "validation_summary": dict(payload.get("validation_summary") or {}),
                    "validation_feedback": _test_writer_validation_feedback_snapshot(
                        current_validation_feedback
                    ),
                    "validation_feedback_repair_attempt_count": int(
                        validation_feedback_repair_attempt_count
                    ),
                    "design_summary": {
                        "objective_count": int(signal.get("design_objective_count") or 0),
                        "candidate_objective_count": int(
                            signal.get("design_candidate_objective_count") or 0
                        ),
                        "verified_objective_count": int(
                            signal.get("design_verified_objective_count") or 0
                        ),
                        "milestone_count": int(signal.get("design_milestone_count") or 0),
                        "core_ready_milestone_count": int(
                            signal.get("design_core_ready_milestone_count") or 0
                        ),
                        "iso_ready_milestone_count": int(
                            signal.get("design_iso_ready_milestone_count") or 0
                        ),
                        "strict_ready_milestone_count": int(
                            signal.get("design_strict_ready_milestone_count") or 0
                        ),
                        "portfolio_strict_ready": bool(signal.get("design_portfolio_strict_ready")),
                        "pass_then_invert_complete_count": int(
                            signal.get("design_pass_then_invert_complete_count") or 0
                        ),
                        "artifact_metadata_gap_count": int(
                            signal.get("design_artifact_metadata_gap_count") or 0
                        ),
                    },
                }
            )
            if semantic_review_enabled and semantic_review_config is not None:
                try:
                    repo_visible_semantic_review = review_generated_vs_reference_test_semantics(
                        packet=semantic_review_packet,
                        generated_portfolio=payload,
                        reference_portfolio=repo_visible_reference_portfolio,
                        judge_config=semantic_review_config,
                        working_dir=worktree_path,
                        reference_label="repo-visible reference suite",
                    )
                    repo_visible_semantic_review_summary = summarize_semantic_test_review(
                        repo_visible_semantic_review
                    )
                    payload["_apex_repo_visible_semantic_review"] = dict(
                        repo_visible_semantic_review
                    )
                    payload["_apex_repo_visible_semantic_review_summary"] = dict(
                        repo_visible_semantic_review_summary
                    )
                    semantic_review_tokens = int(
                        dict(repo_visible_semantic_review).get("judge_total_tokens") or 0
                    )
                    total_tokens += semantic_review_tokens
                    record["repo_visible_semantic_review"] = dict(repo_visible_semantic_review)
                    record["repo_visible_semantic_review_summary"] = dict(
                        repo_visible_semantic_review_summary
                    )
                    record["repo_visible_semantic_review_tokens"] = semantic_review_tokens
                except Exception as exc:
                    record["repo_visible_semantic_review_error"] = str(exc)
            candidate_records.append(record)
            if (
                best_signal is None
                or best_payload is None
                or _test_writer_candidate_is_better(
                    candidate_signal=signal,
                    candidate_payload=payload,
                    baseline_signal=best_signal,
                    baseline_payload=best_payload,
                )
            ):
                best_submission = dict(submission or {})
                best_payload = dict(payload or {})
                best_signal = dict(signal or {})
                best_trajectory = dict(stage_trajectory or {})
                best_llm_config = candidate_llm_config
        except Exception as exc:
            last_exc = exc
            record["error"] = str(exc)
            candidate_records.append(record)

    if (
        best_payload is None
        or best_submission is None
        or best_trajectory is None
        or best_llm_config is None
    ):
        if last_exc is not None:
            raise last_exc
        return _run_with_llm_backend_failover(
            requested_llm_config=llm_config,
            config=config,
            purpose="rollout_test_writer",
            runner=_run_once,
            allow_fallback=_brief_allows_llm_backend_fallback(config, brief),
        )

    selected_submission = dict(best_payload)
    selected_submission["_apex_selected_llm_model"] = str(best_llm_config.model or "")
    selected_submission["_apex_selected_llm_backend"] = str(
        getattr(best_llm_config.backend, "value", best_llm_config.backend) or ""
    )
    selected_submission["_apex_selected_vendor_family"] = _model_source_family(
        str(best_llm_config.model or "")
    )
    selected_submission["_apex_selected_cli_env_overrides"] = {
        str(key): str(value)
        for key, value in dict(getattr(best_llm_config, "cli_env_overrides", {}) or {}).items()
        if str(key).strip()
    }
    selected_submission["_apex_test_writer_candidate_count"] = len(candidate_records)
    selected_submission["_apex_test_writer_candidates"] = [
        dict(record) for record in candidate_records
    ]
    best_trajectory = dict(best_trajectory)
    best_trajectory["portfolio_ensemble"] = {
        "attempted": True,
        "candidate_count": len(candidate_records),
        "repo_visible_semantic_review_enabled": semantic_review_enabled,
        "selected_backend": str(
            getattr(best_llm_config.backend, "value", best_llm_config.backend) or ""
        ),
        "selected_model": str(best_llm_config.model or ""),
        "selected_vendor_family": _model_source_family(str(best_llm_config.model or "")),
        "candidate_vendor_families": _dedupe_strings(
            [str(record.get("vendor_family") or "").strip() for record in candidate_records]
        ),
        "candidates": [dict(record) for record in candidate_records],
    }
    return selected_submission, total_tokens, best_trajectory


def _execute_rollout_test_generation(
    *,
    config: ApexConfig,
    repo_path: str,
    repo_context: RepoContext,
    issue_description: str,
    issue_plan: IssuePlan,
    brief: Any,
    worktree_path: str,
    reproduction_artifact: Optional[ReproductionArtifact],
    localization_artifact: Optional[LocalizationArtifact],
    memory_bus: Optional[EpisodicMemoryBus],
    rollout_id: int,
    resolved_baseline: Optional[str],
    execution_tree: Optional[ExecutionTree],
    temperature: float,
    test_command: Optional[str],
    changed_files: list[str],
    status_output_dir: Optional[str] = None,
    stop_after_usable_submission: bool = False,
) -> _TestGenerationExecutionResult:
    active_issue_plan = issue_plan
    active_repo_context = repo_context
    active_brief = brief
    cumulative_portfolio: dict[str, Any] = {}
    cumulative_public_artifacts: list[dict[str, Any]] = []
    total_tokens = 0
    stage_trajectories: list[dict[str, Any]] = []
    loop_enabled = _test_generation_milestone_loop_enabled(active_issue_plan)

    # Phase G.2: mine repo's existing tests as few-shot exemplars and
    # stash on the issue plan's planner_metadata so the test_writer
    # prompt can render them. One-shot per task (not per iteration).
    # Generalizes outside benchmarks: focus_files comes from the brief,
    # which any caller can supply. Cost-bounded by the helper's defaults.
    try:
        from ..preprocessing.repo_test_exemplars import extract_test_exemplars

        focus_files_for_exemplars = list(getattr(active_brief, "focus_files", []) or [])
        if focus_files_for_exemplars:
            # Pull identifier-shaped tokens from the issue text (cheap
            # word boundary regex) so the exemplar miner can score
            # tests that call the same symbols higher.
            issue_keywords = list(
                {
                    tok.lower()
                    for tok in re.findall(r"\b[a-zA-Z_][a-zA-Z0-9_]{2,}\b", issue_description or "")
                }
            )[:32]
            exemplars = extract_test_exemplars(
                repo_path=repo_path,
                focus_files=focus_files_for_exemplars,
                issue_keywords=issue_keywords,
            )
            if exemplars:
                existing_metadata = (
                    dict(active_issue_plan.planner_metadata)
                    if isinstance(getattr(active_issue_plan, "planner_metadata", None), dict)
                    else {}
                )
                existing_metadata["repo_test_exemplars"] = [ex.to_dict() for ex in exemplars]
                active_issue_plan.planner_metadata = existing_metadata
    except Exception as exc:  # pragma: no cover — defensive
        logger.warning("Repo-test exemplar mining failed: %s", exc)

    ledger = _test_generation_ledger(active_issue_plan)
    ordered_milestone_ids = [
        str(item.get("milestone_id") or "").strip()
        for item in list(ledger.get("milestones") or [])
        if isinstance(item, dict) and str(item.get("milestone_id") or "").strip()
    ]
    milestone_count = max(1, len(ordered_milestone_ids) or 1)
    max_iterations = milestone_count + (
        milestone_count * _MAX_TEST_GENERATION_EXECUTOR_REPLANS_PER_MILESTONE
    )
    final_artifact: Optional[TestSuiteArtifact] = None
    final_submission: dict[str, Any] = {}
    loop_records: list[dict[str, Any]] = []

    # Soft wall-clock budget for the entire milestone loop. The iteration
    # count cap (`max_iterations`) is the primary safety; this is an
    # additional ceiling for the case where each iteration runs near its
    # CLI timeout and the cumulative time still blows past what's
    # reasonable for a single rollout.
    # K4 (progress-based liveness): the testgen milestone loop's wall-clock break
    # is DISARMED by default — ``max_iterations`` is the primary bound and the K2
    # CLI stall watchdog enforces per-step liveness, so a long-but-progressing
    # milestone loop is never cut off on elapsed time. The break remains
    # available as an OPT-IN advisory ceiling via the env var (a positive value
    # re-arms it); when unset the budget is infinite (no wall-clock break).
    wallclock_budget_env = os.environ.get("APEX_TEST_GENERATION_ROLLOUT_WALLCLOCK_SECONDS")
    try:
        wallclock_budget_seconds = (
            float(wallclock_budget_env)
            if wallclock_budget_env is not None and wallclock_budget_env.strip()
            else float("inf")
        )
    except (TypeError, ValueError):
        wallclock_budget_seconds = float("inf")
    if wallclock_budget_seconds <= 0:
        wallclock_budget_seconds = float("inf")
    loop_started_at = time.time()
    wallclock_deadline = (
        loop_started_at + wallclock_budget_seconds
        if wallclock_budget_seconds != float("inf")
        else None
    )
    wallclock_exhausted = False

    def _remaining_wallclock_seconds(*, safety_margin_seconds: float = 5.0) -> Optional[float]:
        if wallclock_deadline is None:
            return None
        return max(0.0, wallclock_deadline - time.time() - safety_margin_seconds)

    def _persist_iteration_state() -> None:
        _persist_test_generation_portfolio_state(
            cumulative_portfolio,
            output_dir=status_output_dir,
        )
        _persist_test_generation_state(
            active_issue_plan,
            output_dir=status_output_dir,
        )

    _persist_iteration_state()

    for iteration_index in range(max_iterations):
        elapsed_seconds = time.time() - loop_started_at
        if elapsed_seconds >= wallclock_budget_seconds:
            wallclock_exhausted = True
            loop_records.append(
                {
                    "iteration_index": iteration_index,
                    "event": "wallclock_budget_exhausted",
                    "elapsed_seconds": round(elapsed_seconds, 1),
                    "wallclock_budget_seconds": wallclock_budget_seconds,
                    "milestone_id": str(ledger.get("current_milestone_id") or "").strip(),
                    "completed_iterations": iteration_index,
                }
            )
            logger.warning(
                "Test-generation rollout %s aborted milestone loop after "
                "%.1fs (budget %.0fs); using portfolio from iteration %d",
                rollout_id,
                elapsed_seconds,
                wallclock_budget_seconds,
                iteration_index,
            )
            break
        reloaded_issue_plan_from_disk = False
        reloaded_portfolio_from_disk = False
        if iteration_index > 0:
            reloaded_issue_plan_from_disk = _reload_test_generation_state_from_disk(
                active_issue_plan,
                output_dir=status_output_dir,
            )
            if status_output_dir:
                cumulative_portfolio = {}
                cumulative_public_artifacts = []
                final_submission = {}
                final_artifact = None
                reloaded_portfolio = _reload_test_generation_portfolio_state_from_disk(
                    output_dir=status_output_dir,
                )
                if reloaded_portfolio:
                    cumulative_portfolio = dict(reloaded_portfolio)
                    cumulative_public_artifacts = _test_generation_public_artifacts(
                        cumulative_portfolio
                    )
                    final_submission = dict(cumulative_portfolio)
                    try:
                        final_artifact = TestSuiteArtifact.from_dict(cumulative_portfolio)
                    except Exception:
                        final_artifact = None
                    reloaded_portfolio_from_disk = True
        if stop_after_usable_submission and cumulative_portfolio:
            reloaded_usable_summary = _test_generation_usable_submission_summary(
                cumulative_portfolio
            )
            if bool(reloaded_usable_summary.get("usable")):
                loop_records.append(
                    {
                        "iteration_index": iteration_index,
                        "event": "usable_submission_reloaded_stop",
                        "state_reinitialized_from_ledger": iteration_index > 0,
                        "reloaded_issue_plan_from_disk": reloaded_issue_plan_from_disk,
                        "reloaded_portfolio_from_disk": reloaded_portfolio_from_disk,
                        "usable_submission_stop": True,
                        "usable_submission_summary": dict(reloaded_usable_summary),
                    }
                )
                final_submission = dict(cumulative_portfolio)
                break
        # Phase F.2 / G.0: surface prior-iteration feedback signals
        # to this iteration's prompt by stashing them in the issue
        # plan's planner_metadata. The prompt builder reads from
        # there. Engine.py touch is intentionally minimal — the
        # prompt builder owns the rendering.
        prior_feedback = (cumulative_portfolio or {}).get("prior_iteration_f2p_feedback")
        prior_axis_coverage = (cumulative_portfolio or {}).get("prior_iteration_axis_coverage")
        prior_mutation_sensitivity = (cumulative_portfolio or {}).get(
            "prior_iteration_mutation_sensitivity"
        )
        prior_coverage_gap = (cumulative_portfolio or {}).get("prior_iteration_coverage_gap")
        prior_test_quality = (cumulative_portfolio or {}).get("prior_iteration_test_quality")
        prior_test_stability = (cumulative_portfolio or {}).get("prior_iteration_test_stability")
        prior_assertion_mutation = (cumulative_portfolio or {}).get(
            "prior_iteration_assertion_mutation"
        )
        prior_quarantined_paths = dict(
            dict((cumulative_portfolio or {}).get("validation_summary") or {}).get(
                "quarantined_test_paths"
            )
            or {}
        )
        prior_edge_predictions = (cumulative_portfolio or {}).get(
            "prior_iteration_edge_predictions"
        )
        # Phase G.9: query the shared EpisodicMemoryBus for testgen
        # insights from OTHER parallel rollouts. This runs even on
        # iteration 0 so sequential best-of-N testgen evals can use
        # discoveries broadcast by earlier sibling rollouts.
        cross_rollout_dict: Optional[dict[str, Any]] = None
        try:
            from ..evaluation.iteration_feedback import (
                derive_cross_rollout_feedback,
            )

            cross_feedback = derive_cross_rollout_feedback(
                memory_bus=memory_bus,
                rollout_id=rollout_id,
                iteration_index=iteration_index,
            )
            if cross_feedback.is_actionable():
                cross_rollout_dict = cross_feedback.to_dict()
        except Exception as exc:  # pragma: no cover — defensive
            logger.warning(
                "Cross-rollout testgen feedback derivation failed: %s",
                exc,
            )
        if (
            prior_feedback
            or prior_axis_coverage
            or prior_mutation_sensitivity
            or prior_coverage_gap
            or prior_test_quality
            or prior_test_stability
            or prior_assertion_mutation
            or prior_quarantined_paths
            or prior_edge_predictions
            or cross_rollout_dict
        ):
            existing_metadata = (
                dict(active_issue_plan.planner_metadata)
                if isinstance(getattr(active_issue_plan, "planner_metadata", None), dict)
                else {}
            )
            if prior_feedback:
                existing_metadata["prior_iteration_f2p_feedback"] = dict(prior_feedback)
            if prior_axis_coverage:
                existing_metadata["prior_iteration_axis_coverage"] = dict(prior_axis_coverage)
            if prior_mutation_sensitivity:
                existing_metadata["prior_iteration_mutation_sensitivity"] = dict(
                    prior_mutation_sensitivity
                )
            if prior_coverage_gap:
                existing_metadata["prior_iteration_coverage_gap"] = dict(prior_coverage_gap)
            if prior_test_quality:
                existing_metadata["prior_iteration_test_quality"] = dict(prior_test_quality)
            if prior_test_stability:
                existing_metadata["prior_iteration_test_stability"] = dict(prior_test_stability)
            if prior_assertion_mutation:
                existing_metadata["prior_iteration_assertion_mutation"] = dict(
                    prior_assertion_mutation
                )
            if prior_quarantined_paths:
                existing_metadata["quarantined_test_paths"] = dict(prior_quarantined_paths)
            if prior_edge_predictions:
                existing_metadata["prior_iteration_edge_predictions"] = dict(prior_edge_predictions)
            if cross_rollout_dict:
                existing_metadata["cross_rollout_testgen_feedback"] = dict(cross_rollout_dict)
            active_issue_plan.planner_metadata = existing_metadata
        execution_context = _test_generation_execution_context(
            active_issue_plan,
            issue_description=issue_description,
            required_contract_targets=[],
            required_contract_axes=[],
        )
        current_milestone_id = str(execution_context.get("current_milestone_id") or "").strip()
        if loop_enabled and not current_milestone_id:
            break

        if iteration_index > 0:
            reset_paths = _reset_test_writer_workspace_to_baseline(
                worktree_path=worktree_path,
                baseline_commit=resolved_baseline,
            )
            restored_paths = _materialize_test_generation_artifacts(
                worktree_path=worktree_path,
                artifacts=cumulative_public_artifacts,
                quarantined_paths=prior_quarantined_paths,
            )
        else:
            reset_paths = []
            restored_paths = []

        iteration_memory_bus = memory_bus
        iteration_execution_tree = execution_tree
        if iteration_index > 0:
            iteration_memory_bus = EpisodicMemoryBus() if memory_bus is not None else None
            iteration_execution_tree = None

        test_stage_llm = _resolve_stage_llm_config(
            config,
            rollout_id,
            "test_writer",
            brief=active_brief,
        )
        remaining_for_stage = _remaining_wallclock_seconds(safety_margin_seconds=15.0)
        if remaining_for_stage is not None and remaining_for_stage <= 30.0:
            wallclock_exhausted = True
            loop_records.append(
                {
                    "iteration_index": iteration_index,
                    "event": "wallclock_budget_preempted_before_stage",
                    "wallclock_remaining_seconds": round(remaining_for_stage, 1),
                    "milestone_id": current_milestone_id,
                    "completed_iterations": iteration_index,
                }
            )
            logger.warning(
                "Test-generation rollout %s preempted before test_writer "
                "stage; only %.1fs remained in wallclock budget.",
                rollout_id,
                remaining_for_stage,
            )
            break
        stage_submission, stage_tokens, stage_trajectory = _run_scaffold_test_writer_stage(
            llm_config=test_stage_llm,
            config=config,
            repo_context=active_repo_context,
            issue_description=issue_description,
            issue_plan=active_issue_plan,
            brief=active_brief,
            worktree_path=worktree_path,
            reproduction_artifact=reproduction_artifact,
            localization_artifact=localization_artifact,
            memory_bus=iteration_memory_bus,
            rollout_id=rollout_id,
            resolved_baseline=resolved_baseline,
            execution_tree=iteration_execution_tree,
            temperature=temperature,
            preserved_test_artifacts=cumulative_public_artifacts,
            status_output_dir=status_output_dir,
            wallclock_deadline=wallclock_deadline,
        )
        total_tokens += stage_tokens
        final_submission = _merge_cumulative_test_generation_submission(
            cumulative_portfolio,
            stage_submission,
        )
        final_artifact = _finalize_generated_test_suite_artifact(
            final_submission,
            repo_path=repo_path,
            worktree_path=worktree_path,
            issue_plan=active_issue_plan,
            issue_description=issue_description,
            llm_model=_test_writer_selected_llm_model(
                stage_submission,
                test_stage_llm,
            ),
            test_command=test_command,
            changed_files=list(changed_files or []),
            localization_artifact=localization_artifact,
            repo_context=active_repo_context,
            runtime_env_overrides=_test_writer_selected_runtime_env_overrides(
                stage_submission,
                test_stage_llm,
            ),
            status_output_dir=status_output_dir,
            rollout_id=rollout_id,
        )
        if final_artifact is not None:
            cumulative_portfolio = final_artifact.to_dict()
            cumulative_public_artifacts = _test_generation_public_artifacts(cumulative_portfolio)
            final_submission = dict(cumulative_portfolio)
        usable_submission_source = cumulative_portfolio or final_submission
        usable_submission_summary = (
            _test_generation_usable_submission_summary(usable_submission_source)
            if stop_after_usable_submission and usable_submission_source
            else {"usable": False, "usable_paths": [], "blocked": []}
        )
        usable_submission_stop = bool(usable_submission_summary.get("usable"))
        # Phase F.2: derive closed-loop F2P-style feedback from this
        # iteration's quick_verification result so iteration N+1's
        # prompt can warn the agent about P2P (useless) tests it just
        # wrote. The agent has been writing tests against the broken
        # worktree, so any test that PASSES on the worktree cannot be
        # F2P by construction. Without this feedback the agent has no
        # way to know which of its tests need to be rewritten.
        iteration_feedback = None
        axis_feedback = None
        candidate_paths: list[str] = []
        try:
            from ..evaluation.iteration_feedback import (
                broadcast_iteration_testgen_insights,
                classify_iteration_feedback,
                derive_axis_coverage_feedback,
                derive_edge_prediction_feedback,
            )

            quick_verification_payload = (
                dict(stage_submission.get("_apex_quick_verification") or {})
                if isinstance(stage_submission, dict)
                else {}
            )
            candidate_paths = [
                str(a.get("path") or "").strip()
                for a in cumulative_public_artifacts
                if a.get("path")
            ]
            iteration_feedback = classify_iteration_feedback(
                quick_verification_payload=quick_verification_payload,
                candidate_test_paths=candidate_paths,
                iteration_index=iteration_index,
            )
            if iteration_feedback.is_actionable():
                cumulative_portfolio["prior_iteration_f2p_feedback"] = iteration_feedback.to_dict()
                final_submission = dict(cumulative_portfolio)
            # Phase G.0: per-iteration axis-coverage feedback. Walks the
            # agent's own declared contract_axes across artifacts to
            # surface "still missing X" nudges in the next iteration.
            # Cheap (no F2P / mutation oracle required) and generalizes
            # outside benchmarks because it's rooted in the agent's
            # declared axes, not a gold suite.
            axis_feedback = derive_axis_coverage_feedback(
                test_artifacts=cumulative_public_artifacts,
                iteration_index=iteration_index,
            )
            if axis_feedback.is_actionable():
                cumulative_portfolio["prior_iteration_axis_coverage"] = axis_feedback.to_dict()
                final_submission = dict(cumulative_portfolio)
            # Phase G.3: structured adversarial edge predictions →
            # exercised-vs-unaddressed feedback for the next iteration.
            edge_feedback = derive_edge_prediction_feedback(
                submission=stage_submission if isinstance(stage_submission, dict) else None,
                iteration_index=iteration_index,
            )
            if edge_feedback.is_actionable():
                cumulative_portfolio["prior_iteration_edge_predictions"] = edge_feedback.to_dict()
                final_submission = dict(cumulative_portfolio)
            # Static oracle-quality feedback is cheap enough to run every
            # iteration. It catches passing-but-useless tests before the
            # expensive F2P/mutation stages have to diagnose them.
            try:
                from ..evaluation.test_quality import analyze_test_artifacts_quality

                quality_summary = analyze_test_artifacts_quality(
                    [
                        dict(artifact)
                        for artifact in list(cumulative_public_artifacts or [])
                        if isinstance(artifact, dict)
                    ],
                    language=str(
                        getattr(issue_plan.test_context, "test_inventory_language", "") or "python"
                    ),
                ).to_dict()
                quality_summary["iteration_index"] = iteration_index
                if int(quality_summary.get("weak_artifact_count") or 0) > 0:
                    cumulative_portfolio["prior_iteration_test_quality"] = quality_summary
                    final_submission = dict(cumulative_portfolio)
            except Exception as quality_exc:  # pragma: no cover - defensive
                logger.warning(
                    "Iteration test-quality feedback derivation failed: %s",
                    quality_exc,
                )
        except Exception as exc:  # pragma: no cover — defensive
            logger.warning("Iteration F2P feedback derivation failed: %s", exc)
        stability_enabled = os.environ.get(
            "APEX_ENABLE_ITERATION_STABILITY", ""
        ).strip().lower() in {"1", "true", "yes", "on", "enabled"}
        if stability_enabled and candidate_paths:
            try:
                from ..evaluation.test_stability import evaluate_test_stability

                stability_report = evaluate_test_stability(
                    worktree_path=worktree_path,
                    test_paths=candidate_paths,
                    language=str(
                        getattr(issue_plan.test_context, "test_inventory_language", "") or "python"
                    ),
                    runs=int(os.environ.get("APEX_ITERATION_STABILITY_RUNS", "2") or 2),
                    timeout_seconds=30.0,
                )
                stability_summary = stability_report.to_dict()
                stability_summary["iteration_index"] = iteration_index
                if not stability_report.stable:
                    cumulative_portfolio["prior_iteration_test_stability"] = stability_summary
                    final_submission = dict(cumulative_portfolio)
            except Exception as exc:  # pragma: no cover - defensive
                logger.warning("Iteration test-stability derivation failed: %s", exc)
        assertion_mutation_disabled = os.environ.get(
            "APEX_DISABLE_ITERATION_ASSERTION_MUTATION", ""
        ).strip().lower() in {"1", "true", "yes", "on", "enabled"}
        if not assertion_mutation_disabled and candidate_paths:
            try:
                from ..evaluation.assertion_mutation import (
                    evaluate_assertion_effect_in_loop,
                )

                assertion_report = evaluate_assertion_effect_in_loop(
                    worktree_path=worktree_path,
                    test_paths=candidate_paths,
                    language=str(
                        getattr(issue_plan.test_context, "test_inventory_language", "") or "python"
                    ),
                    timeout_seconds=30.0,
                )
                assertion_summary = assertion_report.to_dict()
                assertion_summary["iteration_index"] = iteration_index
                if bool(assertion_report.survived) or str(assertion_report.status) in {
                    "no_assertions_mutated",
                    "baseline_no_tests_collected",
                }:
                    cumulative_portfolio["prior_iteration_assertion_mutation"] = assertion_summary
                    final_submission = dict(cumulative_portfolio)
            except Exception as exc:  # pragma: no cover - defensive
                logger.warning("Iteration assertion-mutation derivation failed: %s", exc)
        # Phase I.1: in-loop mutation sensitivity is now ALWAYS-ON for
        # testgen rollouts. The closed-loop signal it produces is the
        # single biggest mutation-score lever the literature
        # (e-Otter++, AdverTest, UTRL) confirms. Default budget bumped
        # from 1×1×15s to 3 files × 8 mutants × 30s — within the
        # rollout's 45-min wallclock cap, gives the agent meaningful
        # sensitivity signal across multiple iterations. Opt-OUT via
        # APEX_DISABLE_ITERATION_MUTATION=1 (still respected for the
        # rare case where mutation cost has to be capped).
        mutation_feedback = None
        in_loop_mutation_disabled = os.environ.get(
            "APEX_DISABLE_ITERATION_MUTATION", ""
        ).strip().lower() in {"1", "true", "yes", "on", "enabled"}
        if not in_loop_mutation_disabled and not usable_submission_stop:
            try:
                from ..evaluation.iteration_feedback import (
                    derive_mutation_sensitivity_feedback,
                )
                from ..evaluation.mutation_engine import (
                    evaluate_mutation_sensitivity_in_loop,
                    source_path_is_supported_for_mutation,
                )

                # Target up to 3 focus files (was 1) so multi-file bug
                # surfaces are exercised. If none are configured, skip
                # cleanly — feedback is non-actionable.
                mutation_language = str(
                    getattr(issue_plan.test_context, "test_inventory_language", "") or "python"
                ).lower()
                target_source_paths = [
                    str(p)
                    for p in list(getattr(active_brief, "focus_files", []) or [])
                    if source_path_is_supported_for_mutation(
                        str(p),
                        language=mutation_language,
                    )
                ][:3]
                remaining_for_mutation = _remaining_wallclock_seconds(safety_margin_seconds=10.0)
                if (
                    target_source_paths
                    and candidate_paths
                    and (remaining_for_mutation is None or remaining_for_mutation > 45.0)
                ):
                    mutation_timeout = (
                        30.0
                        if remaining_for_mutation is None
                        else max(5.0, min(30.0, remaining_for_mutation / 4.0))
                    )
                    baseline_timeout = (
                        60.0
                        if remaining_for_mutation is None
                        else max(10.0, min(60.0, remaining_for_mutation / 3.0))
                    )
                    mutation_report = evaluate_mutation_sensitivity_in_loop(
                        worktree_path=worktree_path,
                        test_paths=candidate_paths,
                        target_source_paths=target_source_paths,
                        language=mutation_language,
                        max_mutants_per_file=8,
                        max_files=3,
                        per_mutant_timeout_seconds=mutation_timeout,
                        baseline_timeout_seconds=baseline_timeout,
                        seed=iteration_index,
                    )
                    mutation_feedback = derive_mutation_sensitivity_feedback(
                        mutation_report=mutation_report,
                        iteration_index=iteration_index,
                    )
                    if mutation_feedback.is_actionable():
                        cumulative_portfolio["prior_iteration_mutation_sensitivity"] = (
                            mutation_feedback.to_dict()
                        )
                        final_submission = dict(cumulative_portfolio)
            except Exception as exc:  # pragma: no cover — defensive
                logger.warning("Iteration mutation sensitivity derivation failed: %s", exc)
        # Phase I.3: in-loop coverage-gap feedback. Same pattern as
        # mutation: target up to 3 focus files, run pytest with
        # `coverage run --branch` against the worktree, parse the
        # missing-line list into contiguous ranges, and stash on
        # cumulative_portfolio so iteration N+1's prompt can show the
        # agent exactly which lines of the focus file(s) are not
        # exercised. Always-on; opt-OUT via APEX_DISABLE_ITERATION_COVERAGE=1.
        coverage_disabled = os.environ.get(
            "APEX_DISABLE_ITERATION_COVERAGE", ""
        ).strip().lower() in {"1", "true", "yes", "on", "enabled"}
        if not coverage_disabled and not usable_submission_stop:
            try:
                from ..evaluation.coverage_engine import (
                    evaluate_coverage_for_language_in_loop,
                )
                from ..evaluation.iteration_feedback import (
                    derive_coverage_gap_feedback,
                )

                raw_focus_paths = [
                    str(p)
                    for p in list(getattr(active_brief, "focus_files", []) or [])
                    if str(p).strip()
                ]
                coverage_language = str(
                    getattr(issue_plan.test_context, "test_inventory_language", "") or ""
                ).lower()
                if not coverage_language:
                    if any(path.endswith((".ts", ".tsx")) for path in raw_focus_paths):
                        coverage_language = "typescript"
                    elif any(path.endswith((".js", ".jsx")) for path in raw_focus_paths):
                        coverage_language = "javascript"
                    else:
                        coverage_language = "python"
                if coverage_language in {"python", "py", "python3"}:
                    supported_suffixes = (".py",)
                elif coverage_language in {
                    "javascript",
                    "js",
                    "jsx",
                    "typescript",
                    "ts",
                    "tsx",
                }:
                    supported_suffixes = (".js", ".jsx", ".ts", ".tsx")
                else:
                    supported_suffixes = tuple()
                coverage_target_paths = [
                    path
                    for path in raw_focus_paths
                    if not supported_suffixes or path.endswith(supported_suffixes)
                ][:3]
                remaining_for_coverage = _remaining_wallclock_seconds(safety_margin_seconds=10.0)
                if (
                    coverage_target_paths
                    and candidate_paths
                    and (remaining_for_coverage is None or remaining_for_coverage > 20.0)
                ):
                    coverage_timeout = (
                        120.0
                        if remaining_for_coverage is None
                        else max(10.0, min(120.0, remaining_for_coverage))
                    )
                    coverage_report = evaluate_coverage_for_language_in_loop(
                        worktree_path=worktree_path,
                        test_paths=candidate_paths,
                        target_source_paths=coverage_target_paths,
                        language=coverage_language,
                        timeout_seconds=coverage_timeout,
                    )
                    coverage_feedback = derive_coverage_gap_feedback(
                        coverage_report=coverage_report,
                        iteration_index=iteration_index,
                    )
                    if coverage_feedback.is_actionable():
                        cumulative_portfolio["prior_iteration_coverage_gap"] = (
                            coverage_feedback.to_dict()
                        )
                        final_submission = dict(cumulative_portfolio)
            except Exception as exc:  # pragma: no cover — defensive
                logger.warning("Iteration coverage-gap derivation failed: %s", exc)
        # Phase G.9 / I.2: broadcast this iteration's testgen findings
        # to the shared EpisodicMemoryBus so OTHER parallel rollouts on
        # the same task can query them. Moved AFTER in-loop mutation so
        # we can broadcast killed-mutant signatures (positive signal
        # for divergence) and insensitive-test paths (negative pattern
        # to avoid) alongside F2P-likely paths and covered axes.
        try:
            broadcast_iteration_testgen_insights(
                memory_bus=memory_bus,
                rollout_id=rollout_id,
                iteration_index=iteration_index,
                f2p_feedback=iteration_feedback,
                axis_feedback=axis_feedback,
                mutation_feedback=mutation_feedback,
            )
        except Exception as exc:  # pragma: no cover — defensive
            logger.warning("Cross-rollout broadcast failed: %s", exc)
        _persist_iteration_state()

        aligned_reset_paths = _reset_test_writer_workspace_to_baseline(
            worktree_path=worktree_path,
            baseline_commit=resolved_baseline,
        )
        aligned_materialized_paths = _materialize_test_generation_artifacts(
            worktree_path=worktree_path,
            artifacts=cumulative_public_artifacts,
            quarantined_paths=dict(
                dict((cumulative_portfolio or {}).get("validation_summary") or {}).get(
                    "quarantined_test_paths"
                )
                or {}
            ),
        )

        regression_suite_summary = (
            dict(cumulative_portfolio.get("regression_suite_summary") or {})
            if cumulative_portfolio
            else {}
        )
        advance_details = {
            "advanced": False,
            "previous_current_milestone_id": current_milestone_id,
            "next_current_milestone_id": current_milestone_id,
            "strict_ready": bool(regression_suite_summary.get("strict_ready")),
        }
        refresh_details = {
            "attempted": False,
            "refreshed": False,
            "error": "",
            "reason": "",
        }
        executor_replan = {
            "requested": False,
            "reason": "",
            "attempted": False,
            "attempt_count": 0,
            "max_attempts_per_milestone": _MAX_TEST_GENERATION_EXECUTOR_REPLANS_PER_MILESTONE,
            "capped": False,
            "boundary_pressure_count": 0,
            "threshold": 0,
            "boundary_requested_files": [],
            "boundary_interface_symbols": [],
            "boundary_followups": [],
            "active_milestone_blocking_objectives": [],
            "design_missing_objective_ids": [],
            "design_missing_milestone_ids": [],
            "design_artifact_metadata_gap_count": 0,
            "design_artifact_metadata_gaps": [],
        }
        if final_artifact is not None and loop_enabled and not usable_submission_stop:
            advance_details = _advance_test_generation_ledger_after_milestone(
                active_issue_plan,
                promoted_portfolio=cumulative_portfolio,
            )
            _persist_iteration_state()
            if advance_details.get("advanced") and not bool(advance_details.get("strict_ready")):
                (
                    active_issue_plan,
                    refreshed_repo_context,
                    refresh_details,
                ) = _refresh_test_generation_issue_plan_at_boundary(
                    config=config,
                    issue_plan=active_issue_plan,
                    issue_description=issue_description,
                    worktree_path=worktree_path,
                    test_command=test_command,
                )
                if refreshed_repo_context is not None:
                    active_repo_context = refreshed_repo_context
                if list(active_issue_plan.rollout_briefs or []):
                    active_brief = _select_rollout_brief(
                        active_issue_plan,
                        rollout_id,
                        brief=None,
                        config=config,
                    )
                _persist_iteration_state()
            elif not bool(advance_details.get("strict_ready")):
                executor_replan = _test_generation_executor_replan_request(
                    config=config,
                    issue_plan=active_issue_plan,
                    execution_context=execution_context,
                    stage_trajectory=stage_trajectory,
                )
                if bool(executor_replan.get("requested")):
                    executor_replan["attempted"] = True
                    executor_replan["attempt_count"] = (
                        _record_test_generation_executor_replan_attempt(
                            active_issue_plan,
                            milestone_id=current_milestone_id,
                            reason=str(executor_replan.get("reason") or "executor_feedback"),
                        )
                    )
                    _persist_iteration_state()
                    (
                        active_issue_plan,
                        refreshed_repo_context,
                        refresh_details,
                    ) = _refresh_test_generation_issue_plan_at_boundary(
                        config=config,
                        issue_plan=active_issue_plan,
                        issue_description=issue_description,
                        worktree_path=worktree_path,
                        test_command=test_command,
                        boundary_context=dict(executor_replan.get("boundary_context") or {}),
                    )
                    if refreshed_repo_context is not None:
                        active_repo_context = refreshed_repo_context
                    if list(active_issue_plan.rollout_briefs or []):
                        active_brief = _select_rollout_brief(
                            active_issue_plan,
                            rollout_id,
                            brief=None,
                            config=config,
                        )
                    _persist_iteration_state()

        stage_metadata = {
            "iteration_index": iteration_index + 1,
            "current_milestone_id": current_milestone_id,
            "loop_enabled": loop_enabled,
            "reset_paths_before_iteration": list(reset_paths),
            "restored_paths_before_iteration": list(restored_paths),
            "aligned_reset_paths": list(aligned_reset_paths),
            "aligned_materialized_paths": list(aligned_materialized_paths),
            "cumulative_public_artifact_count": len(cumulative_public_artifacts),
            "state_reinitialized_from_ledger": iteration_index > 0,
            "reloaded_issue_plan_from_disk": reloaded_issue_plan_from_disk,
            "reloaded_portfolio_from_disk": reloaded_portfolio_from_disk,
            "iteration_memory_bus_reused": iteration_memory_bus is memory_bus,
            "iteration_execution_tree_reused": iteration_execution_tree is execution_tree,
            "advance": dict(advance_details),
            "boundary_refresh": dict(refresh_details),
            "executor_replan": dict(executor_replan),
            "usable_submission_stop": bool(usable_submission_stop),
            "usable_submission_summary": dict(usable_submission_summary),
        }
        stage_trajectory = dict(stage_trajectory or {})
        stage_trajectory["test_generation_milestone"] = dict(stage_metadata)
        stage_trajectories.append(stage_trajectory)
        loop_records.append(stage_metadata)

        if not loop_enabled:
            break
        if usable_submission_stop:
            break
        if bool(advance_details.get("strict_ready")):
            break
        if bool(executor_replan.get("requested")) and bool(refresh_details.get("refreshed")):
            continue
        if not bool(advance_details.get("advanced")):
            break

    return _TestGenerationExecutionResult(
        submission=final_submission,
        artifact=final_artifact,
        tokens_used=total_tokens,
        trajectory=stage_trajectories,
        loop_summary={
            "enabled": loop_enabled,
            "iteration_count": len(loop_records),
            "iterations": loop_records,
            "wallclock_budget_seconds": (
                wallclock_budget_seconds if wallclock_budget_seconds != float("inf") else None
            ),
            "wallclock_elapsed_seconds": round(time.time() - loop_started_at, 1),
            "wallclock_exhausted": wallclock_exhausted,
        },
    )


def _execute_single_rollout(
    rollout_id: int,
    config: ApexConfig,
    repo_context: RepoContext,
    issue_description: str,
    issue_plan: IssuePlan,
    worktree_path: str,
    test_command: Optional[str],
    rollout_brief: Optional[RolloutBrief] = None,
    baseline_commit: Optional[str] = None,
    memory_bus: Optional[EpisodicMemoryBus] = None,
    wallclock_deadline: Optional[float] = None,
    cancel_check: Optional[Callable[[], bool]] = None,
    cancel_reason: Optional[Callable[[], str]] = None,
    advisory_seed_reproduction_artifact: Optional[ReproductionArtifact] = None,
    advisory_seed_localization_artifact: Optional[LocalizationArtifact] = None,
    advisory_seed_source_rollout_id: Optional[int] = None,
) -> RolloutResult:
    start_time = time.time()
    brief = _select_rollout_brief(
        issue_plan,
        rollout_id,
        brief=rollout_brief,
        config=config,
    )
    standalone_anchor = _brief_is_standalone_anchor(brief)
    repo_label = _rollout_repo_label(repo_context, worktree_path)
    profile_index = _rollout_brief_profile_index(brief)
    status_output_dir = config.output_dir
    rollout_llm_config = _resolve_rollout_llm_config(
        config,
        rollout_id,
        brief=brief,
    )
    temperature = config.get_temperature_for_rollout(rollout_id)
    strategy = config.get_prompt_strategy_for_rollout(rollout_id)
    # Phase A.4 (Decisive-Edge): strategy-axis diversity. K rollouts now
    # round-robin through K strategically distinct approaches. The
    # canonical 7-axis library is :data:`STRATEGY_AXES`; operators may
    # subset / reorder via ``RolloutConfig.diversity_strategies``.
    # The strategy prefix is prepended to ``issue_description`` here so
    # every downstream agent surface (scaffolded MASAI patcher, CLI
    # agent, in-container V5 agent) sees the steered prompt without
    # needing per-agent injection.
    diversity_axis = assign_strategy(
        rollout_id,
        n_rollouts=max(1, int(getattr(config.rollout, "num_rollouts", 1))),
        enabled_strategies=list(getattr(config.rollout, "diversity_strategies", []) or [])
        or list(STRATEGY_AXES),
    )
    if not standalone_anchor and not _brief_policy_bool(brief, "disable_strategy_prefix"):
        issue_description = apply_strategy_prefix(issue_description, diversity_axis)
    agent_mode = _resolve_agent_mode(config, issue_plan, rollout_id, brief=brief)
    result_llm_config = (
        _resolve_stage_llm_config(config, rollout_id, "patcher", brief=brief)
        if agent_mode == AgentMode.SCAFFOLDED
        else rollout_llm_config
    )
    resolved_baseline = baseline_commit or _resolve_head_commit(Path(worktree_path))
    rollout_start_commit = _resolve_head_commit(Path(worktree_path))
    execution_tree = None
    if (
        config.execution_tree.enabled
        and resolved_baseline
        and _issue_plan_enables_execution_tree(issue_plan)
    ):
        execution_tree = ExecutionTree(
            worktree_path=worktree_path,
            baseline_commit=resolved_baseline,
            max_depth=config.execution_tree.max_depth,
            max_branches=config.execution_tree.max_branches,
        )
        execution_tree.initialize()

    result = RolloutResult(
        rollout_id=rollout_id,
        success=False,
        worktree_path=worktree_path,
        temperature=temperature,
        prompt_strategy=strategy.value,
        llm_model=result_llm_config.model,
        agent_mode=agent_mode.value,
        plan_title=brief.title,
        allocation_key=_rollout_brief_allocation_key(brief),
        baseline_commit=resolved_baseline,
        multi_agent_summary=_planned_multi_agent_summary(
            config,
            issue_plan,
            brief,
            result_llm_config,
        ),
        rollout_profile_index=profile_index,
        rollout_profile_signature=_resolve_rollout_profile_signature(
            config,
            rollout_id,
            brief=brief,
        ),
        stage_model_routing=_resolve_stage_model_routing(
            config,
            rollout_id,
            brief=brief,
        ),
    )
    rollout_backend = getattr(result_llm_config, "backend", "")
    if hasattr(rollout_backend, "value"):
        rollout_backend = rollout_backend.value
    result.search_metadata.update(
        {
            "rollout_llm_backend": str(rollout_backend or "").strip(),
            "rollout_llm_model": str(result_llm_config.model or "").strip(),
            "rollout_profile_index": profile_index,
            "rollout_orchestration_primitives": list(issue_plan.orchestration_primitives),
            "rollout_profile_signature": list(result.rollout_profile_signature),
            # Phase A.4 (Decisive-Edge): record the assigned strategy axis
            # so reviewers can audit which strategic approach each rollout
            # took. Empty string means strategy diversity was disabled.
            "diversity_strategy_axis": str(diversity_axis or ""),
            "standalone_agent_anchor": bool(standalone_anchor),
        }
    )
    component_ablation = component_ablation_assignment_for_task(
        config=config,
        issue_plan=issue_plan,
        repo_label=repo_label,
    )
    result.search_metadata["component_ablation"] = dict(component_ablation)

    def _finalize_cancelled_rollout(
        reason: str,
        *,
        phase: str = "orchestration",
    ) -> RolloutResult:
        cancel_reason_text = str(reason or "rollout cancelled by scheduler")

        # A4: escrow an already-authoritative full-scope pass before the cancel
        # stamp wins. If this rollout already produced (or durably wrote) a clean
        # local full-scope pass, preserve it as a score-bearing candidate instead
        # of discarding it. This closes the finalize-time race where a confirmed
        # 1.0 candidate landing near the wall-clock deadline (or just before a
        # stop-on-result preempt) is lost to ``scheduler_cancelled``.
        escrow_qv = _detect_escrowable_full_scope_pass(result, worktree_path)
        if escrow_qv is not None:
            result.success = True
            result.salvaged_for_external_scoring = True
            result.failure_reason = None
            result.failure_class = None
            result.failure_classification = None
            result.quick_verification = _merge_quick_verification_detail(
                result.quick_verification if isinstance(result.quick_verification, dict) else {},
                escrow_qv,
            )
            if not result.worktree_path:
                result.worktree_path = worktree_path
            result.duration_seconds = time.time() - start_time
            result.search_metadata["full_scope_pass_escrowed_through_cancel"] = True
            result.search_metadata["scheduler_cancelled_after_full_scope_pass"] = True
            result.search_metadata["escrow_cancel_phase"] = str(phase or "orchestration")
            result.search_metadata["escrow_cancel_reason"] = cancel_reason_text
            logger.info(
                "Rollout %s escrowed authoritative full-scope pass through cancel: "
                "repo=%s phase=%s reason=%s",
                rollout_id,
                repo_label,
                phase,
                cancel_reason_text,
            )
            _write_rollout_progress_state(
                status_output_dir,
                rollout_id,
                {
                    "status": "completed",
                    "stage": "rollout_finished",
                    "stage_status": "completed",
                    "model": result.llm_model,
                    "state": "completed",
                    "last_progress_at": time.time(),
                    "last_progress_source": "full_scope_pass_escrowed_through_cancel",
                    "terminal_state": "completed",
                    "duration_seconds": result.duration_seconds,
                    "success": True,
                    "failure_reason": None,
                    "rollout_terminal": True,
                    "full_scope_pass_escrowed_through_cancel": True,
                    "scheduler_cancelled_after_full_scope_pass": True,
                    "worktree_path": result.worktree_path,
                    "quick_verification": _compact_quick_verification_for_status(
                        result.quick_verification
                    ),
                },
            )
            return result

        classification = classify_core_failure(
            stderr=cancel_reason_text,
            stdout="",
            returncode=130,
            context={"phase": phase or "orchestration", "preempted": True},
        )
        result.success = False
        result.salvaged_for_external_scoring = False
        result.failure_reason = cancel_reason_text
        result.failure_class = classification.failure_class
        result.failure_classification = classification
        result.search_metadata["scheduler_cancelled"] = True
        result.search_metadata["scheduler_cancelled_phase"] = str(phase or "orchestration")
        result.duration_seconds = time.time() - start_time
        logger.info(
            "Rollout %s cancelled: repo=%s phase=%s reason=%s",
            rollout_id,
            repo_label,
            phase,
            cancel_reason_text,
        )
        _write_rollout_progress_state(
            status_output_dir,
            rollout_id,
            {
                "status": "error",
                "stage": "rollout_cancelled",
                "stage_status": "cancelled",
                "model": result.llm_model,
                "state": "completed",
                "last_progress_at": time.time(),
                "last_progress_source": "scheduler_cancelled",
                "terminal_state": "cancelled",
                "duration_seconds": result.duration_seconds,
                "success": False,
                "failure_reason": result.failure_reason,
                "rollout_terminal": True,
                "scheduler_cancelled": True,
                "scheduler_cancelled_phase": str(phase or "orchestration"),
                "_clear_keys": [
                    "quick_verification",
                    "verification_scope",
                    "verification_command",
                    "verification_passed",
                    "verification_failed",
                    "verification_errors",
                    "verification_returncode",
                    "verification_timed_out",
                    "verification_selected_test_count",
                ],
            },
        )
        return result

    def _cancelled_result_if_requested(
        *,
        phase: str,
        default_reason: str,
    ) -> Optional[RolloutResult]:
        try:
            _raise_if_rollout_cancelled(
                cancel_check,
                cancel_reason,
                phase=phase,
                default_reason=default_reason,
            )
        except _RolloutCancelled as exc:
            return _finalize_cancelled_rollout(exc.reason, phase=exc.phase)
        return None

    cancelled_result = _cancelled_result_if_requested(
        phase="orchestration",
        default_reason="rollout cancelled before rollout start",
    )
    if cancelled_result is not None:
        return cancelled_result

    if isinstance(wallclock_deadline, (int, float)) and wallclock_deadline > 0:
        result.search_metadata["task_wallclock_deadline"] = float(wallclock_deadline)
        if time.time() >= float(wallclock_deadline):
            failure_reason = "task wall-clock budget exhausted before rollout start"
            classification = classify_core_failure(
                stderr=failure_reason,
                stdout="",
                returncode=124,
                context={"phase": "test_execution", "timed_out": True},
            )
            result.failure_reason = failure_reason
            result.failure_class = classification.failure_class
            result.failure_classification = classification
            result.search_metadata["wallclock_exhausted"] = True
            return result
    try:
        evidence_policy = issue_plan.evaluation_constraints.resolved_evidence_policy()
        result.search_metadata["evidence_mode"] = evidence_policy.mode
        result.search_metadata["evidence_policy"] = evidence_policy.to_dict()
    except Exception:
        result.search_metadata["evidence_mode"] = str(
            getattr(issue_plan.test_context, "evidence_mode", "") or ""
        )
    _write_rollout_progress_state(
        status_output_dir,
        rollout_id,
        {
            "status": "active",
            "stage": "rollout_start",
            "stage_status": "active",
            "model": result.llm_model,
            "state": "active",
            "agent_mode": result.agent_mode,
            "profile_index": profile_index,
            "profile_signature": list(result.rollout_profile_signature),
            "stage_model_routing": dict(result.stage_model_routing),
            "stage_started_at": start_time,
            "last_progress_at": start_time,
            "rollout_terminal": False,
        },
    )

    logger.info(
        "Rollout %s starting: repo=%s model=%s temp=%s strategy=%s mode=%s profile=%s title=%s",
        rollout_id,
        repo_label,
        result_llm_config.model,
        temperature,
        strategy.value,
        agent_mode.value,
        profile_index if profile_index is not None else "-",
        brief.title,
    )
    if agent_mode == AgentMode.SCAFFOLDED:
        stage_models = {
            stage_name: _resolve_stage_llm_config(
                config,
                rollout_id,
                stage_name,
                brief=brief,
            ).model
            for stage_name in ("reproducer", "localizer", "patcher", "test_writer")
        }
        if len(set(stage_models.values())) > 1:
            logger.info(
                "Rollout %s scaffold stage routing: repo=%s reproducer=%s localizer=%s patcher=%s test_writer=%s",
                rollout_id,
                repo_label,
                stage_models["reproducer"],
                stage_models["localizer"],
                stage_models["patcher"],
                stage_models["test_writer"],
            )

    patch_result = None
    llm_failure: Optional[str] = None
    backend_anomaly_from_failure: dict[str, Any] = {}
    generate_test_suites = _should_generate_test_suites(
        config,
        issue_description=issue_description,
        issue_plan=issue_plan,
    )
    submission_state_captured = False

    try:
        reproduction_artifact: Optional[ReproductionArtifact] = None
        localization_artifact: Optional[LocalizationArtifact] = None

        # SPEED LEVER (cross-rollout discovery REUSE): an ADVISORY warm-start
        # seed harvested from the FIRST sibling rollout to produce a
        # high-confidence reproduction + localization. Coerced fail-open: any
        # malformed payload degrades to None and each stage re-derives its own
        # discovery (today's behavior). The seed is honoured identically to a
        # bootstrap proposal — for the SCAFFOLDED path it is promoted into the
        # bootstrap variables below so the existing ``_artifact_has_*_signal``
        # skip mechanism fires; for the CLI path it is consumed by
        # ``_run_cli_masai_preround`` (skip-when-seeded) via these locals. It is
        # strictly advisory: the patcher prompt frames it as a hint not a
        # constraint, and the distinct-hypothesis ``localizer_top_k`` fan-out is
        # untouched, so best-of-N independence is preserved.
        advisory_seed_reproduction: Optional[ReproductionArtifact] = None
        advisory_seed_localization: Optional[LocalizationArtifact] = None
        try:
            if advisory_seed_reproduction_artifact is not None:
                _coerced_repro = coerce_reproduction_artifact(advisory_seed_reproduction_artifact)
                if _artifact_has_reproduction_signal(_coerced_repro):
                    advisory_seed_reproduction = _coerced_repro
            if advisory_seed_localization_artifact is not None:
                _coerced_loc = coerce_localization_artifact(advisory_seed_localization_artifact)
                if _artifact_has_localization_signal(_coerced_loc):
                    advisory_seed_localization = _coerced_loc
        except Exception as advisory_seed_exc:  # noqa: BLE001 - fail-open
            advisory_seed_reproduction = None
            advisory_seed_localization = None
            logger.debug(
                "Advisory discovery seed coercion failed for rollout %s (%s); "
                "falling back to per-rollout derivation.",
                rollout_id,
                advisory_seed_exc,
            )
        if advisory_seed_reproduction is not None or advisory_seed_localization is not None:
            result.search_metadata["advisory_discovery_reuse"] = {
                "reproduction": advisory_seed_reproduction is not None,
                "localization": advisory_seed_localization is not None,
                "source_rollout_id": (
                    int(advisory_seed_source_rollout_id)
                    if advisory_seed_source_rollout_id is not None
                    else None
                ),
            }

        if agent_mode == AgentMode.SCAFFOLDED:
            scaffold_trajectory: list[dict[str, Any]] = []
            bootstrap_reason, bootstrap_reproduction, bootstrap_localization, bootstrap_trace = (
                _select_rollout_bootstrap_proposal(
                    config=config,
                    issue_plan=issue_plan,
                    brief=brief,
                    test_command=test_command,
                )
            )
            # Promote the advisory cross-rollout seed into the bootstrap
            # variables when the heuristic bootstrap lacks signal for that
            # stage. A real, signal-bearing bootstrap proposal always wins (we
            # never override it); we only fill the gap the heuristic left empty,
            # and we reuse the existing skip path verbatim.
            if advisory_seed_reproduction is not None and not _artifact_has_reproduction_signal(
                bootstrap_reproduction
            ):
                bootstrap_reproduction = advisory_seed_reproduction
                if not bootstrap_reason:
                    bootstrap_reason = "cross_rollout_discovery_reuse"
            if advisory_seed_localization is not None and not _artifact_has_localization_signal(
                bootstrap_localization
            ):
                bootstrap_localization = advisory_seed_localization
                if not bootstrap_reason:
                    bootstrap_reason = "cross_rollout_discovery_reuse"
            if bootstrap_reason:
                result.search_metadata["bootstrap_proposal"] = bootstrap_reason
            if bootstrap_trace:
                result.search_metadata["rollout_shadow_policy_log"] = [bootstrap_trace]

            reproducer_llm_config = _resolve_stage_llm_config(
                config,
                rollout_id,
                "reproducer",
                brief=brief,
            )
            localizer_llm_config = _resolve_stage_llm_config(
                config,
                rollout_id,
                "localizer",
                brief=brief,
            )
            patcher_llm_config = _resolve_stage_llm_config(
                config,
                rollout_id,
                "patcher",
                brief=brief,
            )

            if bootstrap_reason and _artifact_has_reproduction_signal(bootstrap_reproduction):
                reproduction_artifact = bootstrap_reproduction
                repro_submission = reproduction_artifact.to_dict()
                tokens_used = 0
                stage_trajectory = _build_seeded_stage_trajectory(
                    "reproducer",
                    reproducer_llm_config,
                    repro_submission,
                    seed_reason=bootstrap_reason,
                )
            else:
                repro_submission, tokens_used, stage_trajectory = _run_scaffold_reproducer_stage(
                    llm_config=reproducer_llm_config,
                    config=config,
                    repo_context=repo_context,
                    issue_description=issue_description,
                    issue_plan=issue_plan,
                    brief=brief,
                    worktree_path=worktree_path,
                    test_command=test_command,
                    memory_bus=memory_bus,
                    rollout_id=rollout_id,
                    resolved_baseline=resolved_baseline,
                    execution_tree=execution_tree,
                    temperature=temperature,
                    status_output_dir=status_output_dir,
                    wallclock_deadline=wallclock_deadline,
                )
                reproduction_artifact = coerce_reproduction_artifact(repro_submission)
                stage_trajectory = dict(stage_trajectory)
                if (
                    bootstrap_reason
                    and not _artifact_has_reproduction_signal(reproduction_artifact)
                    and _artifact_has_reproduction_signal(bootstrap_reproduction)
                ):
                    reproduction_artifact = bootstrap_reproduction
                    repro_submission = reproduction_artifact.to_dict()
                    stage_trajectory["bootstrap_fallback"] = {
                        "seed_reason": bootstrap_reason,
                        "used": True,
                    }
                elif bootstrap_reason:
                    stage_trajectory["bootstrap_proposal"] = {"seed_reason": bootstrap_reason}
            _raise_if_rollout_cancelled(
                cancel_check,
                cancel_reason,
                phase="reproducer",
                default_reason="rollout cancelled after reproducer stage",
            )
            result.reproduction_artifact = (
                reproduction_artifact.to_dict() if reproduction_artifact else {}
            )
            result.total_tokens += tokens_used
            scaffold_trajectory.append(stage_trajectory)
            _maybe_broadcast_stage_summary(
                memory_bus,
                rollout_id=rollout_id,
                insight_type="TEST_STRATEGY",
                submission=repro_submission,
                confidence=0.6,
                stage_name="reproducer",
            )

            if component_disabled(component_ablation, "localization"):
                localization_artifact = None
                loc_submission = {
                    "summary": "Localization scaffold disabled by component ablation.",
                    "files": [],
                    "symbols": [],
                    "hypotheses": [],
                    "_apex_component_ablation": dict(component_ablation),
                }
                tokens_used = 0
                stage_trajectory = {
                    "stage": "localizer",
                    "status": "skipped",
                    "reason": "component_ablation_disabled_localization",
                    "component_ablation": dict(component_ablation),
                    "tokens_used": 0,
                }
            elif bootstrap_reason and _artifact_has_localization_signal(bootstrap_localization):
                localization_artifact = bootstrap_localization
                loc_submission = localization_artifact.to_dict()
                tokens_used = 0
                stage_trajectory = _build_seeded_stage_trajectory(
                    "localizer",
                    localizer_llm_config,
                    loc_submission,
                    seed_reason=bootstrap_reason,
                )
            else:
                loc_submission, tokens_used, stage_trajectory = _run_scaffold_localizer_stage(
                    llm_config=localizer_llm_config,
                    config=config,
                    repo_context=repo_context,
                    issue_description=issue_description,
                    issue_plan=issue_plan,
                    brief=brief,
                    worktree_path=worktree_path,
                    reproduction_artifact=reproduction_artifact,
                    memory_bus=memory_bus,
                    rollout_id=rollout_id,
                    resolved_baseline=resolved_baseline,
                    execution_tree=execution_tree,
                    temperature=temperature,
                    status_output_dir=status_output_dir,
                    wallclock_deadline=wallclock_deadline,
                )
                localization_artifact = coerce_localization_artifact(loc_submission)
                stage_trajectory = dict(stage_trajectory)
                if (
                    bootstrap_reason
                    and not _artifact_has_localization_signal(localization_artifact)
                    and _artifact_has_localization_signal(bootstrap_localization)
                ):
                    localization_artifact = bootstrap_localization
                    loc_submission = localization_artifact.to_dict()
                    stage_trajectory["bootstrap_fallback"] = {
                        "seed_reason": bootstrap_reason,
                        "used": True,
                    }
                elif bootstrap_reason:
                    stage_trajectory["bootstrap_proposal"] = {"seed_reason": bootstrap_reason}
            _raise_if_rollout_cancelled(
                cancel_check,
                cancel_reason,
                phase="localizer",
                default_reason="rollout cancelled after localizer stage",
            )
            result.localization_artifact = (
                localization_artifact.to_dict() if localization_artifact else {}
            )
            result.total_tokens += tokens_used
            scaffold_trajectory.append(stage_trajectory)
            _maybe_broadcast_stage_summary(
                memory_bus,
                rollout_id=rollout_id,
                insight_type="ROOT_CAUSE",
                submission=loc_submission,
                confidence=0.7,
                stage_name="localizer",
            )

            submission, tokens_used, stage_trajectory = _run_scaffold_patcher_stage(
                llm_config=patcher_llm_config,
                config=config,
                repo_context=repo_context,
                issue_description=issue_description,
                issue_plan=issue_plan,
                brief=brief,
                worktree_path=worktree_path,
                strategy=strategy,
                test_command=test_command,
                reproduction_artifact=reproduction_artifact,
                localization_artifact=localization_artifact,
                memory_bus=memory_bus,
                rollout_id=rollout_id,
                resolved_baseline=resolved_baseline,
                execution_tree=execution_tree,
                temperature=temperature,
                status_output_dir=status_output_dir,
                wallclock_deadline=wallclock_deadline,
                cancel_check=cancel_check,
                cancel_reason=cancel_reason,
                component_ablation=component_ablation,
            )
            _raise_if_rollout_cancelled(
                cancel_check,
                cancel_reason,
                phase="patcher",
                default_reason="rollout cancelled after patcher stage",
            )
            result.patch_artifact = _serialize_patch_submission(submission)
            result.total_tokens += tokens_used
            scaffold_trajectory.append(stage_trajectory)
            patch_result = _CLIExecutionResult(
                success=True,
                submission=submission,
                trajectory=scaffold_trajectory,
            )
            result.trajectory = list(scaffold_trajectory)
            _maybe_broadcast_stage_summary(
                memory_bus,
                rollout_id=rollout_id,
                insight_type="PATCH_DIRECTION",
                submission=result.patch_artifact,
                confidence=float(result.patch_artifact.get("confidence") or 0.65),
                stage_name="patcher",
            )
            patch_checkpoint_id, patch_state_captured = _capture_submission_state(
                execution_tree,
                result.patch_artifact or submission,
            )
            if patch_checkpoint_id:
                result.best_checkpoint_id = patch_checkpoint_id
            submission_state_captured = (
                submission_state_captured or patch_state_captured or bool(patch_checkpoint_id)
            )

            if generate_test_suites:
                _raise_if_rollout_cancelled(
                    cancel_check,
                    cancel_reason,
                    phase="test_writer",
                    default_reason="rollout cancelled before generated-test stage",
                )
                test_writer_baseline_commit = (
                    _execution_tree_checkpoint_commit(
                        execution_tree,
                        patch_checkpoint_id or result.best_checkpoint_id,
                    )
                    or resolved_baseline
                )
                test_generation_result = _execute_rollout_test_generation(
                    config=config,
                    repo_path=repo_context.repo_path,
                    repo_context=repo_context,
                    issue_description=issue_description,
                    issue_plan=issue_plan,
                    brief=brief,
                    worktree_path=worktree_path,
                    reproduction_artifact=reproduction_artifact,
                    localization_artifact=localization_artifact,
                    memory_bus=memory_bus,
                    rollout_id=rollout_id,
                    resolved_baseline=test_writer_baseline_commit,
                    execution_tree=execution_tree,
                    temperature=temperature,
                    test_command=test_command,
                    changed_files=list(result.patch_artifact.get("changed_files") or []),
                    status_output_dir=status_output_dir,
                )
                test_submission = dict(test_generation_result.submission or {})
                test_artifact = test_generation_result.artifact
                result.total_tokens += test_generation_result.tokens_used
                result.test_suite_artifact = test_artifact.to_dict() if test_artifact else {}
                result.test_suite = (
                    test_artifact.test_code if test_artifact else test_submission.get("test_code")
                )
                result.test_descriptions = (
                    list(test_artifact.test_descriptions)
                    if test_artifact
                    else test_submission.get("test_descriptions", [])
                )
                if test_artifact and isinstance(test_artifact.public_signal, dict):
                    result.search_metadata["public_signal"] = dict(test_artifact.public_signal)
                if test_artifact and isinstance(test_artifact.validation_summary, dict):
                    result.search_metadata["generated_test_portfolio"] = dict(
                        test_artifact.validation_summary
                    )
                if test_generation_result.loop_summary:
                    result.search_metadata["test_generation_milestone_loop"] = dict(
                        test_generation_result.loop_summary
                    )
                result.trajectory.extend(list(test_generation_result.trajectory))
                _maybe_broadcast_stage_summary(
                    memory_bus,
                    rollout_id=rollout_id,
                    insight_type="TEST_STRATEGY",
                    submission=test_submission,
                    confidence=0.5,
                    stage_name="test_writer",
                )
        elif rollout_llm_config.is_cli_backend and cli_backend_is_healthy(rollout_llm_config):
            cli_trajectory: list[dict[str, Any]] = []
            # SPEED LEVER (cross-rollout discovery REUSE): on the CLI path the
            # advisory seed is consumed by ``_run_cli_masai_preround`` via these
            # locals (it skips the reproducer/localizer pre-round when the
            # artifact is already present). The pre-round prompt frames the
            # findings as advisory ("hint, not a constraint"), so siblings stay
            # free to diverge. Only fill what the seed actually carries.
            if reproduction_artifact is None and advisory_seed_reproduction is not None:
                reproduction_artifact = advisory_seed_reproduction
            if localization_artifact is None and advisory_seed_localization is not None:
                localization_artifact = advisory_seed_localization
            followup_rounds = 1
            if not standalone_anchor and config.rollout.enable_quick_verification and test_command:
                followup_rounds = _size_aware_followup_round_cap(config, issue_plan)
            first_round_llm_config = _select_collection_error_fast_path_first_round_llm_config(
                config,
                rollout_id,
                rollout_llm_config,
                issue_plan=issue_plan,
                brief=brief,
            )

            submission, tokens_used, stage_trajectory = _run_cli_patcher(
                config=config,
                llm_config=rollout_llm_config,
                first_round_llm_config=first_round_llm_config,
                worktree_path=worktree_path,
                baseline_commit=resolved_baseline,
                repo_path=repo_context.repo_path,
                issue_description=issue_description,
                issue_plan=issue_plan,
                brief=brief,
                strategy=strategy,
                test_command=test_command,
                use_concise_prompts=config.use_concise_prompts,
                reproduction_artifact=reproduction_artifact,
                localization_artifact=localization_artifact,
                memory_bus=memory_bus,
                rollout_id=rollout_id,
                quick_verification_timeout_seconds=config.rollout.quick_verification_timeout_seconds,
                quick_verification_max_tests=config.rollout.quick_verification_max_tests,
                max_followup_rounds=followup_rounds,
                enable_orchestrated_delegation=_patcher_delegate_subtasks_enabled(
                    config,
                    brief,
                    issue_plan,
                ),
                status_output_dir=status_output_dir,
                wallclock_deadline=wallclock_deadline,
                cancel_check=cancel_check,
                cancel_reason=cancel_reason,
                execution_tree=execution_tree,
                component_ablation=component_ablation,
            )
            _raise_if_rollout_cancelled(
                cancel_check,
                cancel_reason,
                phase="patcher",
                default_reason="rollout cancelled after CLI patcher stage",
            )
            result.patch_artifact = _serialize_patch_submission(submission)
            result.total_tokens += tokens_used
            cli_trajectory.append(stage_trajectory)
            patch_result = _CLIExecutionResult(
                success=True,
                submission=submission,
                trajectory=cli_trajectory,
            )
            result.trajectory = list(cli_trajectory)
            # Decisive-Edge C.1 — surface the per-rollout localizer
            # dispatch decision directly on ``search_metadata`` so
            # selectors / reports don't have to dig through the
            # trajectory to learn which hypothesis this rollout
            # consumed.
            preround_meta = (
                stage_trajectory.get("masai_preround")
                if isinstance(stage_trajectory, dict)
                else None
            )
            if isinstance(preround_meta, dict):
                if "localizer_hypothesis_index" in preround_meta:
                    result.search_metadata["localizer_hypothesis_index"] = int(
                        preround_meta.get("localizer_hypothesis_index") or 0
                    )
                if "localizer_top_k_requested" in preround_meta:
                    result.search_metadata["localizer_top_k_requested"] = int(
                        preround_meta.get("localizer_top_k_requested") or 1
                    )
                if "localizer_top_k_returned" in preround_meta:
                    result.search_metadata["localizer_top_k_returned"] = int(
                        preround_meta.get("localizer_top_k_returned") or 0
                    )
            _maybe_broadcast_stage_summary(
                memory_bus,
                rollout_id=rollout_id,
                insight_type="PATCH_DIRECTION",
                submission=result.patch_artifact,
                confidence=float(result.patch_artifact.get("confidence") or 0.65),
                stage_name="patcher",
            )
            patch_checkpoint_id, patch_state_captured = _capture_submission_state(
                execution_tree,
                result.patch_artifact or submission,
            )
            if patch_checkpoint_id:
                result.best_checkpoint_id = patch_checkpoint_id
            submission_state_captured = (
                submission_state_captured or patch_state_captured or bool(patch_checkpoint_id)
            )

            if generate_test_suites:
                _raise_if_rollout_cancelled(
                    cancel_check,
                    cancel_reason,
                    phase="test_writer",
                    default_reason="rollout cancelled before generated-test stage",
                )
                test_writer_baseline_commit = (
                    _execution_tree_checkpoint_commit(
                        execution_tree,
                        patch_checkpoint_id or result.best_checkpoint_id,
                    )
                    or resolved_baseline
                )
                test_generation_result = _execute_rollout_test_generation(
                    config=config,
                    repo_path=repo_context.repo_path,
                    repo_context=repo_context,
                    issue_description=issue_description,
                    issue_plan=issue_plan,
                    brief=brief,
                    worktree_path=worktree_path,
                    reproduction_artifact=reproduction_artifact,
                    localization_artifact=localization_artifact,
                    memory_bus=memory_bus,
                    rollout_id=rollout_id,
                    resolved_baseline=test_writer_baseline_commit,
                    execution_tree=execution_tree,
                    temperature=temperature,
                    test_command=test_command,
                    changed_files=list(result.patch_artifact.get("changed_files") or []),
                    status_output_dir=status_output_dir,
                )
                test_submission = dict(test_generation_result.submission or {})
                test_artifact = test_generation_result.artifact
                result.total_tokens += test_generation_result.tokens_used
                result.test_suite_artifact = test_artifact.to_dict() if test_artifact else {}
                result.test_suite = (
                    test_artifact.test_code if test_artifact else test_submission.get("test_code")
                )
                result.test_descriptions = (
                    list(test_artifact.test_descriptions)
                    if test_artifact
                    else test_submission.get("test_descriptions", [])
                )
                if test_artifact and isinstance(test_artifact.public_signal, dict):
                    result.search_metadata["public_signal"] = dict(test_artifact.public_signal)
                if test_artifact and isinstance(test_artifact.validation_summary, dict):
                    result.search_metadata["generated_test_portfolio"] = dict(
                        test_artifact.validation_summary
                    )
                if test_generation_result.loop_summary:
                    result.search_metadata["test_generation_milestone_loop"] = dict(
                        test_generation_result.loop_summary
                    )
                result.trajectory.extend(list(test_generation_result.trajectory))
                _maybe_broadcast_stage_summary(
                    memory_bus,
                    rollout_id=rollout_id,
                    insight_type="TEST_STRATEGY",
                    submission=test_submission,
                    confidence=0.5,
                    stage_name="test_writer",
                )
        elif not rollout_llm_config.is_cli_backend and rollout_llm_config.has_api_key:
            solver = _instantiate_agent(
                FullSolverAgent,
                llm_config=rollout_llm_config,
                working_dir=worktree_path,
                aci_config=config.aci,
                context_config=config.context,
                repo_context=repo_context,
                rollout_id=rollout_id,
                memory_bus=memory_bus,
                execution_tree=execution_tree,
                baseline_commit=resolved_baseline,
                temperature=temperature,
                max_iterations=config.rollout.max_iterations_per_rollout,
                strategy=strategy,
                use_concise_prompts=config.use_concise_prompts,
                enable_subagents=_patcher_subagent_tools_enabled(config, issue_plan),
                enable_delegate_subtasks=_patcher_delegate_subtasks_enabled(
                    config,
                    brief,
                    issue_plan,
                ),
            )
            # TIER 2 (T2.3): install the enforced module-group write scope on the
            # API solver's executor before it runs. The sticky scope survives the
            # solver's internal advisory ``set_write_scope`` call so off-group
            # edits are reverted in-loop. No-op for non-module-group briefs.
            _owned_group_files, _enforce_group = module_group_write_scope(
                getattr(brief, "search_policy", None)
            )
            if (
                _enforce_group
                and _owned_group_files
                and hasattr(getattr(solver, "executor", None), "set_module_group_write_scope")
            ):
                solver.executor.set_module_group_write_scope(
                    _owned_group_files,
                    enforce=True,
                )
            patch_result = solver.run(
                issue_description=issue_description,
                issue_plan=issue_plan,
                rollout_brief=brief,
                test_command=test_command,
            )
            _raise_if_rollout_cancelled(
                cancel_check,
                cancel_reason,
                phase="patcher",
                default_reason="rollout cancelled after API solver stage",
            )
            result.patch_artifact = _serialize_patch_submission(patch_result.submission)
            result.total_tokens += patch_result.tokens_used
            result.trajectory = patch_result.trajectory
            _maybe_broadcast_stage_summary(
                memory_bus,
                rollout_id=rollout_id,
                insight_type="PATCH_DIRECTION",
                submission=result.patch_artifact,
                confidence=float(result.patch_artifact.get("confidence") or 0.65),
                stage_name="patcher",
            )
            patch_checkpoint_id, patch_state_captured = _capture_submission_state(
                execution_tree,
                result.patch_artifact or patch_result.submission,
            )
            if patch_checkpoint_id:
                result.best_checkpoint_id = patch_checkpoint_id
            submission_state_captured = (
                submission_state_captured or patch_state_captured or bool(patch_checkpoint_id)
            )

            if generate_test_suites:
                _raise_if_rollout_cancelled(
                    cancel_check,
                    cancel_reason,
                    phase="test_writer",
                    default_reason="rollout cancelled before generated-test stage",
                )
                test_writer_baseline_commit = (
                    _execution_tree_checkpoint_commit(
                        execution_tree,
                        patch_checkpoint_id or result.best_checkpoint_id,
                    )
                    or resolved_baseline
                )
                test_generation_result = _execute_rollout_test_generation(
                    config=config,
                    repo_path=repo_context.repo_path,
                    repo_context=repo_context,
                    issue_description=issue_description,
                    issue_plan=issue_plan,
                    brief=brief,
                    worktree_path=worktree_path,
                    reproduction_artifact=reproduction_artifact,
                    localization_artifact=localization_artifact,
                    memory_bus=memory_bus,
                    rollout_id=rollout_id,
                    resolved_baseline=test_writer_baseline_commit,
                    execution_tree=execution_tree,
                    temperature=temperature,
                    test_command=test_command,
                    changed_files=list(result.patch_artifact.get("changed_files") or []),
                    status_output_dir=status_output_dir,
                )
                test_submission = dict(test_generation_result.submission or {})
                test_artifact = test_generation_result.artifact
                result.total_tokens += test_generation_result.tokens_used
                result.test_suite_artifact = test_artifact.to_dict() if test_artifact else {}
                result.test_suite = (
                    test_artifact.test_code if test_artifact else test_submission.get("test_code")
                )
                result.test_descriptions = (
                    list(test_artifact.test_descriptions)
                    if test_artifact
                    else test_submission.get("test_descriptions", [])
                )
                if test_artifact and isinstance(test_artifact.public_signal, dict):
                    result.search_metadata["public_signal"] = dict(test_artifact.public_signal)
                if test_artifact and isinstance(test_artifact.validation_summary, dict):
                    result.search_metadata["generated_test_portfolio"] = dict(
                        test_artifact.validation_summary
                    )
                if test_generation_result.loop_summary:
                    result.search_metadata["test_generation_milestone_loop"] = dict(
                        test_generation_result.loop_summary
                    )
                result.trajectory.extend(list(test_generation_result.trajectory))
        else:
            llm_failure = _llm_unavailable_reason(rollout_llm_config)
    except _RolloutCancelled as exc:
        return _finalize_cancelled_rollout(exc.reason, phase=exc.phase)
    except Exception as exc:
        llm_failure = str(exc)
        if isinstance(exc, _CLIStageFailure):
            backend_anomaly_from_failure = dict(getattr(exc, "backend_anomaly", {}) or {})
            timeout_audit = dict(getattr(exc, "timeout_audit", {}) or {})
            output_excerpt = str(getattr(exc, "output_excerpt", "") or "").strip()
            backend_failure_config = result_llm_config
            stage_name = str(getattr(exc, "stage_name", "") or "patcher").strip()
            if agent_mode == AgentMode.SCAFFOLDED and stage_name:
                try:
                    backend_failure_config = _configured_stage_llm_config_for_deadline(
                        config,
                        rollout_id,
                        stage_name,
                        brief=brief,
                    )
                except Exception:
                    backend_failure_config = result_llm_config
            recorded_backend_failure_reason = record_llm_backend_failure(
                backend_failure_config,
                exc,
            )
            failure_event: dict[str, Any] = {
                "stage": stage_name or "patcher",
                "reason": llm_failure,
            }
            if recorded_backend_failure_reason:
                failure_event["recorded_backend_failure_reason"] = recorded_backend_failure_reason
            if timeout_audit:
                failure_event["timeout_audit"] = timeout_audit
            if backend_anomaly_from_failure:
                failure_event["backend_anomaly"] = dict(backend_anomaly_from_failure)
            if output_excerpt:
                failure_event["output_excerpt"] = output_excerpt
            policy_validity_failure = (
                str(backend_anomaly_from_failure.get("kind") or "").strip().lower()
                == "workspace_policy_violation"
            )
            if recorded_backend_failure_reason or (
                backend_anomaly_from_failure and not policy_validity_failure
            ):
                result.search_metadata["backend_failure_event"] = failure_event
            else:
                result.search_metadata["stage_failure_event"] = failure_event

    cancelled_result = _cancelled_result_if_requested(
        phase="orchestration",
        default_reason="rollout cancelled before rollout post-processing",
    )
    if cancelled_result is not None:
        return cancelled_result

    if patch_result and patch_result.success:
        result.explanation = result.patch_artifact.get("summary") or patch_result.submission.get(
            "summary"
        )
        checkpoint_id, submission_state_captured = _capture_submission_state(
            execution_tree,
            result.patch_artifact or patch_result.submission,
        )
        submission_state_captured = submission_state_captured or bool(checkpoint_id)
        if checkpoint_id:
            result.best_checkpoint_id = checkpoint_id
    else:
        if llm_failure:
            if (
                str(backend_anomaly_from_failure.get("kind") or "").strip().lower()
                == "workspace_policy_violation"
            ):
                logger.warning(
                    "Rollout %s invalidated by workspace policy: repo=%s %s",
                    rollout_id,
                    repo_label,
                    llm_failure,
                )
            else:
                logger.warning(
                    "Rollout %s LLM path unavailable: repo=%s %s",
                    rollout_id,
                    repo_label,
                    llm_failure,
                )

        if not config.rollout.enable_heuristic_fallback:
            result.failure_reason = llm_failure or "Rollout heuristic fallback is disabled."
            logger.info(
                "Rollout %s skipping heuristic fallback because it is disabled in config.",
                rollout_id,
            )
        else:
            heuristic = HeuristicRepairAgent(working_dir=worktree_path)
            fallback = heuristic.run(
                issue_description=issue_description,
                issue_plan=issue_plan,
                rollout_brief=brief,
                test_command=test_command,
            )
            if fallback.success:
                patch_result = fallback
                result.patch_artifact = _serialize_patch_submission(fallback.submission)
                result.explanation = result.patch_artifact.get(
                    "summary"
                ) or fallback.submission.get("summary")
                result.failure_reason = llm_failure
                checkpoint_id, submission_state_captured = _capture_submission_state(
                    execution_tree,
                    result.patch_artifact or fallback.submission,
                )
                submission_state_captured = submission_state_captured or bool(checkpoint_id)
                if checkpoint_id:
                    result.best_checkpoint_id = checkpoint_id
            else:
                result.failure_reason = llm_failure or fallback.output

    cancelled_result = _cancelled_result_if_requested(
        phase="orchestration",
        default_reason="rollout cancelled before workspace diff collection",
    )
    if cancelled_result is not None:
        return cancelled_result

    if (
        execution_tree is not None
        and config.execution_tree.restore_best_state
        and submission_state_captured
    ):
        restored_checkpoint = execution_tree.restore_best_state()
        if restored_checkpoint:
            result.best_checkpoint_id = restored_checkpoint

    if execution_tree is not None:
        result.execution_tree = execution_tree.to_dict()
        if result.best_checkpoint_id is None:
            result.best_checkpoint_id = execution_tree.best_node_id()
    if result.trajectory:
        result.multi_agent_summary = _merge_multi_agent_usage(
            result.multi_agent_summary,
            _summarize_multi_agent_trajectory(result.trajectory),
        )

    manager = GitWorktreeManager(repo_context.repo_path, config.workspace_dir)
    changed_files = manager.list_changed_files(
        Path(worktree_path),
        baseline_ref=resolved_baseline,
    )
    diff = manager.get_diff(
        Path(worktree_path),
        baseline_ref=resolved_baseline,
    )

    result.changed_files = changed_files
    result.patch = diff
    result.success = bool(diff.strip()) and patch_result is not None and patch_result.success
    verifier_repair_changed_files = list(changed_files)
    verifier_repair_changed_lines: dict[str, list[int]] = {}
    if _brief_is_verifier_validity_repair(brief) and rollout_start_commit:
        try:
            verifier_repair_changed_files = manager.list_changed_files(
                Path(worktree_path),
                baseline_ref=rollout_start_commit,
            )
            verifier_repair_required_paths = _dedupe_strings(
                [
                    str(path)
                    for path in (
                        _brief_policy(brief).get("action_file_paths")
                        or getattr(brief, "focus_files", [])
                        or []
                    )
                    if str(path).strip()
                ]
            )
            verifier_repair_changed_lines = _git_changed_lines_by_file(
                worktree_path=worktree_path,
                baseline_ref=rollout_start_commit,
                include_paths=verifier_repair_required_paths,
            )
        except Exception as exc:  # noqa: BLE001 - keep main rollout accounting intact
            result.search_metadata["verifier_validity_repair_contract_error"] = str(exc)
    verifier_repair_contract = _verifier_validity_repair_contract_violation(
        brief,
        verifier_repair_changed_files,
        changed_lines_by_file=verifier_repair_changed_lines,
    )
    verifier_repair_contract_violation = bool(verifier_repair_contract.get("violation"))
    if _brief_is_verifier_validity_repair(brief):
        verifier_repair_contract["rollout_start_commit"] = rollout_start_commit
        verifier_repair_contract["selection_baseline_commit"] = resolved_baseline
        verifier_repair_contract["selection_changed_files"] = list(changed_files)
        result.search_metadata["verifier_validity_repair_contract"] = dict(verifier_repair_contract)
    if verifier_repair_contract_violation:
        result.success = False
        result.salvaged_for_external_scoring = False
        result.failure_reason = str(
            verifier_repair_contract.get("reason")
            or "Verifier validity repair did not produce a required source edit."
        )
    _evidence_mode = str(result.search_metadata.get("evidence_mode") or "").strip()
    protected_test_violation_paths: list[str] = []
    collection_critical_violation_paths: list[str] = []
    vendored_upstream_violation_paths: list[str] = []
    if isinstance(diff, str) and diff.strip():
        collection_critical_paths = _collection_critical_paths_for_worktree(Path(worktree_path))
        sanitized_patch = sanitize_patch_text(
            diff,
            evidence_mode=_evidence_mode,
            incomplete_test_files=incomplete_test_files_from_context(issue_plan.test_context),
            protected_test_files=protected_test_files_from_context(issue_plan.test_context),
            collection_critical_paths=collection_critical_paths,
        )
        protected_test_violation_paths = list(sanitized_patch.stripped_test_paths)
        collection_critical_violation_paths = list(
            sanitized_patch.stripped_collection_critical_paths
        )
        vendored_upstream_artifacts = list(sanitized_patch.manifest.vendored_upstream_artifacts)
        if sanitized_patch.patch_text != diff:
            result.patch = sanitized_patch.patch_text
            result.changed_files = list(sanitized_patch.manifest.solution_files)
            changed_files = list(result.changed_files)
            result.search_metadata["patch_sanitizer"] = {
                "stripped_test_paths": list(protected_test_violation_paths),
                "stripped_collection_critical_paths": list(collection_critical_violation_paths),
                "vendored_upstream_artifacts": vendored_upstream_artifacts,
                "manifest": sanitized_patch.manifest.to_dict(),
            }
            result.success = (
                bool(result.patch.strip()) and patch_result is not None and patch_result.success
            )
        # Part C: a stripped vendored-upstream tree means the agent fetched the
        # real implementation (download/copy) rather than writing it. The legit
        # ``src/`` diff has been requalified above (NOT a protected_test_violation),
        # but record an ADVISORY cheat signal so selection can deprioritize an
        # otherwise-equal download-tainted candidate. Never a hard rejection.
        if vendored_upstream_artifacts:
            cheat_signals = result.search_metadata.setdefault("cheat_signals", [])
            if isinstance(cheat_signals, list):
                cheat_signals.append(
                    {
                        "type": "vendored_upstream_source",
                        "action": "stripped_requalified",
                        "severity": "advisory",
                        "count": len(vendored_upstream_artifacts),
                        "sample": vendored_upstream_artifacts[:5],
                    }
                )
            if _evidence_mode == "gold_suite_visible":
                vendored_upstream_violation_paths = list(vendored_upstream_artifacts)
                result.success = False
                result.salvaged_for_external_scoring = False
                result.failure_reason = (
                    "Vendored upstream/source artifacts modified in gold_suite_visible mode: "
                    + ", ".join(vendored_upstream_violation_paths[:10])
                )
        if protected_test_violation_paths or collection_critical_violation_paths:
            result.success = False
            result.salvaged_for_external_scoring = False
            if protected_test_violation_paths:
                result.failure_reason = (
                    "Protected test files modified in gold_suite_visible mode: "
                    + ", ".join(protected_test_violation_paths[:10])
                )
            else:
                result.failure_reason = (
                    "Collection-critical files modified in gold_suite_visible mode: "
                    + ", ".join(collection_critical_violation_paths[:10])
                )
    prior_quick_verification = None
    if isinstance(result.patch_artifact, dict):
        seeded_quick_verification = result.patch_artifact.get("_apex_quick_verification")
        if isinstance(seeded_quick_verification, dict):
            prior_quick_verification = dict(seeded_quick_verification)
            # A2 wiring: record the seed's quick-verification as the comparison
            # baseline so milestone-deepening (acceptance.rollout_made_collection_
            # progress_vs_seed, read via solver._seed_quick_verification_for_result)
            # can tell whether THIS rollout improved collection/coverage over the
            # seed it branched from. Inert for fresh (un-seeded) rollouts, which
            # have no _apex_quick_verification on their patch_artifact.
            if isinstance(result.search_metadata, dict):
                result.search_metadata.setdefault(
                    "seed_quick_verification", dict(seeded_quick_verification)
                )
    if prior_quick_verification is None:
        trajectory_quick_verification = _latest_quick_verification_from_trajectory(
            result.trajectory
        )
        if trajectory_quick_verification:
            prior_quick_verification = trajectory_quick_verification
    if prior_quick_verification is not None:
        result.quick_verification = prior_quick_verification
    elif (
        config.rollout.enable_quick_verification
        and test_command
        and changed_files
        and not verifier_repair_contract_violation
        and not protected_test_violation_paths
        and not collection_critical_violation_paths
    ):
        cancelled_result = _cancelled_result_if_requested(
            phase="quick_verification",
            default_reason="rollout cancelled before final quick verification",
        )
        if cancelled_result is not None:
            return cancelled_result
        try:
            result.quick_verification = _run_rollout_quick_verification(
                repo_path=repo_context.repo_path,
                worktree_path=worktree_path,
                issue_plan=issue_plan,
                test_command=test_command,
                timeout_seconds=config.rollout.quick_verification_timeout_seconds,
                max_tests=config.rollout.quick_verification_max_tests,
                runtime_env_overrides=dict(
                    getattr(rollout_llm_config, "cli_env_overrides", {}) or {}
                ),
                status_output_dir=status_output_dir,
                rollout_id=rollout_id,
                candidate_test_paths=list(changed_files or []),
                # Use the EFFECTIVE brief resolved at the top of this rollout
                # (``brief = _select_rollout_brief(...)``), which carries the
                # decomposition module-group search_policy even when ``rollout_brief``
                # was selected from ``issue_plan.rollout_briefs``.
                module_group_expected_test_ids=_module_group_expected_test_ids_from_brief(brief),
                cancel_check=cancel_check,
                cancel_reason=cancel_reason,
                full_collection_when_expected_set_known=bool(
                    getattr(
                        config.rollout,
                        "quick_verification_full_collection_when_expected_set_known",
                        False,
                    )
                ),
                estimated_seconds_per_test=float(
                    getattr(
                        config.rollout,
                        "quick_verification_estimated_seconds_per_test",
                        0.5,
                    )
                    or 0.5
                ),
                sampled_suite_min=int(
                    getattr(config.rollout, "quick_verification_sampled_suite_min", 200) or 200
                ),
                sampled_suite_max=int(
                    getattr(config.rollout, "quick_verification_sampled_suite_max", 2000) or 2000
                ),
                verification_helper_files=list(config.selection.verification_helper_files),
            )
        except Exception as exc:
            logger.warning(
                "Quick verification failed for rollout %s: %s",
                rollout_id,
                exc,
            )
    cancelled_result = _cancelled_result_if_requested(
        phase="quick_verification",
        default_reason="rollout cancelled after final quick verification",
    )
    if cancelled_result is not None:
        return cancelled_result
    if isinstance(result.quick_verification, dict) and result.quick_verification:
        failure_frontier = failure_frontier_from_quick_verification(result.quick_verification)
        if failure_frontier:
            result.search_metadata["failure_frontier"] = failure_frontier
            if memory_bus is not None:
                memory_bus.broadcast(
                    rollout_id=rollout_id,
                    insight_type="FAILURE_FRONTIER",
                    description=str(failure_frontier.get("description") or ""),
                    confidence=float(failure_frontier.get("confidence") or 0.75),
                    stage_name="quick_verification",
                    provenance="verified",
                    evidence_mode=str(result.search_metadata.get("evidence_mode") or ""),
                    test_ids=list(failure_frontier.get("test_ids") or []),
                    payload=dict(failure_frontier.get("payload") or {}),
                )
    # Quick-verification blocker handling: we keep ``success=True`` for
    # high-pass-rate *behavioral* near-misses so the selector can weigh
    # those candidates, but an expected-coverage gap is different. A
    # rollout that passes locally while silently omitting benchmark-known
    # tests is not a trustworthy near-solution; it is an incomplete
    # validation result and should not be promoted as a successful patch.
    _NEAR_MISS_QV_PASS_RATE_FLOOR = 0.85
    _qv_demote = _quick_verification_success_demotion_decision(
        issue_plan,
        result.quick_verification,
        evidence_mode=_evidence_mode,
        pass_rate_floor=_NEAR_MISS_QV_PASS_RATE_FLOOR,
    )
    _qv_outcome = VerificationOutcome(str(_qv_demote.get("outcome") or "indeterminate"))
    if isinstance(result.quick_verification, dict):
        result.quick_verification["verification_outcome"] = _qv_outcome.value
    result.search_metadata["quick_verification_outcome"] = _qv_outcome.value
    _coverage_collapse_terminal = _evidence_mode == "gold_suite_visible" and bool(
        _qv_demote.get("terminal_coverage_gap")
    )
    result.validity = _candidate_validity_from_rollout(
        result,
        evidence_mode=_evidence_mode,
        coverage_collapse_terminal=_coverage_collapse_terminal,
        provenance_violation=bool(vendored_upstream_violation_paths),
    )
    if _coverage_collapse_terminal:
        result.salvaged_for_external_scoring = False
    if protected_test_violation_paths and result.validity is not None:
        result.validity.protected_tests_unchanged = False
        if "protected_test_violation" not in result.validity.reasons:
            result.validity.reasons.append("protected_test_violation")
    if collection_critical_violation_paths and result.validity is not None:
        result.validity.collection_critical_files_unchanged = False
        if "collection_critical_edit" not in result.validity.reasons:
            result.validity.reasons.append("collection_critical_edit")
    if vendored_upstream_violation_paths and result.validity is not None:
        result.validity.provenance_violation = True
        if "vendored_upstream_artifact" not in result.validity.reasons:
            result.validity.reasons.append("vendored_upstream_artifact")
    if bool(_qv_demote.get("incomplete_not_failure")):
        result.search_metadata["quick_verification_incomplete_reason"] = (
            "expected coverage gap; benchmark scorer must run full scoring"
        )
        result.search_metadata["requires_full_scoring"] = True
        if isinstance(result.quick_verification, dict):
            result.quick_verification["requires_full_scoring"] = True
    if result.success and bool(_qv_demote.get("demotes")):
        result.success = False
        if _coverage_collapse_terminal:
            result.salvaged_for_external_scoring = False
        blocker = _quick_verification_blocker_summary(result.quick_verification)
        quick_scope = str(result.quick_verification.get("scope") or "").strip()
        if not result.failure_reason:
            if bool(_qv_demote.get("terminal_coverage_gap")):
                missing_expected_test_count = result.quick_verification.get(
                    "missing_expected_test_count"
                )
                if isinstance(missing_expected_test_count, int) and missing_expected_test_count > 0:
                    result.failure_reason = (
                        "Broad quick verification passed locally but still missed "
                        f"{missing_expected_test_count} expected tests."
                    )
                else:
                    result.failure_reason = (
                        "Broad quick verification passed locally but did not preserve "
                        "expected test coverage."
                    )
            elif quick_scope == "structural_precheck":
                if blocker:
                    result.failure_reason = "Structural quick verification failed: " + blocker
                else:
                    result.failure_reason = "Structural quick verification failed before Apex restored importability or test collection."
            elif str(_qv_demote.get("rationale") or "") == "structural_precheck_failed":
                if blocker:
                    result.failure_reason = "Structural quick verification failed: " + blocker
                else:
                    result.failure_reason = (
                        "Structural quick verification failed before Apex restored "
                        "importability or test collection."
                    )
            elif bool(result.quick_verification.get("full_scope_timed_out")):
                if blocker:
                    result.failure_reason = (
                        "Broad quick verification timed out and fallback verification failed: "
                        + blocker
                    )
                else:
                    result.failure_reason = "Broad quick verification timed out and fallback verification remained inconclusive."
            elif blocker:
                result.failure_reason = "Broad quick verification failed: " + blocker
            else:
                result.failure_reason = "Broad quick verification timed out before Apex gathered sufficient validation evidence."

    backend_anomaly = {}
    if isinstance(result.patch_artifact, dict):
        patch_backend_anomaly = result.patch_artifact.get("_apex_backend_anomaly")
        if isinstance(patch_backend_anomaly, dict):
            backend_anomaly = dict(patch_backend_anomaly)
    if not backend_anomaly and backend_anomaly_from_failure:
        backend_anomaly = dict(backend_anomaly_from_failure)
    if backend_anomaly:
        result.search_metadata["backend_anomaly"] = dict(backend_anomaly)
        if (
            isinstance(result.patch_artifact, dict)
            and "_apex_backend_anomaly" not in result.patch_artifact
        ):
            result.patch_artifact["_apex_backend_anomaly"] = dict(backend_anomaly)
    if (
        not result.success
        and backend_anomaly
        and _should_salvage_backend_anomaly_rollout(result, backend_anomaly)
    ):
        if not isinstance(result.patch_artifact, dict) or not result.patch_artifact:
            result.patch_artifact = _build_backend_anomaly_patch_artifact(
                changed_files=changed_files,
                backend_anomaly=backend_anomaly,
            )
        elif "_apex_backend_anomaly" not in result.patch_artifact:
            result.patch_artifact["_apex_backend_anomaly"] = dict(backend_anomaly)
        result.search_metadata["backend_anomaly_recovered_candidate"] = True
        # Phase 2 10.K: stash a relaunch hint that the orchestrator's
        # followup-loop reroute reads to pick the right recovery axis.
        # ``workspace_policy_violation`` -> sandbox bypass relaunch.
        # ``cli_timeout``                 -> doubled-timeout relaunch.
        # ``cli_finalization_failure``    -> alternative-profile relaunch.
        relaunch_hint = _backend_anomaly_relaunch_hint(backend_anomaly)
        if relaunch_hint:
            result.search_metadata["backend_anomaly_relaunch_hint"] = relaunch_hint
        result.success = True
        if not result.explanation:
            result.explanation = str(result.patch_artifact.get("summary") or "").strip() or (
                "Recovered workspace patch after CLI backend anomaly."
            )
        if result.failure_reason and result.failure_reason == (
            llm_failure or "No valid patch was produced."
        ):
            result.failure_reason = None

    progress_score, progress_details = _compute_rollout_progress(result, issue_plan)
    result.progress_score = progress_score
    result.progress_details = progress_details
    result.duration_seconds = time.time() - start_time

    if not result.success and not result.failure_reason:
        result.failure_reason = "No valid patch was produced."

    # A1/A2: stamp a failure_class on every non-success rollout exit that has
    # not already been classified by an earlier path (cancel/timeout/QV
    # demotion). Without this, an environment-killed cohort (reaped container,
    # OCI exec failure, daemon loss, unauthenticated CLI) that reaches the main
    # finalization with success=False but failure_class=None falls through to
    # UNCLASSIFIED (charges_apex) and is scored as an APEX miss instead of being
    # split out of the denominator as an environment skip. ENV_RUNTIME is
    # honored downstream by solver._all_rollouts_env_failed via is_environment.
    _stamp_terminal_rollout_failure_class(result, backend_anomaly)

    logger.info(
        "Rollout %s finished: repo=%s duration=%.1fs success=%s changed_files=%s",
        rollout_id,
        repo_label,
        result.duration_seconds,
        result.success,
        len(result.changed_files),
    )
    final_rollout_clear_keys: list[str] = []
    if result.success:
        final_rollout_clear_keys = ["timeout_audit"]
    terminal_backend_failure_event = (
        dict(result.search_metadata.get("backend_failure_event") or {})
        if isinstance(result.search_metadata.get("backend_failure_event"), dict)
        else {}
    )
    terminal_stage_failure_event = (
        dict(result.search_metadata.get("stage_failure_event") or {})
        if isinstance(result.search_metadata.get("stage_failure_event"), dict)
        else {}
    )
    terminal_retry_diagnostics = _collect_cli_retry_diagnostics_from_trajectory(
        result.trajectory,
    )
    if terminal_retry_diagnostics:
        result.search_metadata["retry_diagnostics"] = list(terminal_retry_diagnostics)
        result.search_metadata["retry_count"] = len(terminal_retry_diagnostics)
    terminal_state_payload: dict[str, Any] = {
        "status": "completed" if result.success else "error",
        "stage": "rollout_finished",
        "stage_status": "completed",
        "model": result.llm_model,
        "state": "completed",
        "last_progress_at": time.time(),
        "last_progress_source": "stage_completed" if result.success else "stage_failure",
        "terminal_state": "completed" if result.success else None,
        "duration_seconds": result.duration_seconds,
        "success": result.success,
        "failure_reason": result.failure_reason,
        "changed_file_count": len(result.changed_files),
        "rollout_terminal": True,
        "_clear_keys": final_rollout_clear_keys,
    }
    if terminal_backend_failure_event:
        terminal_state_payload["backend_failure_event"] = terminal_backend_failure_event
    if terminal_stage_failure_event:
        terminal_state_payload["stage_failure_event"] = terminal_stage_failure_event
    if terminal_retry_diagnostics:
        terminal_state_payload["retry_diagnostics"] = list(terminal_retry_diagnostics)
        terminal_state_payload["retry_count"] = len(terminal_retry_diagnostics)
    _write_rollout_progress_state(
        status_output_dir,
        rollout_id,
        terminal_state_payload,
    )
    return result


def _stamp_terminal_rollout_failure_class(
    result: "RolloutResult",
    backend_anomaly: Optional[dict[str, Any]] = None,
) -> Optional["CoreClassificationResult"]:
    """A1/A2: classify a non-success rollout that reached terminal finalization
    without an earlier failure-class stamp.

    Returns the classification (also stamped onto ``result``) or ``None`` when
    the rollout succeeded or was already classified. Kept as a module-level
    helper so the routing decision (env-skip vs APEX-miss) is unit-testable
    without driving a full rollout. Evidence is drawn from the rollout's own
    ``failure_reason``, the backend-anomaly payload, and the quick-verification
    excerpt so an environment-killed exit (reaped container, OCI exec failure,
    unauthenticated CLI) routes to ENV_RUNTIME rather than UNCLASSIFIED.
    """
    if getattr(result, "success", False):
        return None
    if getattr(result, "failure_class", None) is not None:
        return None
    anomaly_text = ""
    if isinstance(backend_anomaly, dict) and backend_anomaly:
        anomaly_text = " ".join(
            str(value)
            for value in backend_anomaly.values()
            if isinstance(value, (str, int, float)) and str(value).strip()
        ).strip()
    qv_excerpt = ""
    quick_verification = getattr(result, "quick_verification", None)
    if isinstance(quick_verification, dict):
        qv_excerpt = str(
            quick_verification.get("stderr_excerpt")
            or quick_verification.get("blocker_summary")
            or quick_verification.get("summary")
            or ""
        ).strip()
    evidence = "\n".join(
        part
        for part in (str(getattr(result, "failure_reason", "") or ""), anomaly_text, qv_excerpt)
        if part
    )
    classification = classify_core_failure(
        stderr=evidence,
        stdout="",
        returncode=1,
        context={"phase": "rollout_finalization"},
    )
    result.failure_class = classification.failure_class
    result.failure_classification = classification
    return classification


def _quick_verification_total_count(payload: dict[str, Any]) -> int:
    for key in ("executed_test_count", "collected_test_count"):
        value = payload.get(key)
        if isinstance(value, int) and value > 0:
            return value
    passed = payload.get("passed")
    failed = payload.get("failed")
    errors = payload.get("errors")
    if all(isinstance(value, int) and value >= 0 for value in (passed, failed, errors)):
        return int(passed) + int(failed) + int(errors)
    return 0


def _quick_verification_payload_from_rollout_status(
    state: dict[str, Any],
) -> dict[str, Any]:
    compact = state.get("quick_verification")
    quick_verification = dict(compact) if isinstance(compact, dict) else {}

    def _as_int(value: Any) -> Optional[int]:
        try:
            return int(value)
        except (TypeError, ValueError):
            return None

    scope = str(quick_verification.get("scope") or state.get("verification_scope") or "").strip()
    if scope:
        quick_verification["scope"] = scope
    command = str(
        quick_verification.get("command") or state.get("verification_command") or ""
    ).strip()
    if command:
        quick_verification["command"] = command
    passed = _as_int(quick_verification.get("passed"))
    if passed is None:
        passed = _as_int(state.get("verification_passed"))
    failed = _as_int(quick_verification.get("failed"))
    if failed is None:
        failed = _as_int(state.get("verification_failed"))
    errors = _as_int(quick_verification.get("errors"))
    if errors is None:
        errors = _as_int(state.get("verification_errors"))
    if passed is None or failed is None or errors is None:
        return {}
    total = passed + failed + errors
    if total <= 0 or not scope:
        return {}
    quick_verification["passed"] = passed
    quick_verification["failed"] = failed
    quick_verification["errors"] = errors
    quick_verification["pass_rate"] = passed / total
    if "verification_returncode" in state and "returncode" not in quick_verification:
        quick_verification["returncode"] = state.get("verification_returncode")
    if "verification_timed_out" in state and "timed_out" not in quick_verification:
        quick_verification["timed_out"] = bool(state.get("verification_timed_out"))
    if (
        "verification_selected_test_count" in state
        and "selected_test_count" not in quick_verification
    ):
        selected_count = _as_int(state.get("verification_selected_test_count"))
        if selected_count is not None:
            quick_verification["selected_test_count"] = selected_count
    return quick_verification


def _quick_verification_payload_from_rollout_report(
    worktree_path: str,
) -> dict[str, Any]:
    worktree = Path(worktree_path)
    report_candidates = (
        worktree / ".apex_verification_reports" / "rollout_report.json",
        worktree / "rollout_report.json",
    )
    report_path: Optional[Path] = None
    report_payload: Optional[dict[str, Any]] = None
    for candidate_path in report_candidates:
        candidate_payload = load_pytest_json_report(candidate_path)
        if isinstance(candidate_payload, dict):
            report_path = candidate_path
            report_payload = candidate_payload
            break
    if report_path is None or not isinstance(report_payload, dict):
        return {}
    tests = extract_pytest_report_tests(report_payload)
    outcomes = extract_pytest_report_outcomes(tests)
    summary = report_payload.get("summary")
    summary = summary if isinstance(summary, dict) else {}

    def _summary_int(*keys: str) -> Optional[int]:
        for key in keys:
            value = summary.get(key)
            if isinstance(value, int):
                return max(0, value)
        return None

    passed = _summary_int("passed")
    failed = _summary_int("failed")
    errors = _summary_int("errors", "error")
    if passed is None:
        passed = sum(
            1 for outcome in outcomes.values() if outcome in {"passed", "xfailed", "xpassed"}
        )
    if failed is None:
        failed = sum(1 for outcome in outcomes.values() if outcome == "failed")
    if errors is None:
        errors = sum(1 for outcome in outcomes.values() if outcome == "error")
    total = int(passed) + int(failed) + int(errors)
    if total <= 0:
        return {}

    failed_tests = sorted(
        node_id for node_id, outcome in outcomes.items() if outcome in {"failed", "error"}
    )
    try:
        report_source = str(report_path.relative_to(worktree))
    except ValueError:
        report_source = str(report_path)
    payload: dict[str, Any] = {
        "scope": "full_test_command",
        "command": "pytest",
        "returncode": 0 if failed == 0 and errors == 0 else 1,
        "timed_out": False,
        "passed": int(passed),
        "failed": int(failed),
        "errors": int(errors),
        "pass_rate": int(passed) / total,
        "failed_tests": failed_tests,
        "report_source": report_source,
    }
    collected = _summary_int("collected")
    if collected is not None:
        payload["collected_test_count"] = collected
    elif outcomes:
        payload["collected_test_count"] = len(outcomes)
    executed = _summary_int("total")
    if executed is not None:
        payload["executed_test_count"] = executed
    signal_score = quick_verification_signal_score(payload)
    if signal_score is not None:
        payload["signal_score"] = max(0.0, min(float(signal_score), 1.0))
    return payload


def _quick_verification_from_status_is_stronger(
    existing: dict[str, Any],
    recovered: dict[str, Any],
) -> bool:
    if not recovered:
        return False
    if not existing:
        return True
    existing_scope = str(existing.get("scope") or "").strip()
    recovered_scope = str(recovered.get("scope") or "").strip()
    if recovered_scope == "full_test_command" and existing_scope != "full_test_command":
        return True
    if recovered_scope != "full_test_command" and existing_scope == "full_test_command":
        return False

    existing_timed_out = bool(existing.get("timed_out")) or bool(
        existing.get("full_scope_timed_out")
    )
    recovered_timed_out = bool(recovered.get("timed_out")) or bool(
        recovered.get("full_scope_timed_out")
    )
    if existing_timed_out and not recovered_timed_out:
        return True
    if recovered_timed_out and not existing_timed_out:
        return False

    existing_total = _quick_verification_total_count(existing)
    recovered_total = _quick_verification_total_count(recovered)
    if recovered_total > max(existing_total * 2, existing_total + 10):
        return True

    existing_coverage = quick_verification_expected_coverage_ratio(existing)
    recovered_coverage = quick_verification_expected_coverage_ratio(recovered)
    if isinstance(recovered_coverage, (int, float)) and (
        not isinstance(existing_coverage, (int, float))
        or float(recovered_coverage) > float(existing_coverage) + 0.001
    ):
        return True

    existing_score = quick_verification_signal_score(existing)
    recovered_score = quick_verification_signal_score(recovered)
    if isinstance(recovered_score, (int, float)) and (
        not isinstance(existing_score, (int, float))
        or float(recovered_score) > float(existing_score) + 0.001
    ):
        return True
    return False


def _merge_quick_verification_detail(
    existing: dict[str, Any],
    recovered: dict[str, Any],
) -> dict[str, Any]:
    if str(existing.get("scope") or "").strip() != str(recovered.get("scope") or "").strip():
        return recovered
    merged = dict(recovered)
    for key in (
        "selected_tests",
        "failed_tests",
        "failure_clusters",
        "missing_expected_test_ids",
        "output_excerpt",
        "failure_classification",
    ):
        if key not in merged and key in existing:
            merged[key] = existing[key]
    return merged


def _propagate_liveness_windows_to_llm_configs(config: Any) -> None:
    """Mirror rollout-level liveness windows onto each per-rollout LLMConfig.

    The CLI watchdog (``cli_backend.CLIModelClient``) only ever receives an
    ``LLMConfig``; the progress-based stall window (K2) and the
    in-flight-LLM-request (S7) ceiling live on ``RolloutConfig``. Copy them
    onto ``LLMConfig.cli_stall_window_seconds`` /
    ``LLMConfig.cli_max_inflight_request_seconds`` so the watchdog can resolve
    them. Fail-open: a missing / non-positive rollout value leaves the
    LLMConfig default in place (never shrinks a window).
    """
    rollout_cfg = getattr(config, "rollout", None)
    if rollout_cfg is None:
        return
    stall_window = getattr(rollout_cfg, "stall_window_seconds", None)
    max_inflight = getattr(rollout_cfg, "max_inflight_request_seconds", None)
    no_edit_window = getattr(rollout_cfg, "no_edit_progress_window_seconds", None)
    llm_configs = getattr(config, "llm_configs", None) or []
    for llm_config in llm_configs:
        if llm_config is None:
            continue
        try:
            if isinstance(stall_window, (int, float)) and stall_window > 0:
                llm_config.cli_stall_window_seconds = int(stall_window)
            if isinstance(max_inflight, (int, float)) and max_inflight > 0:
                llm_config.cli_max_inflight_request_seconds = int(max_inflight)
            # ``0`` is a valid value (disables the no-edit kill), so propagate any
            # non-negative int rather than gating on > 0.
            if isinstance(no_edit_window, (int, float)) and no_edit_window >= 0:
                llm_config.cli_no_edit_progress_window_seconds = int(no_edit_window)
        except Exception:  # noqa: BLE001 - never let propagation break init
            continue


class RolloutEngine:
    """Coordinate rollout workspace setup and concurrent execution."""

    def __init__(self, config: ApexConfig, repo_path: str, repo_context: RepoContext):
        self.config = config
        # Progress-based liveness (K2): the CLI watchdog only sees an
        # ``LLMConfig``, so propagate the rollout-level stall window and the
        # in-flight-LLM-request (S7) ceiling onto every per-rollout LLMConfig.
        # Fail-open: any malformed value leaves the LLMConfig default in place.
        _propagate_liveness_windows_to_llm_configs(config)
        # Progress-based liveness (K3): publish the per-test-run QV stall window
        # so ``_run_rollout_quick_verification`` binds it for the verifier's
        # ``run_shell_command`` poll loop (no verifier.py change required).
        global _ACTIVE_QV_STALL_WINDOW_SECONDS
        _ACTIVE_QV_STALL_WINDOW_SECONDS = _resolve_qv_stall_window_seconds(config)
        self.repo_path = repo_path
        self.repo_context = repo_context
        self.memory_bus = EpisodicMemoryBus()
        # Phase 2.1: scope branch names + lockfiles so concurrent engines
        # can't collide on the git branch namespace or the per-rollout
        # lockfile name. uuid4 short-form is sufficient — collisions are
        # ~1 in 4B.
        self._run_id = uuid.uuid4().hex[:8]
        # Decisive-Edge C.5: optional worktree pool. Constructed lazily in
        # ``execute_rollout_requests`` because the pool is per-(repo,
        # baseline) and the engine reuses one ``RolloutEngine`` across
        # tasks (``solve()`` calls) but mints a fresh pool per task to
        # respect the safety contract.
        self._worktree_pool: Optional[WorktreePool] = None
        # Map worktree-path -> PooledWorktree so the post-rollout cleanup
        # path can decide whether to release back to the pool or call
        # ``worktree_manager.remove_worktree`` (the legacy / fallback
        # path).
        self._pooled_by_path: dict[str, PooledWorktree] = {}
        self._quarantined_worktree_paths: set[str] = set()
        # Phase 2.5: per-engine scoped CLI process registry. Replaces the
        # legacy global ``terminate_registered_cli_processes`` so a deadline
        # expiry on one rollout no longer kills sibling rollouts.
        self._cli_registry = RolloutCLIRegistry()
        # Phase 2.1: by default each engine gets its own per-solve scratch
        # directory. Operators can opt back into a shared workspace_dir
        # for cross-solve caches via ``RolloutConfig.shared_workspace=True``;
        # the file lock continues to apply either way.
        rollout_cfg = getattr(config, "rollout", None)
        shared_workspace = bool(getattr(rollout_cfg, "shared_workspace", False))
        if shared_workspace:
            workspace_dir = config.workspace_dir
            self._owns_workspace_dir = False
        else:
            base = config.workspace_dir if config.workspace_dir else tempfile.gettempdir()
            base = _workspace_base_for_rollout_scratch(config, base)
            try:
                Path(base).mkdir(parents=True, exist_ok=True)
            except OSError:
                base = tempfile.gettempdir()
            workspace_dir = tempfile.mkdtemp(prefix="apex_solve_", dir=base)
            self._owns_workspace_dir = True
        self._workspace_dir = workspace_dir
        self.worktree_manager = GitWorktreeManager(
            repo_path=repo_path,
            workspace_dir=workspace_dir,
            use_git_worktrees=config.rollout.use_git_worktrees,
            run_scope=self._run_id,
            historyless_snapshots=bool(getattr(config.rollout, "historyless_snapshots", False)),
        )
        self._repo_memory_store: Optional[Any] = None
        self._repo_memory_summary: dict[str, Any] = {
            "enabled": False,
            "loaded": False,
            "prior_insight_count": 0,
        }
        repo_memory_config = getattr(config, "repo_memory", None)
        # APEX_DISABLE_REPO_MEMORY=1 forces the gate off regardless of the
        # config value. Used for the with/without-memory ablation that
        # reviewers ask for whenever a paper claims a persistent-memory
        # contribution. Recorded in the summary so the audit trail shows
        # the override was applied.
        from ..persistence import is_repo_memory_disabled_via_env

        repo_memory_disabled_by_env = is_repo_memory_disabled_via_env()
        if repo_memory_disabled_by_env:
            self._repo_memory_summary["disabled_via_env"] = True
            self._repo_memory_summary["env_var"] = "APEX_DISABLE_REPO_MEMORY"
        if (
            repo_memory_config is not None
            and bool(getattr(repo_memory_config, "enabled", False))
            and not repo_memory_disabled_by_env
        ):
            try:
                from ..persistence import RepoMemoryStore  # local import to avoid cycle in tests

                store = RepoMemoryStore(
                    repo_path=repo_path,
                    directory=getattr(repo_memory_config, "directory", None),
                    max_persisted_insights=int(
                        getattr(repo_memory_config, "max_persisted_insights", 64)
                    ),
                    decay_factor=float(getattr(repo_memory_config, "decay_factor", 0.85)),
                    min_confidence_to_persist=float(
                        getattr(repo_memory_config, "min_confidence_to_persist", 0.7)
                    ),
                    prefer_high_support_threshold=int(
                        getattr(repo_memory_config, "prefer_high_support_threshold", 2)
                    ),
                )
                self._repo_memory_store = store
                prior_insights = [insight.to_dict() for insight in store.load()]
                seeded = self.memory_bus.seed_priors(prior_insights)
                store_summary = store.summary()
                self._repo_memory_summary = {
                    "enabled": True,
                    "loaded": True,
                    "prior_insight_count": int(seeded),
                    "store_path": str(store.store_path),
                    "store_summary": store_summary,
                }
                if seeded:
                    logger.info(
                        "Repo memory: seeded %s prior insights from %s",
                        seeded,
                        store.store_path,
                    )
            except Exception as exc:  # noqa: BLE001 - persistent memory must never crash the solve
                logger.warning("Failed to initialise repo memory store: %s", exc)
                self._repo_memory_store = None
                self._repo_memory_summary = {
                    "enabled": True,
                    "loaded": False,
                    "prior_insight_count": 0,
                    "error": str(exc) or exc.__class__.__name__,
                }

    def repo_memory_summary(self) -> dict[str, Any]:
        """Return the current repo-memory load state for the result artifact."""

        return dict(self._repo_memory_summary)

    def _standalone_anchor_request_key(
        self,
        issue_description: str,
        issue_plan: IssuePlan,
    ) -> str:
        return "\0".join(
            [
                str(issue_description or "").strip(),
                str(getattr(issue_plan, "summary", "") or "").strip(),
                str(getattr(issue_plan, "planner_source", "") or "").strip(),
            ]
        )

    def _rollout_request_is_standalone_anchor(self, request: RolloutRequest) -> bool:
        metadata = dict(getattr(request, "metadata", {}) or {})
        if bool(metadata.get("standalone_agent_anchor")):
            return True
        return _brief_is_standalone_anchor(getattr(request, "rollout_brief", None))

    def _maybe_append_standalone_anchor_request(
        self,
        *,
        issue_description: str,
        rollout_requests: list[RolloutRequest],
    ) -> list[RolloutRequest]:
        if not bool(getattr(self.config.rollout, "enable_standalone_anchor", False)):
            return rollout_requests
        if not rollout_requests:
            return rollout_requests
        first_request = rollout_requests[0]
        if _should_seed_collection_error_scaffold(first_request.issue_plan):
            return rollout_requests
        key = self._standalone_anchor_request_key(
            issue_description,
            first_request.issue_plan,
        )
        injected_keys = getattr(self, "_standalone_anchor_request_keys", None)
        if not isinstance(injected_keys, set):
            injected_keys = set()
            self._standalone_anchor_request_keys = injected_keys
        if any(self._rollout_request_is_standalone_anchor(request) for request in rollout_requests):
            injected_keys.add(key)
            return rollout_requests
        if key in injected_keys:
            return rollout_requests

        anchor_id = max(int(request.rollout_id) for request in rollout_requests) + 1
        source_brief = _select_rollout_brief(
            first_request.issue_plan,
            first_request.rollout_id,
            brief=first_request.rollout_brief,
            config=self.config,
        )
        anchor_targets = list(_select_standalone_anchor_targets(self.config))
        source_profile_index = _rollout_brief_profile_index(source_brief)
        if source_profile_index is not None:
            source_llm_config_index: Optional[int] = _anchor_profile_to_llm_config_index(
                self.config,
                source_profile_index,
            )
        elif self.config.llm_configs:
            source_llm_config_index = int(first_request.rollout_id) % len(self.config.llm_configs)
        else:
            source_llm_config_index = None
        if source_llm_config_index is not None:
            indexed_targets = list(enumerate(anchor_targets))
            indexed_targets.sort(
                key=lambda item: (
                    int(item[1].get("llm_config_index") or 0) == source_llm_config_index,
                    item[0],
                )
            )
            anchor_targets = [target for _index, target in indexed_targets]

        anchor_requests: list[RolloutRequest] = []
        for offset, target in enumerate(anchor_targets):
            anchor_brief = _build_standalone_anchor_brief(
                config=self.config,
                issue_plan=first_request.issue_plan,
                source_brief=source_brief,
                target=target,
            )
            anchor_requests.append(
                RolloutRequest(
                    rollout_id=anchor_id + offset,
                    issue_plan=first_request.issue_plan,
                    rollout_brief=anchor_brief,
                    workspace_seed=None,
                    metadata={
                        "standalone_agent_anchor": True,
                        "standalone_anchor_label": str(target.get("label") or ""),
                        "standalone_anchor_profile_index": int(target.get("profile_index") or 0),
                        "standalone_anchor_llm_config_index": int(
                            target.get("llm_config_index") or 0
                        ),
                        "standalone_anchor_resolution": {
                            "source": str(target.get("source") or ""),
                            "candidate": dict(target.get("candidate") or {}),
                        },
                    },
                )
            )
        injected_keys.add(key)
        interleaved_requests: list[RolloutRequest] = []
        regular_requests = list(rollout_requests)
        max_len = max(len(anchor_requests), len(regular_requests))
        for index in range(max_len):
            if index < len(anchor_requests):
                interleaved_requests.append(anchor_requests[index])
            if index < len(regular_requests):
                interleaved_requests.append(regular_requests[index])
        return interleaved_requests

    def persist_repo_memory(
        self,
        accepted_rollout_ids: Optional[set[int]] = None,
    ) -> dict[str, Any]:
        """Extract durable insights and merge them into the persistent store.

        Always safe to call. When the store is disabled or unavailable
        this returns the existing summary unchanged. The orchestrator
        invokes this after a solve completes, regardless of success —
        even failed solves can produce reusable negative insights
        ("don't search this directory; everything imports lazily").
        """

        store = self._repo_memory_store
        if store is None:
            return self.repo_memory_summary()
        repo_memory_config = getattr(self.config, "repo_memory", None)
        max_items = int(getattr(repo_memory_config, "max_persisted_insights", 64))
        try:
            durable = self.memory_bus.extract_durable_insights(
                accepted_rollout_ids=accepted_rollout_ids,
                min_confidence=float(getattr(repo_memory_config, "min_confidence_to_persist", 0.7)),
                min_support_count=1,
                max_items=max_items,
            )
            persisted_payloads: list[Any] = []
            from ..persistence import PersistedInsight  # local import to avoid cycle

            for entry in durable:
                persisted_payloads.append(
                    PersistedInsight(
                        insight_type=str(entry.get("insight_type") or ""),
                        description=str(entry.get("description") or ""),
                        confidence=float(entry.get("confidence") or 0.0),
                        file_paths=list(entry.get("file_paths") or []),
                        symbols=list(entry.get("symbols") or []),
                        test_ids=list(entry.get("test_ids") or []),
                        stage_name=str(entry.get("stage_name") or ""),
                        negative=bool(entry.get("negative")),
                        support_count=int(entry.get("support_count") or 1),
                    )
                )
            persist_summary = store.merge_and_persist(persisted_payloads, solve_increment=1)
            self._repo_memory_summary = {
                "enabled": True,
                "loaded": True,
                "prior_insight_count": int(
                    self._repo_memory_summary.get("prior_insight_count") or 0
                ),
                "store_path": str(store.store_path),
                "persist_summary": persist_summary,
                "durable_insight_count": len(persisted_payloads),
            }
            logger.info(
                "Repo memory: persisted %s durable insights to %s",
                len(persisted_payloads),
                store.store_path,
            )
        except Exception as exc:  # noqa: BLE001 - persistent memory must never crash the solve
            logger.warning("Failed to persist repo memory: %s", exc)
            self._repo_memory_summary = {
                **self._repo_memory_summary,
                "persist_error": str(exc) or exc.__class__.__name__,
            }
        return self.repo_memory_summary()

    def execute_rollouts(
        self,
        issue_description: str,
        issue_plan: IssuePlan,
        test_command: Optional[str] = None,
        rollout_id_offset: int = 0,
        stop_on_result: Optional[Callable[[RolloutResult], bool]] = None,
        workspace_seed: Optional[WorkspaceSeed] = None,
        workspace_seeds: Optional[list[Optional[WorkspaceSeed]]] = None,
        wallclock_deadline: Optional[float] = None,
        advisory_seed_reproduction_artifact: Optional[Any] = None,
        advisory_seed_localization_artifact: Optional[Any] = None,
        advisory_seed_source_rollout_id: Optional[int] = None,
    ) -> list[RolloutResult]:
        num_rollouts = len(issue_plan.rollout_briefs) or self.config.rollout.num_rollouts
        # SPEED LEVER (cross-rollout discovery REUSE): carry the harvested
        # advisory warm-start seed on each request's free ``metadata`` field. The
        # dispatch reads it back, applies the giants size-gate, and forwards it
        # into ``_execute_single_rollout``. Default empty metadata keeps existing
        # callers byte-identical.
        advisory_seed_metadata: dict[str, Any] = {}
        if (
            advisory_seed_reproduction_artifact is not None
            or advisory_seed_localization_artifact is not None
        ):
            advisory_seed_metadata = {
                "advisory_seed_reproduction_artifact": advisory_seed_reproduction_artifact,
                "advisory_seed_localization_artifact": advisory_seed_localization_artifact,
                "advisory_seed_source_rollout_id": advisory_seed_source_rollout_id,
            }
        rollout_requests = [
            RolloutRequest(
                rollout_id=rollout_id_offset + index,
                issue_plan=issue_plan,
                rollout_brief=_select_rollout_brief(
                    issue_plan,
                    rollout_id_offset + index,
                    config=self.config,
                ),
                workspace_seed=_request_workspace_seed_for_index(
                    index,
                    workspace_seed=workspace_seed,
                    workspace_seeds=workspace_seeds,
                ),
                metadata=dict(advisory_seed_metadata),
            )
            for index in range(num_rollouts)
        ]
        request_kwargs: dict[str, Any] = {
            "issue_description": issue_description,
            "rollout_requests": rollout_requests,
            "test_command": test_command,
        }
        if stop_on_result is not None:
            request_kwargs["stop_on_result"] = stop_on_result
        if wallclock_deadline is not None:
            request_kwargs["wallclock_deadline"] = wallclock_deadline
        return self.execute_rollout_requests(
            **request_kwargs,
        )

    def _estimate_rollout_diversity_capacity(
        self,
        rollout_requests: list[RolloutRequest],
    ) -> tuple[Optional[int], int]:
        overlap_sensitive: list[tuple[set[str], set[str], tuple[str, ...]]] = []
        non_sensitive_count = 0

        for request in rollout_requests:
            brief = _select_rollout_brief(
                request.issue_plan,
                request.rollout_id,
                brief=request.rollout_brief,
                config=self.config,
            )
            if not _rollout_is_overlap_sensitive(request.issue_plan, brief):
                non_sensitive_count += 1
                continue
            source_focus, test_focus = _rollout_focus_signature(request.issue_plan, brief)
            if not source_focus and not test_focus:
                non_sensitive_count += 1
                continue
            profile_signature = _rollout_diversity_profile_signature(
                self.config,
                request.rollout_id,
                brief=brief,
            )
            overlap_sensitive.append((source_focus, test_focus, profile_signature))

        if len(overlap_sensitive) < 2:
            return None, len(overlap_sensitive)

        groups: list[list[tuple[set[str], set[str], tuple[str, ...]]]] = []
        for signature in overlap_sensitive:
            placed = False
            for group in groups:
                if any(
                    _focus_signatures_overlap(
                        self.config,
                        signature[0],
                        signature[1],
                        member[0],
                        member[1],
                    )
                    and signature[2] == member[2]
                    for member in group
                ):
                    group.append(signature)
                    placed = True
                    break
            if not placed:
                groups.append([signature])

        diversity_capacity = len(groups) + non_sensitive_count
        return max(1, diversity_capacity), len(overlap_sensitive)

    def _rollout_has_recent_deadline_progress(
        self,
        rollout_id: int,
        *,
        now: float,
        started_at: Optional[float] = None,
        parent_deadline_seconds: Optional[float] = None,
    ) -> bool:
        """Return True when the parent deadline should wait for active progress."""

        try:
            states = load_rollout_live_states(self.config.output_dir)
        except Exception as exc:  # noqa: BLE001 - deadline fallback stays conservative
            logger.debug(
                "Failed to inspect rollout status for parent-deadline progress: %s",
                exc,
            )
            return False

        def _as_int(value: Any) -> Optional[int]:
            try:
                return int(value)
            except (TypeError, ValueError):
                return None

        def _as_float(value: Any) -> Optional[float]:
            try:
                return float(value)
            except (TypeError, ValueError):
                return None

        state = next(
            (
                payload
                for payload in states
                if _as_int(payload.get("rollout_id")) == int(rollout_id)
            ),
            None,
        )
        if not isinstance(state, dict):
            return False
        status = str(state.get("status") or "").strip()
        terminal_state = str(state.get("terminal_state") or "").strip()
        if status in {"completed", "error"} or terminal_state:
            return False
        last_progress_at = _as_float(state.get("last_progress_at"))
        if last_progress_at is None or last_progress_at <= 0:
            return False
        grace_seconds = _as_float(state.get("hard_timeout_progress_grace_seconds"))
        if grace_seconds is None or grace_seconds <= 0:
            grace_seconds = 600.0
        stage = str(state.get("stage") or "").strip()
        if stage == "quick_verification":
            grace_seconds = max(grace_seconds, 900.0)
        if now - last_progress_at > grace_seconds:
            return False
        if (
            isinstance(started_at, (int, float))
            and started_at > 0
            and isinstance(parent_deadline_seconds, (int, float))
            and parent_deadline_seconds > 0
        ):
            parent_deadline_at = float(started_at) + float(parent_deadline_seconds)
            if now - parent_deadline_at > grace_seconds:
                return False
        return True

    def _rollout_is_stalled(
        self,
        rollout_id: int,
        *,
        now: float,
        stall_window: float,
    ) -> bool:
        """Return True iff a rollout is STALLED (K1, the sole scheduler kill).

        Progress-based liveness: a rollout is killed by the scheduler IFF it
        produced no meaningful progress for ``stall_window`` seconds — NOT on
        elapsed wall-clock. This is the inverted body of
        ``_rollout_has_recent_deadline_progress`` reduced to a pure stall test:

        - terminal (completed / error / terminal_state set) => NOT stalled;
        - no ``last_progress_at`` recorded yet => NOT stalled (fail open: the
          worker hasn't checked in, so wait rather than kill);
        - else stalled iff ``now - last_progress_at >= stall_window``.

        Fail-open everywhere: any live-state read error returns False (do not
        kill). A genuinely dead future (exception/done) is handled separately by
        the scheduler loop, not here.
        """
        if not isinstance(stall_window, (int, float)) or stall_window <= 0:
            return False
        try:
            states = load_rollout_live_states(self.config.output_dir)
        except Exception as exc:  # noqa: BLE001 - fail open (do not kill)
            logger.debug("Failed to inspect rollout status for stall check: %s", exc)
            return False

        def _as_int(value: Any) -> Optional[int]:
            try:
                return int(value)
            except (TypeError, ValueError):
                return None

        def _as_float(value: Any) -> Optional[float]:
            try:
                return float(value)
            except (TypeError, ValueError):
                return None

        state = next(
            (
                payload
                for payload in states
                if _as_int(payload.get("rollout_id")) == int(rollout_id)
            ),
            None,
        )
        if not isinstance(state, dict):
            # No live-state record yet => the worker hasn't reported progress;
            # fail open (do not kill on a missing record).
            return False
        status = str(state.get("status") or "").strip()
        terminal_state = str(state.get("terminal_state") or "").strip()
        if status in {"completed", "error"} or terminal_state:
            return False
        last_progress_at = _as_float(state.get("last_progress_at"))
        if last_progress_at is None or last_progress_at <= 0:
            # No progress timestamp recorded => fail open (do not kill).
            return False
        if (now - last_progress_at) < float(stall_window):
            return False
        # The stall window has elapsed by the live-state clock. Before reaping,
        # honour the S7 in-flight-request freeze that the INNER CLI watchdog
        # applies (cli_backend.py): while an agentic CLI subprocess has an
        # in-flight-request marker set and total silence is still under the S7
        # ceiling (``max_inflight_request_seconds``), a long "thinking" turn is
        # ALIVE, not a stall. Without this, the flat outer scheduler out-races the
        # inner watchdog and reaps a rollout the watchdog is deliberately freezing
        # (the observed pure-host-idle giant kills). Mirrors cli_backend's freeze
        # condition exactly. Fail open everywhere: any read error / missing marker
        # => ordinary stall governs (this can only ever DELAY a kill, bounded by
        # the same S7 ceiling, never fire one earlier).
        if not self._rollout_inflight_request_freeze_active(int(rollout_id), now=now):
            return True
        return False

    def _rollout_inflight_request_freeze_active(
        self,
        rollout_id: int,
        *,
        now: float,
    ) -> bool:
        """True iff the S7 in-flight-request freeze should hold this rollout ALIVE.

        Reads the per-rollout CLI registry's in-flight marker directly (option (b)
        from the fix spec — no JSON plumbing needed). Returns True only when a
        marker is set AND the silence since dispatch is still under the S7 ceiling
        (``max_inflight_request_seconds``), exactly mirroring the inner watchdog's
        freeze in cli_backend.py. Fail open: any error / no marker => False (the
        ordinary stall governs), so this can never cause an EARLIER kill.
        """
        registry = getattr(self, "_cli_registry", None)
        if registry is None:
            return False
        try:
            marker_started_at = registry.latest_inflight_request_started_at(rollout_id)
        except Exception:  # noqa: BLE001 - fail open (no freeze)
            return False
        if not isinstance(marker_started_at, (int, float)):
            return False
        try:
            max_inflight = float(
                getattr(self.config.rollout, "max_inflight_request_seconds", 0) or 0
            )
        except (TypeError, ValueError):
            max_inflight = 0.0
        if max_inflight <= 0:
            max_inflight = float(_DEFAULT_MAX_INFLIGHT_REQUEST_SECONDS)
        return (now - float(marker_started_at)) < max_inflight

    def _task_output_or_worktree_activity_at(
        self,
        rollout_ids: "set[int]",
    ) -> Optional[float]:
        """Max ``last_stdout_at`` / ``last_worktree_at`` across active rollouts.

        Used by the §4 emergency SILENCE cap. CPU timestamps are deliberately
        EXCLUDED so the cap only ever fires on true output+edit silence, never on
        a working agent. Fail-open: any read error returns None (the caller
        treats None as "activity unknown" and does NOT advance the silence
        clock toward a kill).
        """
        try:
            states = load_rollout_live_states(self.config.output_dir)
        except Exception as exc:  # noqa: BLE001 - fail open (do not kill)
            logger.debug("Failed to inspect rollout status for emergency cap: %s", exc)
            return None

        def _as_int(value: Any) -> Optional[int]:
            try:
                return int(value)
            except (TypeError, ValueError):
                return None

        def _as_float(value: Any) -> Optional[float]:
            try:
                return float(value)
            except (TypeError, ValueError):
                return None

        best: Optional[float] = None
        for payload in states:
            if not isinstance(payload, dict):
                continue
            rid = _as_int(payload.get("rollout_id"))
            if rid is None or rid not in rollout_ids:
                continue
            for key in ("last_stdout_at", "last_stderr_at", "last_worktree_at"):
                value = _as_float(payload.get(key))
                if value is not None and value > 0 and (best is None or value > best):
                    best = value
        return best

    def execute_rollout_requests(
        self,
        *,
        issue_description: str,
        rollout_requests: list[RolloutRequest],
        test_command: Optional[str] = None,
        stop_on_result: Optional[Callable[[RolloutResult], bool]] = None,
        wallclock_deadline: Optional[float] = None,
    ) -> list[RolloutResult]:
        if not rollout_requests:
            return []
        rollout_requests = self._maybe_append_standalone_anchor_request(
            issue_description=issue_description,
            rollout_requests=list(rollout_requests),
        )

        # Decisive-Edge C.5 — pre-warm the worktree pool when enabled.
        # The pool is per-task: we mint a fresh one in this call and
        # tear it down in the ``finally`` at the bottom so a sibling
        # task can construct its own without contention.
        self._maybe_init_worktree_pool(rollout_requests)

        results: list[RolloutResult] = []

        configured_parallel_workers = max(1, int(self.config.rollout.parallel_workers))
        requested_parallel_workers = max(1, min(configured_parallel_workers, len(rollout_requests)))
        max_workers = requested_parallel_workers
        diversity_capacity, overlap_sensitive_rollout_count = (
            self._estimate_rollout_diversity_capacity(rollout_requests)
        )
        diversity_limited = False
        diversity_cap_enabled = bool(self.config.rollout.enable_overlap_diversity_cap)
        diversity_floor_requested = max(
            1,
            int(self.config.rollout.min_overlap_diversity_parallel_workers),
        )
        diversity_floor_parallel_workers = max(
            1,
            min(requested_parallel_workers, diversity_floor_requested),
        )
        diversity_floor_applied = False
        if (
            diversity_cap_enabled
            and diversity_capacity is not None
            and diversity_capacity < max_workers
        ):
            effective_diversity_workers = max(
                max(1, diversity_capacity),
                diversity_floor_parallel_workers,
            )
            if effective_diversity_workers > diversity_capacity:
                logger.info(
                    "Relaxing overlap diversity cap from %s to %s due to configured outer rollout floor.",
                    diversity_capacity,
                    effective_diversity_workers,
                )
                diversity_floor_applied = True
            else:
                logger.info(
                    "Capping rollout workers from %s to %s to avoid duplicate overlapping frontier slices.",
                    max_workers,
                    effective_diversity_workers,
                )
            max_workers = effective_diversity_workers
            diversity_limited = True

        global_worker_budget = max(
            0,
            int(getattr(self.config.rollout, "global_parallel_worker_budget", 0) or 0),
        )
        configured_outer_task_parallelism = max(
            1,
            int(getattr(self.config.benchmark, "task_parallelism", 1) or 1),
        )
        (
            outer_task_parallelism,
            runtime_active_outer_task_count,
            runtime_waiting_outer_task_count,
            runtime_outer_task_parallelism_applied,
        ) = _runtime_outer_task_parallelism(configured_outer_task_parallelism)
        resource_cap_workers = requested_parallel_workers
        resource_limited = False
        if global_worker_budget > 0 and outer_task_parallelism > 1:
            resource_cap_workers = max(1, global_worker_budget // outer_task_parallelism)
            if max_workers > resource_cap_workers:
                logger.info(
                    "Capping rollout workers from %s to %s to respect global rollout worker budget %s across %s concurrent tasks.",
                    max_workers,
                    resource_cap_workers,
                    global_worker_budget,
                    outer_task_parallelism,
                )
                max_workers = resource_cap_workers
                resource_limited = True

        scheduler_metadata: dict[str, Any] = {
            "scheduler_configured_parallel_workers": configured_parallel_workers,
            "scheduler_requested_parallel_workers": requested_parallel_workers,
            "scheduler_effective_parallel_workers": max_workers,
            "scheduler_global_parallel_worker_budget": global_worker_budget,
            "scheduler_configured_outer_task_parallelism": configured_outer_task_parallelism,
            "scheduler_outer_task_parallelism": outer_task_parallelism,
            "scheduler_runtime_outer_task_parallelism_applied": (
                runtime_outer_task_parallelism_applied
            ),
            "scheduler_runtime_active_outer_task_count": runtime_active_outer_task_count,
            "scheduler_runtime_waiting_outer_task_count": runtime_waiting_outer_task_count,
            "scheduler_resource_cap_parallel_workers": resource_cap_workers,
            "scheduler_resource_limited": resource_limited,
            "scheduler_diversity_limited": diversity_limited,
            "scheduler_diversity_cap_enabled": diversity_cap_enabled,
            "scheduler_diversity_floor_requested": diversity_floor_requested,
            "scheduler_diversity_floor_parallel_workers": diversity_floor_parallel_workers,
            "scheduler_diversity_floor_applied": diversity_floor_applied,
            "scheduler_overlap_sensitive_rollout_count": overlap_sensitive_rollout_count,
        }
        if diversity_capacity is not None:
            scheduler_metadata["scheduler_diversity_capacity_estimate"] = int(diversity_capacity)
        scheduler_metadata["scheduler_overlap_diversity_include_prompt_strategy"] = bool(
            self.config.rollout.overlap_diversity_include_prompt_strategy
        )
        scheduler_metadata["scheduler_overlap_diversity_include_temperature"] = bool(
            self.config.rollout.overlap_diversity_include_temperature
        )

        # Map rollout_id -> worktree path so the worker post-processing can
        # safely tear down its worktree without needing the prepared tuple.
        worktree_path_by_rollout_id: dict[int, str] = {}

        # Worktrees referenced as live seeds by sibling/follow-up requests in
        # this same batch must NOT be torn down — the seed-handoff path clones
        # from them in `_create_seed_workspace`, but we still need to keep the
        # source path readable until every consumer is finished. We collect
        # those paths up front so the post-result cleanup can skip them.
        active_seed_worktree_paths: set[str] = set()
        for request in rollout_requests:
            seed = request.workspace_seed
            if seed is None:
                continue
            seed_repo_path = str(getattr(seed, "repo_path", "") or "").strip()
            if seed_repo_path:
                active_seed_worktree_paths.add(seed_repo_path)

        configured_timeout_contract_seconds = _rollout_requests_timeout_contract_seconds(
            self.config,
            rollout_requests,
        )
        # T1.4 — size-scale the per-rollout wall-clock budgets for huge suites.
        # ``size_factor`` is derived purely from the measured expected-test count
        # (max across this batch's requests) so it is 1 for small repos =>
        # byte-for-byte identical behavior. Scaling is EXTEND-ONLY: budgets only
        # ever grow, never shrink below their configured floors, and the outer
        # ``task_wallclock_budget_seconds`` (applied via ``wallclock_deadline``
        # below) remains a hard cap.
        max_expected_test_count = 0
        for _request in rollout_requests:
            max_expected_test_count = max(
                max_expected_test_count,
                _issue_plan_expected_test_count(getattr(_request, "issue_plan", None)),
            )
        rollout_budget_size_factor = _rollout_budget_size_factor(
            max_expected_test_count,
            tests_per_unit=int(
                getattr(self.config.rollout, "rollout_budget_tests_per_unit", 2000) or 2000
            ),
            max_size_factor=int(
                getattr(self.config.rollout, "rollout_budget_max_size_factor", 6) or 6
            ),
        )
        scheduler_metadata["rollout_budget_expected_test_count"] = max_expected_test_count
        scheduler_metadata["rollout_budget_size_factor"] = rollout_budget_size_factor
        # SPEED LEVER (cross-rollout discovery REUSE) giants size-gate: only
        # inject the harvested advisory seed when the suite is NOT a giant.
        # Giants (size_factor at the configured max) keep today's fully-
        # independent behavior — each rollout re-localizes/re-reproduces — which
        # is exactly where independent localization is most load-bearing. This
        # mirrors the giants-keep-full-behavior guard in
        # ``_size_aware_followup_round_cap``.
        _advisory_reuse_max_size_factor = max(
            2,
            int(getattr(self.config.rollout, "rollout_budget_max_size_factor", 6) or 6),
        )
        advisory_seed_reuse_allowed = (
            bool(getattr(self.config.rollout, "enable_cross_rollout_discovery_reuse", True))
            and rollout_budget_size_factor < _advisory_reuse_max_size_factor
        )
        scheduler_metadata["advisory_discovery_reuse_allowed"] = advisory_seed_reuse_allowed
        base_timeout = max(
            configured_timeout_contract_seconds,
            300.0,
        )
        # T1.4 REMOVED (progress-based liveness): the size-scale wall-clock
        # budget extension and the ``rollout_wallclock_budget_seconds`` clamps
        # are gone — wall-clock is no longer a kill (K1 uses the stall window;
        # K4 passes ``wallclock_deadline=None`` per-dispatch). The base value
        # below is retained ONLY as a metadata / log label
        # (``parent_executor_deadline_seconds``); it no longer gates any kill.
        # ``rollout_budget_size_factor`` survives upstream solely as a scheduling
        # hint, not a kill threshold.
        parent_rollout_deadline_seconds = max(
            base_timeout + 600.0,
            base_timeout * max(1, int(self.config.rollout.max_iterations_per_rollout or 1)),
        )
        if isinstance(wallclock_deadline, (int, float)) and wallclock_deadline > 0:
            # Advisory metadata only: the task-level wallclock deadline is no
            # longer enforced as a kill here (the §4 emergency SILENCE cap is the
            # sole absolute ceiling). Recorded for auditability.
            remaining_task_seconds = max(1.0, float(wallclock_deadline) - time.time())
            scheduler_metadata["task_wallclock_deadline"] = float(wallclock_deadline)
            scheduler_metadata["task_wallclock_remaining_seconds_at_dispatch"] = (
                remaining_task_seconds
            )
        scheduler_metadata["parent_executor_deadline_seconds"] = parent_rollout_deadline_seconds
        # Progress-based liveness (K1): the scheduler kills a rollout IFF it is
        # STALLED (no progress for ``scheduler_stall_window_seconds``) or its
        # future is genuinely dead — NEVER on elapsed wall-clock. The window is
        # the rollout-level ``stall_window_seconds`` (decoupled from the parent
        # deadline above, which is now only a metadata/log label). Fail open to
        # the generous module default if misconfigured.
        try:
            scheduler_stall_window_seconds = float(
                getattr(self.config.rollout, "stall_window_seconds", 0) or 0
            )
        except (TypeError, ValueError):
            scheduler_stall_window_seconds = 0.0
        if scheduler_stall_window_seconds <= 0:
            scheduler_stall_window_seconds = float(_DEFAULT_QV_STALL_WINDOW_SECONDS)
        base_scheduler_stall_window_seconds = scheduler_stall_window_seconds
        # Size-aware OUTER stall window + S7-ceiling alignment. The flat 1200s
        # outer window out-races the INNER CLI watchdog (whose no-edit governor +
        # S7 freeze understand in-flight requests and in-container CPU) for
        # legitimately-long giant suites. Scale the outer window by the SAME
        # expected_test_count size factor used everywhere else: size_factor == 1
        # (small repos) keeps the EXACT 1200s default (monotone no-op); larger
        # suites scale UP only. This widens no-progress tolerance, never caps
        # work, so final_pass_rate==1.0 stays reachable.
        _size_factor = max(1, int(rollout_budget_size_factor or 1))
        scheduler_stall_window_seconds = base_scheduler_stall_window_seconds * float(_size_factor)
        if _size_factor > 1:
            # GIANTS ONLY (size_factor > 1): also FLOOR the outer window above the
            # inner watchdog's stall window + the S7 ceiling + a margin, so the
            # inner liveness logic (no-edit governor + S7 freeze) acts FIRST and
            # the outer scheduler stays a coarse last resort. Small repos are
            # untouched by this floor (they keep the byte-identical 1200s window),
            # preserving the historical small-repo behavior. Complementary to the
            # Fix-2 S7-bypass closure (which applies to ALL repos): that alone
            # stops the outer reaper killing a frozen rollout; this prevents the
            # flat window out-racing the inner logic for legitimately-long giants.
            try:
                _s7_ceiling_seconds = float(
                    getattr(self.config.rollout, "max_inflight_request_seconds", 0) or 0
                )
            except (TypeError, ValueError):
                _s7_ceiling_seconds = 0.0
            if _s7_ceiling_seconds <= 0:
                _s7_ceiling_seconds = float(_DEFAULT_MAX_INFLIGHT_REQUEST_SECONDS)
            _inner_alignment_floor = (
                base_scheduler_stall_window_seconds + _s7_ceiling_seconds + 120.0
            )
            scheduler_stall_window_seconds = max(
                scheduler_stall_window_seconds, _inner_alignment_floor
            )
        scheduler_metadata["scheduler_stall_window_seconds"] = scheduler_stall_window_seconds
        scheduler_metadata["scheduler_stall_window_base_seconds"] = (
            base_scheduler_stall_window_seconds
        )
        scheduler_metadata["scheduler_stall_window_size_factor"] = _size_factor
        # §4 EMERGENCY SILENCE CAP (the SINGLE absolute ceiling, task-level).
        # Kill ALL active rollouts iff the WHOLE TASK has been silent — no new
        # stdout/stderr AND no worktree edits — for this many seconds. CPU is
        # EXPLICITLY IGNORED, so a silent CPU-spinning livelock is bounded while
        # a working agent that streams output / edits files is never touched.
        # Large default (24 h); ``0`` => unlimited. This is the only remaining
        # absolute cap; every other elapsed>=deadline kill was removed (K1–K4).
        try:
            emergency_silence_window_seconds = float(
                getattr(self.config.rollout, "emergency_silence_window_seconds", 0) or 0
            )
        except (TypeError, ValueError):
            emergency_silence_window_seconds = 0.0
        scheduler_metadata["emergency_silence_window_seconds"] = emergency_silence_window_seconds
        try:
            selection_ready_drain_grace_seconds = float(
                getattr(self.config.rollout, "selection_ready_drain_grace_seconds", 0) or 0
            )
        except (TypeError, ValueError):
            selection_ready_drain_grace_seconds = 0.0
        selection_ready_drain_grace_seconds = max(0.0, selection_ready_drain_grace_seconds)
        scheduler_metadata["selection_ready_drain_grace_seconds"] = (
            selection_ready_drain_grace_seconds
        )

        executor = _AbandonableThreadPoolExecutor(max_workers=max_workers)
        deferred_timeout_futures_by_rollout_id: dict[int, Any] = {}
        try:
            pending_requests = deque(rollout_requests)
            active_futures: dict[Any, RolloutRequest] = {}
            active_started_at: dict[Any, float] = {}
            stop_dispatch = False
            cancelled_rollout_reasons: dict[int, str] = {}
            cancelled_rollout_lock = threading.Lock()
            selection_ready_drain_started_at: Optional[float] = None
            selection_ready_drain_deadline: Optional[float] = None
            selection_ready_drain_rollout_id: Optional[int] = None

            cli_registry_for_workers = self._cli_registry

            def mark_rollout_cancelled(rollout_id: int, reason: str) -> None:
                with cancelled_rollout_lock:
                    cancelled_rollout_reasons[int(rollout_id)] = str(
                        reason or "rollout cancelled by scheduler"
                    )

            def is_rollout_cancelled(rollout_id: int) -> bool:
                with cancelled_rollout_lock:
                    return int(rollout_id) in cancelled_rollout_reasons

            def rollout_cancel_reason(rollout_id: int) -> str:
                with cancelled_rollout_lock:
                    return str(
                        cancelled_rollout_reasons.get(
                            int(rollout_id),
                            "rollout cancelled by scheduler",
                        )
                    )

            def _scoped_single_rollout(*, rollout_id: int, **kwargs: Any) -> RolloutResult:
                # Phase 2.5: bind the per-rollout CLI registry on the worker
                # thread so any CLIModelClient spawned inside the rollout
                # auto-registers under the right rollout id. The context
                # manager is a no-op for callers that don't construct any
                # CLI clients.
                # T1.4: also bind the size-scaling factor so every CLI agent
                # step's hard timeout is EXTENDED (never shrunk) for huge
                # suites. ``size_factor == 1`` for small repos => no change.
                with (
                    active_rollout_cli_context(
                        cli_registry_for_workers,
                        rollout_id,
                    ),
                    active_cli_hard_timeout_size_factor(
                        rollout_budget_size_factor,
                    ),
                ):
                    return _execute_single_rollout(rollout_id=rollout_id, **kwargs)

            def submit_available_requests() -> None:
                prepared_to_submit: list[tuple[RolloutRequest, str, str]] = []
                while (
                    not stop_dispatch
                    and pending_requests
                    and len(active_futures) + len(prepared_to_submit) < max_workers
                ):
                    request = pending_requests.popleft()
                    prepared = prepare_request_workspace(request)
                    if isinstance(prepared, RolloutResult):
                        results.append(prepared)
                        continue
                    prepared_to_submit.append(prepared)
                for request, worktree_path, baseline_commit in prepared_to_submit:
                    dispatch_started_at = time.time()
                    # K4 (progress-based liveness): pass ``wallclock_deadline=None``
                    # per-dispatch. Every downstream wall-clock preempt (stage
                    # preempt, rollout-start gate, testgen milestone breaks,
                    # delegated-subtask preempts) is already guarded on
                    # ``wallclock_deadline > 0``, so a None deadline structurally
                    # DISARMS all of them — liveness is enforced one layer down by
                    # the K2 CLI stall watchdog and one layer up by the K1
                    # scheduler stall check. The legacy
                    # ``parent_rollout_deadline_seconds`` and outer
                    # ``wallclock_deadline`` survive only as metadata/log labels.
                    rollout_wallclock_deadline = None
                    # SPEED LEVER (cross-rollout discovery REUSE): read the
                    # harvested advisory warm-start seed off the request metadata
                    # and forward it (coerced, fail-open) when the giants
                    # size-gate allows. Any coercion error simply drops the seed
                    # so the rollout derives its own discovery (today's behavior).
                    advisory_seed_repro_payload: Optional[ReproductionArtifact] = None
                    advisory_seed_loc_payload: Optional[LocalizationArtifact] = None
                    advisory_seed_source_id: Optional[int] = None
                    if advisory_seed_reuse_allowed and isinstance(request.metadata, dict):
                        try:
                            _raw_repro = request.metadata.get("advisory_seed_reproduction_artifact")
                            _raw_loc = request.metadata.get("advisory_seed_localization_artifact")
                            if _raw_repro is not None:
                                advisory_seed_repro_payload = coerce_reproduction_artifact(
                                    _raw_repro
                                )
                            if _raw_loc is not None:
                                advisory_seed_loc_payload = coerce_localization_artifact(_raw_loc)
                            _raw_source = request.metadata.get("advisory_seed_source_rollout_id")
                            if _raw_source is not None:
                                advisory_seed_source_id = int(_raw_source)
                        except Exception as advisory_dispatch_exc:  # noqa: BLE001 - fail-open
                            advisory_seed_repro_payload = None
                            advisory_seed_loc_payload = None
                            advisory_seed_source_id = None
                            logger.debug(
                                "Advisory discovery seed dispatch coercion failed "
                                "for rollout %s (%s); deriving discovery normally.",
                                request.rollout_id,
                                advisory_dispatch_exc,
                            )
                    future = executor.submit(
                        _scoped_single_rollout,
                        rollout_id=request.rollout_id,
                        config=self.config,
                        repo_context=self.repo_context,
                        issue_description=issue_description,
                        issue_plan=request.issue_plan,
                        rollout_brief=request.rollout_brief,
                        worktree_path=worktree_path,
                        test_command=test_command,
                        baseline_commit=baseline_commit,
                        memory_bus=self.memory_bus,
                        wallclock_deadline=rollout_wallclock_deadline,
                        cancel_check=(
                            lambda rollout_id=request.rollout_id: is_rollout_cancelled(rollout_id)
                        ),
                        cancel_reason=(
                            lambda rollout_id=request.rollout_id: rollout_cancel_reason(rollout_id)
                        ),
                        advisory_seed_reproduction_artifact=advisory_seed_repro_payload,
                        advisory_seed_localization_artifact=advisory_seed_loc_payload,
                        advisory_seed_source_rollout_id=advisory_seed_source_id,
                    )
                    active_futures[future] = request
                    active_started_at[future] = dispatch_started_at

            def workspace_setup_failure_result(
                request: RolloutRequest,
                exc: Exception,
            ) -> RolloutResult:
                # Phase 0/2 wire-up: classify the workspace-setup failure
                # so downstream selectors / metrics can distinguish a
                # lock-collision (concurrent solve fighting for the slot,
                # ConcurrentWorktreeError -> APEX_MISS by default but
                # callable specific) from a clone/network failure.
                workspace_setup_reason = f"Workspace setup failed: {exc}"
                workspace_phase = (
                    "clone" if "clone" in workspace_setup_reason.lower() else "pre_install"
                )
                workspace_classification = classify_core_failure(
                    stderr=workspace_setup_reason,
                    stdout="",
                    returncode=1,
                    context={"phase": workspace_phase},
                )
                return RolloutResult(
                    rollout_id=request.rollout_id,
                    success=False,
                    failure_reason=workspace_setup_reason,
                    failure_class=workspace_classification.failure_class,
                    failure_classification=workspace_classification,
                    search_metadata={**scheduler_metadata, **dict(request.metadata)},
                )

            def preempt_active_rollouts(
                *,
                preempting_rollout_id: int,
                reason: Optional[str] = None,
                extra_metadata: Optional[dict[str, Any]] = None,
                protect_seed_worktrees: bool = True,
            ) -> None:
                pending_requests.clear()
                active_items = list(active_futures.items())
                for future, request in active_items:
                    # Belt-and-suspenders giants-safety: never cancel a rollout
                    # whose worktree is a registered synthesis member /
                    # carry-forward seed source. Mirrors the skip guard in
                    # `_maybe_remove_completed_worktree` (~30022). This is a pure
                    # `continue` BEFORE the pop/cancel below — we must not pop the
                    # future, append a preempted RolloutResult, or terminate its
                    # children, or the skipped rollout would be lost. Fail-open:
                    # a missing worktree path proceeds to cancel as before.
                    skip_worktree_path = worktree_path_by_rollout_id.get(request.rollout_id)
                    if (
                        protect_seed_worktrees
                        and skip_worktree_path
                        and skip_worktree_path in active_seed_worktree_paths
                    ):
                        continue
                    active_futures.pop(future, None)
                    active_started_at.pop(future, None)
                    rollout_id = request.rollout_id
                    preempt_reason = str(
                        reason
                        or (
                            "rollout preempted after stop condition from rollout "
                            f"{preempting_rollout_id}"
                        )
                    )
                    mark_rollout_cancelled(rollout_id, preempt_reason)
                    future.cancel()
                    terminate_rollout_children(
                        rollout_id,
                        reason=(
                            f"preempted after stop condition from rollout {preempting_rollout_id}"
                        ),
                    )
                    preempt_classification = classify_core_failure(
                        stderr=preempt_reason,
                        stdout="",
                        returncode=130,
                        context={"phase": "orchestration", "preempted": True},
                    )
                    metadata = {
                        **scheduler_metadata,
                        **dict(request.metadata),
                        "preempted_by_stop_on_result": True,
                        "preempting_rollout_id": preempting_rollout_id,
                    }
                    if extra_metadata:
                        metadata.update(dict(extra_metadata))
                    results.append(
                        RolloutResult(
                            rollout_id=rollout_id,
                            success=False,
                            failure_reason=preempt_reason,
                            failure_class=preempt_classification.failure_class,
                            failure_classification=preempt_classification,
                            worktree_path=str(worktree_path_by_rollout_id.get(rollout_id) or "")
                            or None,
                            search_metadata=metadata,
                        )
                    )
                    deferred_timeout_futures_by_rollout_id[rollout_id] = future

            def begin_selection_ready_drain(preempting_rollout_id: int) -> None:
                nonlocal selection_ready_drain_started_at
                nonlocal selection_ready_drain_deadline
                nonlocal selection_ready_drain_rollout_id
                if selection_ready_drain_deadline is not None:
                    return
                selection_ready_drain_started_at = time.time()
                selection_ready_drain_deadline = (
                    selection_ready_drain_started_at + selection_ready_drain_grace_seconds
                )
                selection_ready_drain_rollout_id = int(preempting_rollout_id)

            def preempt_selection_ready_drain(now: float) -> None:
                nonlocal selection_ready_drain_deadline
                nonlocal selection_ready_drain_started_at
                nonlocal selection_ready_drain_rollout_id
                preempting_rollout_id = int(selection_ready_drain_rollout_id or -1)
                started_at = float(selection_ready_drain_started_at or now)
                elapsed = max(0.0, float(now) - started_at)
                preempt_active_rollouts(
                    preempting_rollout_id=preempting_rollout_id,
                    reason=(
                        "rollout preempted after selection-ready drain grace "
                        f"({selection_ready_drain_grace_seconds:.1f}s) from rollout "
                        f"{preempting_rollout_id}"
                    ),
                    extra_metadata={
                        "preempted_by_selection_ready_drain": True,
                        "selection_ready_drain_grace_elapsed": True,
                        "selection_ready_drain_elapsed_seconds": elapsed,
                        "selection_ready_drain_grace_seconds": (
                            selection_ready_drain_grace_seconds
                        ),
                    },
                    protect_seed_worktrees=False,
                )
                selection_ready_drain_deadline = None
                selection_ready_drain_started_at = None
                selection_ready_drain_rollout_id = None

            def terminate_rollout_children(
                rollout_id: int,
                *,
                reason: str,
            ) -> None:
                """Best-effort hard cancellation for abandoned rollout work."""

                process_task_id = self._cli_registry.process_task_id(rollout_id)

                def _terminate_cli(signum: signal.Signals, label: str) -> None:
                    try:
                        count = self._cli_registry.terminate_for_rollout(
                            rollout_id,
                            signum=signum,
                        )
                        if count:
                            logger.info(
                                "%s %s CLI process(es) for rollout %s (%s)",
                                label,
                                count,
                                rollout_id,
                                reason,
                            )
                    except Exception:
                        logger.exception(
                            "Failed to %s CLI children for rollout %s (%s)",
                            label.lower(),
                            rollout_id,
                            reason,
                        )

                def _terminate_target_runtime(signum: signal.Signals, label: str) -> None:
                    if not process_task_id:
                        return
                    try:
                        tracked = PROCESS_REGISTRY.kill(
                            process_task_id,
                            signum=signum,
                        )
                        if tracked:
                            logger.info(
                                "%s %s target-runtime process(es) for rollout %s (%s)",
                                label,
                                len(tracked),
                                rollout_id,
                                reason,
                            )
                    except Exception:
                        logger.exception(
                            "Failed to %s target-runtime children for rollout %s (%s)",
                            label.lower(),
                            rollout_id,
                            reason,
                        )

                _terminate_cli(signal.SIGTERM, "Terminated")
                _terminate_target_runtime(signal.SIGTERM, "Terminated")
                # Some agent and docker-exec children survive SIGTERM long
                # enough to keep writing rollout status after APEX has moved
                # on. Escalate immediately because these rollouts have already
                # been abandoned by the scheduler.
                _terminate_cli(signal.SIGKILL, "Killed")
                _terminate_target_runtime(signal.SIGKILL, "Killed")

            def prepare_request_workspace(
                request: RolloutRequest,
            ) -> tuple[RolloutRequest, str, str] | RolloutResult:
                expected_worktree_path = (
                    self.worktree_manager.workspace_dir / f"rollout_{request.rollout_id}"
                )
                try:
                    worktree_path, pooled_entry = self._acquire_worktree_for_request(
                        request,
                    )
                    if pooled_entry is not None:
                        self._pooled_by_path[str(worktree_path)] = pooled_entry
                    baseline_commit_value = (
                        request.workspace_seed.baseline_commit
                        if request.workspace_seed is not None
                        else self.worktree_manager.get_baseline_commit(worktree_path)
                        if pooled_entry is None
                        else (
                            self._worktree_pool.base_commit
                            if self._worktree_pool is not None
                            else _resolve_head_commit(Path(worktree_path)) or ""
                        )
                    )
                    baseline_commit = str(baseline_commit_value or "")
                    worktree_path_by_rollout_id[request.rollout_id] = str(worktree_path)
                    return request, str(worktree_path), baseline_commit
                except Exception as exc:
                    logger.error(
                        "Failed to create workspace for rollout %s: %s",
                        request.rollout_id,
                        exc,
                    )
                    if expected_worktree_path.exists():
                        self.worktree_manager.remove_worktree(expected_worktree_path)
                    return workspace_setup_failure_result(request, exc)

            submit_available_requests()

            # §4 emergency SILENCE cap: track the wall-clock at which the task
            # was last seen producing output / editing a worktree. Initialized to
            # loop start (dispatch counts as activity). Only ever ADVANCED when
            # newer output/worktree activity is observed; never reset by CPU.
            task_emergency_activity_at = time.time()
            task_emergency_max_observed = 0.0

            while active_futures:
                done_futures, _ = wait(
                    set(active_futures),
                    timeout=1.0,
                    return_when=FIRST_COMPLETED,
                )
                if not done_futures:
                    now = time.time()
                    # §4 EMERGENCY SILENCE CAP (the one absolute ceiling). Kill
                    # ALL active rollouts iff the whole task has emitted no new
                    # output AND made no worktree edits for the configured window
                    # (CPU explicitly ignored). A working agent that streams
                    # output / edits files keeps advancing the activity clock and
                    # is never touched; only a silent CPU-spinning livelock (or a
                    # truly wedged task) trips this.
                    if emergency_silence_window_seconds > 0 and active_futures:
                        active_rollout_ids = {req.rollout_id for req in active_futures.values()}
                        observed_activity_at = self._task_output_or_worktree_activity_at(
                            active_rollout_ids
                        )
                        if (
                            observed_activity_at is not None
                            and observed_activity_at > task_emergency_max_observed
                        ):
                            task_emergency_max_observed = observed_activity_at
                            task_emergency_activity_at = now
                        if (now - task_emergency_activity_at) >= emergency_silence_window_seconds:
                            for future in list(active_futures):
                                request = active_futures.pop(future)
                                active_started_at.pop(future, None)
                                rollout_id = request.rollout_id
                                emergency_failure_reason = (
                                    "task hit emergency silence cap (no output / "
                                    f"worktree edits for "
                                    f"{emergency_silence_window_seconds:.1f}s)"
                                )
                                mark_rollout_cancelled(rollout_id, emergency_failure_reason)
                                future.cancel()
                                terminate_rollout_children(
                                    rollout_id,
                                    reason=(
                                        "emergency silence cap "
                                        f"{emergency_silence_window_seconds:.1f}s"
                                    ),
                                )
                                emergency_classification = classify_core_failure(
                                    stderr=emergency_failure_reason,
                                    stdout="",
                                    returncode=124,
                                    context={"phase": "test_execution", "timed_out": True},
                                )
                                results.append(
                                    RolloutResult(
                                        rollout_id=rollout_id,
                                        success=False,
                                        failure_reason=emergency_failure_reason,
                                        failure_class=emergency_classification.failure_class,
                                        failure_classification=emergency_classification,
                                        worktree_path=str(
                                            worktree_path_by_rollout_id.get(rollout_id) or ""
                                        )
                                        or None,
                                        search_metadata={
                                            **scheduler_metadata,
                                            **dict(request.metadata),
                                            "terminal_state": "emergency_absolute_cap",
                                            "emergency_absolute_cap": True,
                                            "emergency_silence_window_seconds": (
                                                emergency_silence_window_seconds
                                            ),
                                        },
                                    )
                                )
                                deferred_timeout_futures_by_rollout_id[rollout_id] = future
                            continue
                    if (
                        selection_ready_drain_deadline is not None
                        and active_futures
                        and now >= selection_ready_drain_deadline
                    ):
                        preempt_selection_ready_drain(now)
                        continue
                    # K1: stall-only expiry. The wall-clock conjunct
                    # (``now - started_at >= parent_rollout_deadline_seconds``)
                    # and the secondary absolute clause inside the old helper are
                    # GONE — a rollout is expired here IFF it is provably stalled
                    # (no progress for the stall window). A genuinely dead future
                    # (exception/done) is reaped via the ``done_futures`` path
                    # below, not here.
                    expired = [
                        future
                        for future in active_started_at
                        if self._rollout_is_stalled(
                            active_futures[future].rollout_id,
                            now=now,
                            stall_window=scheduler_stall_window_seconds,
                        )
                    ]
                    for future in expired:
                        request = active_futures.pop(future)
                        active_started_at.pop(future, None)
                        rollout_id = request.rollout_id
                        deadline_failure_reason = (
                            "rollout stalled (no progress for "
                            f"{scheduler_stall_window_seconds:.1f}s) / disconnected"
                        )
                        mark_rollout_cancelled(rollout_id, deadline_failure_reason)
                        future.cancel()
                        # Scope stall cancellation to the expired rollout. Kill
                        # both the agent CLI and verifier/target-runtime
                        # subprocesses so abandoned workers cannot keep launching
                        # follow-up commands after the scheduler has moved on.
                        terminate_rollout_children(
                            rollout_id,
                            reason=(
                                f"stalled {scheduler_stall_window_seconds:.1f}s / disconnected"
                            ),
                        )
                        deadline_classification = classify_core_failure(
                            stderr=deadline_failure_reason,
                            stdout="",
                            returncode=124,
                            context={"phase": "test_execution", "timed_out": True},
                        )
                        # T1.3 — carry the partial workspace path on the bare
                        # deadline result so the post-loop recovery step can
                        # materialize whatever the killed rollout implemented and
                        # preserve it as a carry-forward seed (NOT a promoted
                        # success — promotion stays gated on full-pass/near-miss).
                        results.append(
                            RolloutResult(
                                rollout_id=rollout_id,
                                success=False,
                                failure_reason=deadline_failure_reason,
                                failure_class=deadline_classification.failure_class,
                                failure_classification=deadline_classification,
                                worktree_path=str(worktree_path_by_rollout_id.get(rollout_id) or "")
                                or None,
                                search_metadata={
                                    **scheduler_metadata,
                                    **dict(request.metadata),
                                    "parent_executor_deadline_seconds": (
                                        parent_rollout_deadline_seconds
                                    ),
                                },
                            )
                        )
                        # ``Future.cancel()`` cannot stop a Python thread
                        # that is already running. Defer workspace cleanup
                        # until executor shutdown has observed the worker
                        # quiesce; otherwise pool teardown can remove or move
                        # ``_pool/pool_<idx>`` while the worker still uses it.
                        deferred_timeout_futures_by_rollout_id[rollout_id] = future
                    if expired:
                        submit_available_requests()
                    continue
                for future in done_futures:
                    request = active_futures.pop(future)
                    active_started_at.pop(future, None)
                    rollout_id = request.rollout_id
                    try:
                        result = future.result()
                        result.search_metadata.update(scheduler_metadata)
                        result.search_metadata.update(dict(request.metadata))
                        if request.workspace_seed is not None:
                            source_rollout_id = request.workspace_seed.source_rollout_id
                            if (
                                isinstance(source_rollout_id, int)
                                and source_rollout_id not in result.source_rollout_ids
                            ):
                                result.source_rollout_ids.append(source_rollout_id)
                            seed_state_id = str(request.workspace_seed.state_id or "").strip()
                            seed_checkpoint_id = str(
                                request.workspace_seed.checkpoint_id or ""
                            ).strip()
                            if seed_state_id:
                                result.search_metadata["seed_state_id"] = seed_state_id
                            if seed_checkpoint_id:
                                result.search_metadata["seed_checkpoint_id"] = seed_checkpoint_id
                            if isinstance(source_rollout_id, int):
                                result.search_metadata["seed_source_rollout_id"] = source_rollout_id
                        results.append(result)
                        self._prepare_result_for_stop_evaluation(
                            result,
                            worktree_path_by_rollout_id=worktree_path_by_rollout_id,
                        )
                        should_stop = False
                        should_preempt = False
                        should_continue_dispatch = False
                        should_drain_active = False
                        if (
                            not stop_dispatch
                            and stop_on_result is not None
                            and stop_on_result(result)
                        ):
                            should_stop = True
                            should_preempt = bool(
                                getattr(stop_on_result, "preempt_active_rollouts", False)
                            )
                            should_continue_dispatch = bool(
                                getattr(
                                    stop_on_result,
                                    "continue_dispatch_after_nonpreemptive_stop",
                                    False,
                                )
                            )
                            should_drain_active = bool(
                                getattr(
                                    stop_on_result,
                                    "drain_active_rollouts_after_nonpreemptive_stop",
                                    False,
                                )
                            )
                            worktree_path = worktree_path_by_rollout_id.get(rollout_id)
                            if should_preempt and worktree_path:
                                active_seed_worktree_paths.add(worktree_path)
                        # Tear down the per-rollout worktree once it's appended
                        # so long-running batches (50-repo benchmarks * 24
                        # rollouts) don't fill /tmp with hundreds of GB.
                        # `cleanup_all` previously fired only at solve()
                        # teardown, far too late.
                        self._maybe_remove_completed_worktree(
                            rollout_id=rollout_id,
                            result=result,
                            worktree_path_by_rollout_id=worktree_path_by_rollout_id,
                            active_seed_worktree_paths=active_seed_worktree_paths,
                        )
                        if should_stop:
                            if should_preempt:
                                stop_dispatch = True
                                preempt_active_rollouts(preempting_rollout_id=rollout_id)
                                break
                            if should_drain_active or not should_continue_dispatch:
                                stop_dispatch = True
                                if should_drain_active and active_futures:
                                    begin_selection_ready_drain(rollout_id)
                                    if selection_ready_drain_grace_seconds <= 0:
                                        preempt_selection_ready_drain(time.time())
                                        break
                    except Exception as exc:  # pragma: no cover - defensive
                        logger.exception("Rollout %s raised an exception", rollout_id)
                        # Worker raised inside ``future.result()`` — usually
                        # a harness bug or an OOM the executor surfaced
                        # instead of the rollout itself. Run the classifier
                        # to disambiguate so we don't silently charge the
                        # APEX miss-rate for an env failure.
                        worker_failure_reason = str(exc)
                        _write_rollout_progress_state(
                            self.config.output_dir,
                            rollout_id,
                            {
                                "status": "error",
                                "stage": "rollout_finished",
                                "stage_status": "completed",
                                "state": "completed",
                                "last_progress_at": time.time(),
                                "last_progress_source": "worker_exception",
                                "terminal_state": "failed",
                                "success": False,
                                "failure_reason": worker_failure_reason,
                                "rollout_terminal": True,
                                "worktree_path": worktree_path_by_rollout_id.get(rollout_id),
                            },
                        )
                        worker_classification = classify_core_failure(
                            stderr=worker_failure_reason,
                            stdout="",
                            returncode=1,
                            context={"phase": "test_execution"},
                        )
                        results.append(
                            RolloutResult(
                                rollout_id=rollout_id,
                                success=False,
                                failure_reason=worker_failure_reason,
                                failure_class=worker_classification.failure_class,
                                failure_classification=worker_classification,
                                search_metadata={**scheduler_metadata, **dict(request.metadata)},
                            )
                        )
                        # Worker raised before producing a usable result; the
                        # worktree is unrecoverable so we always reclaim it
                        # (still gated on keep_worktrees).
                        self._maybe_remove_completed_worktree(
                            rollout_id=rollout_id,
                            result=None,
                            worktree_path_by_rollout_id=worktree_path_by_rollout_id,
                            active_seed_worktree_paths=active_seed_worktree_paths,
                        )
                submit_available_requests()
        finally:
            quiesced_timeout_rollout_ids: set[int] = set(deferred_timeout_futures_by_rollout_id)
            if deferred_timeout_futures_by_rollout_id:
                grace_seconds = _rollout_executor_shutdown_grace_seconds()
                _, still_running_futures = wait(
                    set(deferred_timeout_futures_by_rollout_id.values()),
                    timeout=grace_seconds,
                )
                still_running_rollout_ids = {
                    rollout_id
                    for rollout_id, future in deferred_timeout_futures_by_rollout_id.items()
                    if future in still_running_futures
                }
                quiesced_timeout_rollout_ids.difference_update(still_running_rollout_ids)
                if still_running_rollout_ids:
                    self._quarantine_unquiesced_timeout_worktrees(
                        rollout_ids=still_running_rollout_ids,
                        worktree_path_by_rollout_id=worktree_path_by_rollout_id,
                        grace_seconds=grace_seconds,
                        results=results,
                    )
            # Cancel not-yet-started work. Running Python threads cannot be
            # force-cancelled; any that missed the grace window above have
            # had their workspaces quarantined so teardown will not remove
            # files from underneath them.
            executor.shutdown(wait=False, cancel_futures=True)
            if quiesced_timeout_rollout_ids:
                self._recover_timeout_candidate_results_from_worktrees(
                    results=results,
                    worktree_path_by_rollout_id=worktree_path_by_rollout_id,
                )
                # T1.3 — must run BEFORE the cleanup loop below so a deadline
                # partial's patch is materialized first; that makes
                # ``_should_keep_worktree`` preserve the workspace instead of
                # resetting it, so the next wave can branch from the partial.
                self._preserve_deadline_partials_as_carry_forward_seeds(
                    results=results,
                    worktree_path_by_rollout_id=worktree_path_by_rollout_id,
                )
                result_by_rollout_id = {result.rollout_id: result for result in results}
                for rollout_id in sorted(quiesced_timeout_rollout_ids):
                    self._maybe_remove_completed_worktree(
                        rollout_id=rollout_id,
                        result=result_by_rollout_id.get(rollout_id),
                        worktree_path_by_rollout_id=worktree_path_by_rollout_id,
                        active_seed_worktree_paths=active_seed_worktree_paths,
                    )
            self._recover_late_candidate_results_from_rollout_status(
                results=results,
                worktree_path_by_rollout_id=worktree_path_by_rollout_id,
            )
            # T1.3 — also cover deadline partials whose worker was quarantined
            # (not in ``quiesced_timeout_rollout_ids``). Idempotent: skips any
            # result already promoted or already marked seed-eligible.
            self._preserve_deadline_partials_as_carry_forward_seeds(
                results=results,
                worktree_path_by_rollout_id=worktree_path_by_rollout_id,
            )
            # Decisive-Edge C.5 (post-pool-fix): when ``keep_worktrees``
            # is on (the benchmark / selection path), the consumer
            # expects each ``RolloutResult.worktree_path`` to remain
            # readable AFTER ``execute_rollout_requests`` returns —
            # ``_select_best_patch`` runs ``git`` against it, the
            # benchmark scorer runs pytest against it, etc. Pool
            # teardown destroys the underlying ``_pool/pool_<idx>``
            # directories, so we must *promote* each still-leased
            # pooled worktree to a stable ``rollout_<id>`` location
            # BEFORE the pool tears down, and update every matching
            # ``RolloutResult.worktree_path`` in-place. Promotion is
            # gated on ``keep_worktrees`` because the legacy /
            # disposable path tears worktrees down anyway and the copy
            # would just be busy-work.
            if self._worktree_pool is not None and self._pooled_by_path:
                self._promote_pooled_worktrees_for_results(
                    results=results,
                    worktree_path_by_rollout_id=worktree_path_by_rollout_id,
                )
            # Decisive-Edge C.5 — return any still-leased pool entries
            # before the pool is torn down. The post-rollout cleanup
            # path normally releases each entry as the rollout
            # completes, but a worker that raised during the run might
            # leave its lease dangling.
            if self._worktree_pool is not None:
                for path, pooled in list(self._pooled_by_path.items()):
                    try:
                        self._worktree_pool.release(pooled, reset=False)
                    except Exception:  # noqa: BLE001
                        logger.exception(
                            "Failed to release pooled worktree at %s during "
                            "execute_rollout_requests teardown",
                            path,
                        )
                self._pooled_by_path.clear()
                # Tear down the per-task pool. ``cleanup`` is idempotent
                # so a sibling task starting up in this engine doesn't
                # see any leftover state.
                try:
                    self._worktree_pool.cleanup()
                except Exception:  # noqa: BLE001
                    logger.exception("Failed to clean up WorktreePool after batch.")
                self._worktree_pool = None

        results.sort(key=lambda item: item.rollout_id)
        return results

    def _quarantine_unquiesced_timeout_worktrees(
        self,
        *,
        rollout_ids: set[int],
        worktree_path_by_rollout_id: dict[int, str],
        grace_seconds: float,
        results: list[RolloutResult],
    ) -> None:
        result_by_rollout_id = {result.rollout_id: result for result in results}
        for rollout_id in sorted(rollout_ids):
            worktree_path = str(worktree_path_by_rollout_id.get(rollout_id) or "")
            if not worktree_path:
                continue
            self._quarantined_worktree_paths.add(worktree_path)
            result = result_by_rollout_id.get(rollout_id)
            if result is not None:
                result.search_metadata["worker_quiescence_timeout"] = True
                result.search_metadata["worker_quiescence_grace_seconds"] = grace_seconds
                result.search_metadata["quarantined_worktree_path"] = worktree_path
                result.search_metadata["scheduler_cancelled"] = True
                result.search_metadata["scheduler_cancelled_phase"] = "executor_shutdown"
            pooled = self._pooled_by_path.pop(worktree_path, None)
            try:
                self._pooled_by_path.pop(str(Path(worktree_path).resolve()), None)
            except OSError:
                pass
            if pooled is not None and self._worktree_pool is not None:
                self._pooled_by_path.pop(str(pooled.path), None)
                try:
                    self._pooled_by_path.pop(str(pooled.path.resolve()), None)
                except OSError:
                    pass
                with self._worktree_pool._lock:  # noqa: SLF001 - quarantine pool slot
                    self._worktree_pool._entries.pop(pooled.pool_index, None)  # noqa: SLF001
            failure_reason = (
                "rollout worker did not quiesce within "
                f"{grace_seconds:.1f}s after scheduler cancellation; workspace quarantined"
            )
            _write_rollout_progress_state(
                self.config.output_dir,
                rollout_id,
                {
                    "status": "error",
                    "stage": "rollout_cancelled",
                    "stage_status": "cancelled",
                    "state": "completed",
                    "last_progress_at": time.time(),
                    "last_progress_source": "worker_quiescence_timeout",
                    "terminal_state": "cancelled",
                    "success": False,
                    "failure_reason": failure_reason,
                    "rollout_terminal": True,
                    "scheduler_cancelled": True,
                    "scheduler_cancelled_phase": "executor_shutdown",
                    "worker_quiescence_timeout": True,
                    "worker_quiescence_grace_seconds": grace_seconds,
                    "quarantined_worktree_path": worktree_path,
                    "_clear_keys": [
                        "quick_verification",
                        "verification_scope",
                        "verification_command",
                        "verification_passed",
                        "verification_failed",
                        "verification_errors",
                        "verification_returncode",
                        "verification_timed_out",
                        "verification_selected_test_count",
                    ],
                },
            )
            logger.warning(
                "Rollout %s worker did not quiesce within %.1fs after parent deadline; "
                "quarantining workspace %s and skipping teardown for that path.",
                rollout_id,
                grace_seconds,
                worktree_path,
            )

    def _recover_timeout_candidate_results_from_worktrees(
        self,
        *,
        results: list[RolloutResult],
        worktree_path_by_rollout_id: dict[int, str],
    ) -> None:
        """Recover verified timeout/stall worktrees before pool cleanup resets them."""

        for result in list(results):
            if result.success or result.patch:
                continue
            failure_reason = str(result.failure_reason or "").lower()
            if not any(
                marker in failure_reason
                for marker in (
                    "parent executor deadline",
                    "cli backend stalled",
                    "stalled",
                    "disconnected",
                    "emergency",
                    "missing_structured_output",
                )
            ):
                continue
            worktree_path = str(
                result.worktree_path or worktree_path_by_rollout_id.get(result.rollout_id) or ""
            ).strip()
            if not worktree_path or not Path(worktree_path).is_dir():
                continue
            quick_verification = _quick_verification_payload_from_rollout_report(
                worktree_path,
            )
            if not quick_verification:
                continue
            existing_quick = (
                dict(result.quick_verification)
                if isinstance(result.quick_verification, dict)
                else {}
            )
            result.quick_verification = _merge_quick_verification_detail(
                existing_quick,
                quick_verification,
            )
            result.worktree_path = worktree_path
            if not result.baseline_commit:
                try:
                    result.baseline_commit = self.worktree_manager.get_baseline_commit(
                        Path(worktree_path),
                    )
                except Exception:
                    result.baseline_commit = (
                        self._worktree_pool.base_commit
                        if self._worktree_pool is not None
                        else _resolve_head_commit(Path(worktree_path))
                    )
            patch_text = self._materialize_candidate_patch_text(result)
            if not patch_text.strip() and not list(result.changed_files or []):
                continue
            if not (
                quick_verification_has_local_full_scope_pass(result.quick_verification)
                or rollout_has_repairable_near_miss(result)
            ):
                continue
            result.success = True
            result.failure_reason = None
            result.search_metadata["timeout_candidate_recovered_from_worktree"] = True
            result.search_metadata["timeout_candidate_recovery_source"] = str(
                quick_verification.get("report_source") or "rollout_report.json"
            )
            worktree_path_by_rollout_id[result.rollout_id] = worktree_path
            self._persist_promoted_candidate_artifacts(result)

    def _preserve_deadline_partials_as_carry_forward_seeds(
        self,
        *,
        results: list[RolloutResult],
        worktree_path_by_rollout_id: dict[int, str],
    ) -> None:
        """T1.3 — keep deadline-killed partials as carry-forward seeds.

        A rollout killed by the parent-executor deadline / scheduler (the common
        outcome on huge-library reimplementations where a single agent session
        can't finish in one budget) leaves a partially-implemented workspace.
        Today that work is discarded: the bare result has no patch, so the
        worktree is reset and the next wave restarts from baseline.

        This materializes whatever the killed rollout implemented and flags it
        ``carry_forward_seed_eligible`` so:
          * ``_should_keep_worktree`` preserves the workspace (the materialized
            ``result.patch`` makes ``_has_candidate_handoff_signal`` True), and
          * ``build_workspace_seed_from_rollout_result`` (already a no-edit
            consumer in the search/followup planners) can branch a follow-up
            rollout from the partial via ``rollout_has_materialized_repair_seed``.

        Crucially it does NOT set ``success`` and does NOT promote the result:
        candidate promotion stays gated on full-pass/near-miss elsewhere, and the
        full-suite official audit remains the sole scoring arbiter. So a partial
        union can never be falsely accepted — it only seeds the next attempt.
        """

        for result in list(results):
            # Already a promoted candidate, or already preserved — skip.
            if result.success or result.patch:
                continue
            if result.search_metadata.get("carry_forward_seed_eligible"):
                continue
            failure_reason = str(result.failure_reason or "").lower()
            if not any(
                marker in failure_reason
                for marker in (
                    # Legacy + progress-based-liveness labels. The scheduler now
                    # emits "rollout stalled (no progress ...) / disconnected"
                    # and the §4 emergency cap emits an "emergency"/silence
                    # label; both are carry-forward eligible (KEEP T1.3).
                    "parent executor deadline",
                    "cli backend stalled",
                    "stalled",
                    "disconnected",
                    "emergency",
                    "scheduler",
                    "cancelled",
                )
            ):
                continue
            worktree_path = str(
                result.worktree_path or worktree_path_by_rollout_id.get(result.rollout_id) or ""
            ).strip()
            if not worktree_path or not Path(worktree_path).is_dir():
                continue
            result.worktree_path = worktree_path
            if not result.baseline_commit:
                try:
                    result.baseline_commit = self.worktree_manager.get_baseline_commit(
                        Path(worktree_path),
                    )
                except Exception:  # noqa: BLE001 - seed recovery must not mask the result
                    result.baseline_commit = (
                        self._worktree_pool.base_commit
                        if self._worktree_pool is not None
                        else _resolve_head_commit(Path(worktree_path))
                    )
            patch_text = self._materialize_candidate_patch_text(result)
            if not patch_text.strip() and not list(result.changed_files or []):
                # Nothing was implemented — no seed to carry forward.
                continue
            # Seed-eligible WITHOUT success: promotion stays gated elsewhere.
            result.search_metadata["carry_forward_seed_eligible"] = True
            result.search_metadata["carry_forward_seed_source"] = "deadline_partial"
            worktree_path_by_rollout_id[result.rollout_id] = worktree_path

    def _recover_late_candidate_results_from_rollout_status(
        self,
        *,
        results: list[RolloutResult],
        worktree_path_by_rollout_id: dict[int, str],
    ) -> None:
        """Recover terminal candidate evidence written after the future was lost."""

        try:
            rollout_states = load_rollout_live_states(self.config.output_dir)
        except Exception as exc:  # noqa: BLE001 - recovery must not mask rollout results
            logger.debug(
                "Failed to inspect rollout status for late candidate recovery: %s",
                exc,
            )
            return

        def _as_int(value: Any) -> Optional[int]:
            try:
                return int(value)
            except (TypeError, ValueError):
                return None

        result_by_rollout_id: dict[int, RolloutResult] = {}
        for result in results:
            rollout_id = _as_int(result.rollout_id)
            if rollout_id is not None:
                result_by_rollout_id[rollout_id] = result
        for state in rollout_states:
            if not isinstance(state, dict):
                continue
            rollout_id = _as_int(state.get("rollout_id"))
            if rollout_id is None:
                continue
            status = str(state.get("status") or "").strip()
            stage = str(state.get("stage") or "").strip()
            terminal_state = str(state.get("terminal_state") or "").strip()
            # A4: an escrowed authoritative full-scope pass must still be
            # recovered even if it carries a cancel marker — escrow deliberately
            # preserves the win through a finalize-time cancel.
            escrowed_full_scope = bool(state.get("full_scope_pass_escrowed_through_cancel"))
            if not escrowed_full_scope and (
                bool(state.get("scheduler_cancelled")) or terminal_state == "cancelled"
            ):
                continue
            if status != "completed" and stage != "rollout_finished" and not terminal_state:
                continue

            quick_verification = _quick_verification_payload_from_rollout_status(state)
            if not quick_verification:
                continue

            worktree_path = str(
                state.get("working_dir")
                or state.get("worktree_path")
                or worktree_path_by_rollout_id.get(rollout_id)
                or ""
            ).strip()
            if not worktree_path or not Path(worktree_path).is_dir():
                continue

            result = result_by_rollout_id.get(rollout_id)
            recovered_result = False
            if result is None:
                result = RolloutResult(
                    rollout_id=rollout_id,
                    success=True,
                    worktree_path=worktree_path,
                    quick_verification=quick_verification,
                    llm_model=str(state.get("model") or ""),
                    agent_mode=str(state.get("agent_mode") or ""),
                )
                result.rollout_profile_index = _as_int(state.get("profile_index"))
                results.append(result)
                result_by_rollout_id[rollout_id] = result
                recovered_result = True
            else:
                existing_quick_verification = (
                    dict(result.quick_verification)
                    if isinstance(result.quick_verification, dict)
                    else {}
                )
                if not existing_quick_verification or _quick_verification_from_status_is_stronger(
                    existing_quick_verification,
                    quick_verification,
                ):
                    result.quick_verification = _merge_quick_verification_detail(
                        existing_quick_verification,
                        quick_verification,
                    )
                if not result.worktree_path:
                    result.worktree_path = worktree_path
                if result.rollout_profile_index is None:
                    result.rollout_profile_index = _as_int(state.get("profile_index"))
                if not result.agent_mode:
                    result.agent_mode = str(state.get("agent_mode") or "")
                if not result.llm_model:
                    result.llm_model = str(state.get("model") or "")

            if not result.baseline_commit:
                try:
                    result.baseline_commit = self.worktree_manager.get_baseline_commit(
                        Path(worktree_path),
                    )
                except Exception:
                    result.baseline_commit = (
                        self._worktree_pool.base_commit
                        if self._worktree_pool is not None
                        else _resolve_head_commit(Path(worktree_path))
                    )
            patch_text = self._materialize_candidate_patch_text(result)
            if not patch_text.strip() and not list(result.changed_files or []):
                continue
            is_full_pass = quick_verification_has_local_full_scope_pass(
                result.quick_verification,
            )
            is_near_miss = rollout_has_repairable_near_miss(result)
            if not is_full_pass and not is_near_miss:
                continue

            result.success = True
            result.failure_reason = None
            result.search_metadata["late_candidate_recovered_from_rollout_status"] = True
            result.search_metadata["late_candidate_recovered_result"] = recovered_result
            worktree_path_by_rollout_id[rollout_id] = worktree_path
            self._persist_promoted_candidate_artifacts(result)

    def _prepare_result_for_stop_evaluation(
        self,
        result: RolloutResult,
        *,
        worktree_path_by_rollout_id: dict[int, str],
    ) -> None:
        """Populate durable candidate signals before scheduler stop predicates."""

        self._recover_quick_verification_from_rollout_status(result)
        if not result.worktree_path:
            result.worktree_path = worktree_path_by_rollout_id.get(result.rollout_id)
        raw_worktree_path = str(result.worktree_path or "").strip()
        if not raw_worktree_path:
            return
        worktree_path = Path(raw_worktree_path)
        if not worktree_path.is_dir():
            return
        if not result.baseline_commit:
            try:
                result.baseline_commit = self.worktree_manager.get_baseline_commit(worktree_path)
            except Exception:
                result.baseline_commit = (
                    self._worktree_pool.base_commit
                    if self._worktree_pool is not None
                    else _resolve_head_commit(worktree_path)
                )
        quick_verification = (
            result.quick_verification if isinstance(result.quick_verification, dict) else {}
        )
        requires_authoritative_scoring = quick_verification_requires_authoritative_scoring(
            quick_verification,
            metadata=result.search_metadata if isinstance(result.search_metadata, dict) else {},
        )
        if (
            str(quick_verification.get("scope") or "").strip() == "full_test_command"
            or requires_authoritative_scoring
        ):
            self._materialize_candidate_patch_text(result)
            self._ensure_candidate_validity_for_handoff(result)
        self._promote_verified_scheduler_candidate(result)

    def _promote_pooled_worktrees_for_results(
        self,
        *,
        results: list[RolloutResult],
        worktree_path_by_rollout_id: dict[int, str],
    ) -> None:
        """Move each still-leased pooled worktree to a stable location.

        Decisive-Edge C.5 cleanup-race fix. While
        ``execute_rollout_requests`` is running, every rollout's
        ``worktree_path`` may point inside the per-task pool dir
        (``_pool/pool_<idx>``). When the function returns the pool is
        torn down — but the orchestrator's ``_select_best_patch`` and
        the benchmark's ``_run_task`` post-scorer still need to read
        those worktrees (``git diff``, ``pytest``, ``git add -N .``
        all crash with ``FileNotFoundError`` if the worktree has been
        physically removed).

        Resolution: BEFORE pool teardown we **move** each leased pool
        entry to ``workspace_dir/rollout_<id>`` (same layout the
        legacy ``GitWorktreeManager`` produces) and rewrite the
        matching ``RolloutResult.worktree_path`` in-place. The move
        uses ``git worktree move`` so the worktree's admin metadata
        stays consistent (otherwise ``.git`` files end up pointing at
        a stale ``.git/worktrees/pool_<idx>`` admin dir that the
        subsequent ``git worktree prune`` would invalidate, breaking
        every later ``git`` invocation).

        Falls back to a raw ``shutil.move`` + ``.git`` rewrite when
        ``git worktree move`` fails (some git versions choke on
        cross-filesystem moves). Promoted entries are removed from
        ``_pooled_by_path`` and ``WorktreePool._entries`` so the
        downstream pool teardown leaves them alone.

        Only runs when ``keep_worktrees`` is set — the disposable /
        legacy path tears worktrees down post-batch anyway, so the
        move would be wasted work.

        Cleanup failures must NOT propagate: a partial-promotion is
        better than the entire batch crashing in the ``finally`` block
        and masking the actual rollout outcomes.
        """
        if not bool(getattr(self.config.rollout, "keep_worktrees", False)):
            return
        if not self._pooled_by_path:
            return
        result_by_rollout_id = {result.rollout_id: result for result in results}
        path_to_rollout_id: dict[str, int] = {}

        def _record_path_alias(path_value: Optional[str], rollout_id: int) -> None:
            if not path_value:
                return
            path_to_rollout_id[path_value] = rollout_id
            try:
                resolved = str(Path(path_value).resolve())
                if resolved != path_value:
                    path_to_rollout_id[resolved] = rollout_id
            except OSError:
                pass

        for rollout_id, path_value in worktree_path_by_rollout_id.items():
            _record_path_alias(path_value, rollout_id)
        for result in results:
            _record_path_alias(result.worktree_path, result.rollout_id)

        def _pooled_rollout_id(
            pool_path_str: str,
            pooled: PooledWorktree,
        ) -> Optional[int]:
            raw_rollout_id = str(pooled.rollout_id or "").strip()
            if raw_rollout_id:
                try:
                    return int(raw_rollout_id)
                except ValueError:
                    pass
            rollout_id = path_to_rollout_id.get(pool_path_str)
            if rollout_id is not None:
                return rollout_id
            try:
                resolved = str(Path(pool_path_str).resolve())
            except OSError:
                return None
            return path_to_rollout_id.get(resolved)

        promoted_pool_entries: list[tuple[str, PooledWorktree]] = []

        def _promote(rollout_id: int, pooled: PooledWorktree) -> Optional[Path]:
            """Move the pool entry into ``workspace_dir/rollout_<id>``.

            Returns the destination path on success, ``None`` on any
            cleanup failure (caller logs + leaves the result alone so
            the consumer at least sees the ORIGINAL pool path and can
            decide for itself).
            """
            source = pooled.path
            workspace_root = Path(self.worktree_manager.workspace_dir)
            destination = (workspace_root / f"rollout_{rollout_id}").resolve()
            if destination == source.resolve():
                return destination
            if not source.exists():
                logger.warning(
                    "Cannot promote pooled worktree for rollout %s: "
                    "source path %s no longer exists.",
                    rollout_id,
                    source,
                )
                return None
            try:
                workspace_root.mkdir(parents=True, exist_ok=True)
                if destination.exists():
                    shutil.rmtree(destination, ignore_errors=True)
                # First try ``git worktree move``: it updates the admin
                # dir entry under ``<src_repo>/.git/worktrees/`` so
                # subsequent ``git`` operations against ``destination``
                # keep working. This is the supported path on
                # ``git >= 2.17``.
                git_move = subprocess.run(
                    ["git", "worktree", "move", str(source), str(destination)],
                    cwd=str(self.repo_path),
                    capture_output=True,
                    text=True,
                    check=False,
                )
                if git_move.returncode != 0:
                    # Fallback: a raw shutil.move + repair. ``git
                    # worktree repair`` rewrites the admin dir's
                    # ``gitdir`` file to point at the new location,
                    # restoring git semantics. Used when ``git
                    # worktree move`` rejects the move (e.g. dirty
                    # working tree, or a git version too old to
                    # support cross-FS moves).
                    err = (git_move.stderr or git_move.stdout or "").strip()
                    logger.info(
                        "git worktree move %s -> %s failed (%s); falling "
                        "back to shutil.move + git worktree repair.",
                        source,
                        destination,
                        err or "no stderr",
                    )
                    shutil.move(str(source), str(destination))
                    repair = subprocess.run(
                        ["git", "worktree", "repair", str(destination)],
                        cwd=str(self.repo_path),
                        capture_output=True,
                        text=True,
                        check=False,
                    )
                    if repair.returncode != 0:
                        # ``git worktree repair`` failed too — the
                        # promoted directory is still readable as a
                        # plain filesystem tree (good enough for
                        # ``shutil``-based scoring) but ``git`` calls
                        # will fail. Log and continue rather than
                        # crashing teardown.
                        repair_err = (repair.stderr or repair.stdout or "").strip()
                        logger.warning(
                            "git worktree repair failed for promoted %s: %s",
                            destination,
                            repair_err or "no stderr",
                        )
                relativize_git_worktree_metadata(destination)
            except Exception as exc:  # noqa: BLE001 - degrade gracefully
                logger.warning(
                    "Failed to promote pooled worktree for rollout %s from %s -> %s: %s",
                    rollout_id,
                    source,
                    destination,
                    exc,
                )
                return None
            return destination

        # Pass 1: promote every still-leased pool entry. The pool's
        # bookkeeping is the source of truth here; a worker can fail before
        # filling ``RolloutResult.worktree_path`` even though the lease still
        # points at the candidate worktree.
        for pool_path_str, pooled in list(self._pooled_by_path.items()):
            pooled_rollout_id = _pooled_rollout_id(pool_path_str, pooled)
            if pooled_rollout_id is None:
                logger.warning(
                    "Cannot promote pooled worktree at %s: missing rollout id.",
                    pool_path_str,
                )
                continue
            destination = _promote(pooled_rollout_id, pooled)
            if destination is None:
                continue
            destination_str = str(destination)
            promoted_result = result_by_rollout_id.get(pooled_rollout_id)
            if promoted_result is not None:
                promoted_result.worktree_path = destination_str
                self._persist_promoted_candidate_artifacts(promoted_result)
            worktree_path_by_rollout_id[pooled_rollout_id] = destination_str
            promoted_pool_entries.append((pool_path_str, pooled))
        # Pass 2: detach promoted pool entries from the pool so the
        # subsequent teardown doesn't try to ``git worktree remove``
        # the (now-moved-or-gone) source paths.
        if promoted_pool_entries and self._worktree_pool is not None:
            pool = self._worktree_pool
            for pool_path_str, pooled in promoted_pool_entries:
                # Drop our reverse-lookup so the per-rollout cleanup
                # can't double-handle the entry.
                self._pooled_by_path.pop(pool_path_str, None)
                self._pooled_by_path.pop(str(pooled.path), None)
                try:
                    self._pooled_by_path.pop(str(pooled.path.resolve()), None)
                except OSError:
                    pass
                # Drop from the pool's own bookkeeping. The semaphore
                # slot is implicitly forfeit — the per-task pool is
                # about to tear down anyway, and we need to keep the
                # promoted directory alive past that teardown.
                with pool._lock:  # noqa: SLF001 - intentional internal hook
                    pool._entries.pop(pooled.pool_index, None)  # noqa: SLF001

    def _persist_promoted_candidate_artifacts(self, result: RolloutResult) -> bool:
        """Persist the durable candidate handoff alongside promoted worktrees."""
        output_dir = Path(str(getattr(self.config, "output_dir", "") or "."))
        artifact_dir = output_dir / "_candidate_artifacts" / f"rollout_{result.rollout_id}"
        try:
            patch_text = self._materialize_candidate_patch_text(result)
            if not patch_text.strip() and not list(result.changed_files or []):
                return False
            self._ensure_candidate_validity_for_handoff(result)
            artifact_dir.mkdir(parents=True, exist_ok=True)
            (artifact_dir / "patch.diff").write_text(
                patch_text,
                encoding="utf-8",
            )
            (artifact_dir / "changed_files.json").write_text(
                json.dumps(list(result.changed_files), indent=2) + "\n",
                encoding="utf-8",
            )
            (artifact_dir / "quick_verification.json").write_text(
                json.dumps(dict(result.quick_verification), indent=2, sort_keys=True) + "\n",
                encoding="utf-8",
            )
            validity_payload = result.validity.as_dict() if result.validity is not None else None
            (artifact_dir / "validity.json").write_text(
                json.dumps(validity_payload, indent=2, sort_keys=True) + "\n",
                encoding="utf-8",
            )
            # CCEDF: durably escrow a confirmed-correct candidate at the instant
            # of promotion (write-ahead, fsync, idempotent) so it survives any
            # later cancel/OOM/container-reap/restart. Only authoritative local
            # full-scope passes are escrowed; the WAL is the cross-restart backstop
            # to the in-process A4 escrow.
            self._escrow_confirmed_candidate(result, patch_text=patch_text)
            return True
        except OSError as exc:
            logger.warning(
                "Failed to persist candidate artifacts for rollout %s: %s",
                result.rollout_id,
                exc,
            )
            return False

    def _escrow_confirmed_candidate(self, result: RolloutResult, *, patch_text: str = "") -> None:
        """CCEDF write hook: append a confirmed full-scope-pass candidate to the
        run-scoped escrow WAL. Best-effort and never raises into the caller."""
        try:
            quick_verification = (
                dict(result.quick_verification)
                if isinstance(result.quick_verification, dict)
                else {}
            )
            if not quick_verification_has_local_full_scope_pass(quick_verification):
                return
            output_dir = str(getattr(self.config, "output_dir", "") or "").strip()
            if not output_dir:
                return
            patch_payload = patch_text or self._materialize_candidate_patch_text(result)
            if not patch_payload.strip() and not list(result.changed_files or []):
                return
            task_id = self._escrow_task_id()
            EscrowStore(output_dir).escrow_confirmed_candidate(
                task_id=task_id,
                candidate_id=f"rollout_{result.rollout_id}",
                payload={
                    "rollout_id": result.rollout_id,
                    "patch": patch_payload,
                    "changed_files": list(result.changed_files or []),
                    "worktree_path": str(result.worktree_path or ""),
                    "quick_verification": quick_verification,
                    "llm_model": str(getattr(result, "llm_model", "") or ""),
                },
                kind="confirmed_full_scope_pass",
                score=1.0,
            )
        except Exception:  # noqa: BLE001 - escrow is a durability backstop, never fatal
            logger.debug("Confirmed-candidate escrow failed", exc_info=True)

    def _escrow_task_id(self) -> str:
        """A stable per-task identity for the escrow WAL (repo-scoped)."""
        repo_label = str(
            getattr(getattr(self, "repo_context", None), "repo_name", "") or ""
        ).strip()
        if repo_label:
            return repo_label
        return Path(str(self.repo_path or "task")).name or "task"

    def _materialize_candidate_patch_text(self, result: RolloutResult) -> str:
        patch_text = str(result.patch or "")
        if patch_text.strip():
            return patch_text
        raw_worktree_path = str(result.worktree_path or "").strip()
        if not raw_worktree_path:
            return patch_text
        worktree_path = Path(raw_worktree_path)
        if not worktree_path.is_dir():
            return patch_text
        baseline_ref = str(getattr(result, "baseline_commit", "") or "").strip() or None
        try:
            patch_text = self.worktree_manager.get_diff(
                worktree_path,
                baseline_ref=baseline_ref,
            )
        except Exception as exc:  # noqa: BLE001 - artifact recovery must not mask rollout result
            logger.warning(
                "Failed to recover patch text for candidate rollout %s from %s: %s",
                result.rollout_id,
                worktree_path,
                exc,
            )
            return str(result.patch or "")
        if patch_text.strip():
            result.patch = patch_text
            if not list(result.changed_files or []):
                try:
                    result.changed_files = self.worktree_manager.list_changed_files(
                        worktree_path,
                        baseline_ref=baseline_ref,
                    )
                except Exception as exc:  # noqa: BLE001 - keep recovered patch even if listing fails
                    logger.warning(
                        "Failed to recover changed files for candidate rollout %s from %s: %s",
                        result.rollout_id,
                        worktree_path,
                        exc,
                    )
        return patch_text

    def _has_candidate_handoff_signal(self, result: Optional[RolloutResult]) -> bool:
        if result is None:
            return False
        self._prepare_full_scope_candidate_handoff(result)
        if (
            result.patch
            or getattr(result, "best_checkpoint_id", None)
            or getattr(result, "selected_for_submission", False)
            or getattr(result, "internally_accepted", False)
            or getattr(result, "is_synthetic", False)
        ):
            return True
        return rollout_has_repairable_near_miss(result)

    def _recover_quick_verification_from_rollout_status(self, result: RolloutResult) -> None:
        existing_quick_verification = (
            dict(result.quick_verification) if isinstance(result.quick_verification, dict) else {}
        )
        try:
            rollout_states = load_rollout_live_states(self.config.output_dir)
        except Exception as exc:  # noqa: BLE001 - cleanup must not fail on diagnostics
            logger.debug(
                "Failed to load rollout status for quick-verification recovery: %s",
                exc,
            )
            return

        def _as_int(value: Any) -> Optional[int]:
            try:
                return int(value)
            except (TypeError, ValueError):
                return None

        result_rollout_id = _as_int(result.rollout_id)
        if result_rollout_id is None:
            return
        state = next(
            (
                payload
                for payload in rollout_states
                if _as_int(payload.get("rollout_id")) == result_rollout_id
            ),
            None,
        )
        if not isinstance(state, dict):
            return

        quick_verification = _quick_verification_payload_from_rollout_status(state)
        if not quick_verification:
            return
        if existing_quick_verification and not _quick_verification_from_status_is_stronger(
            existing_quick_verification,
            quick_verification,
        ):
            return
        quick_verification = _merge_quick_verification_detail(
            existing_quick_verification,
            quick_verification,
        )
        result.quick_verification = quick_verification
        result.search_metadata["quick_verification_recovered_from_rollout_status"] = True

    def _prepare_full_scope_candidate_handoff(self, result: RolloutResult) -> None:
        """Materialize patch evidence for full-scope verified worktrees."""

        self._recover_quick_verification_from_rollout_status(result)
        quick_verification = (
            result.quick_verification if isinstance(result.quick_verification, dict) else {}
        )
        if str(quick_verification.get("scope") or "").strip() != "full_test_command":
            return
        raw_worktree_path = str(result.worktree_path or "").strip()
        if not raw_worktree_path:
            return
        worktree_path = Path(raw_worktree_path)
        if not worktree_path.is_dir():
            return
        if not result.baseline_commit:
            try:
                result.baseline_commit = self.worktree_manager.get_baseline_commit(worktree_path)
            except Exception:
                result.baseline_commit = (
                    self._worktree_pool.base_commit
                    if self._worktree_pool is not None
                    else _resolve_head_commit(worktree_path)
                )
        if not result.patch:
            self._materialize_candidate_patch_text(result)

    def _promote_verified_scheduler_candidate(self, result: RolloutResult) -> None:
        """Let verified worktree candidates participate in stop/preemption.

        A CLI backend can fail while finalizing structured output after it has
        already produced a patch and run full-suite verification. The scheduler
        should treat that as a materialized candidate for search control instead
        of spending sibling rollout budget while final selection still performs
        the strict acceptance/audit checks.
        """

        if result.success:
            return
        quick_verification = (
            result.quick_verification if isinstance(result.quick_verification, dict) else {}
        )
        if not (
            quick_verification_has_local_full_scope_pass(quick_verification)
            or rollout_has_repairable_near_miss(result)
        ):
            return
        patch_text = self._materialize_candidate_patch_text(result)
        if not patch_text.strip() and not list(result.changed_files or []):
            return
        result.success = True
        result.search_metadata["verified_scheduler_candidate_promoted"] = True
        if result.failure_reason:
            result.search_metadata["verified_scheduler_candidate_failure_reason"] = (
                result.failure_reason
            )
        result.failure_reason = None
        self._ensure_candidate_validity_for_handoff(result)

    def _ensure_candidate_validity_for_handoff(self, result: RolloutResult) -> None:
        """Backfill a validity contract for recovered verified candidates."""

        if result.validity is not None:
            return
        quick_verification = (
            result.quick_verification if isinstance(result.quick_verification, dict) else {}
        )
        if not quick_verification:
            return
        metadata = result.search_metadata if isinstance(result.search_metadata, dict) else {}
        if not (
            quick_verification_has_local_full_scope_pass(quick_verification)
            or rollout_has_repairable_near_miss(result)
            or quick_verification_requires_authoritative_scoring(
                quick_verification,
                metadata=metadata,
            )
        ):
            return
        evidence_mode = ""
        coverage_collapse_terminal = False
        if metadata:
            evidence_mode = str(metadata.get("evidence_mode") or "").strip()
            coverage_collapse_terminal = bool(metadata.get("coverage_collapse_terminal"))
        result.validity = _candidate_validity_from_rollout(
            result,
            evidence_mode=evidence_mode,
            coverage_collapse_terminal=coverage_collapse_terminal,
        )
        if isinstance(result.search_metadata, dict):
            result.search_metadata["validity_backfilled_for_candidate_handoff"] = True

    def _should_keep_worktree(self, result: Optional[RolloutResult]) -> bool:
        """Return True if the rollout's worktree must survive post-batch.

        WHY: candidate handoff is broader than structured patch text. CLI
        rollouts can materialize a verified near-complete workspace but fail to
        serialize the patch; that workspace is still the best repair seed and
        must not be reset before selection or residual follow-up can branch
        from it.
        """
        if result is None:
            return False
        self._prepare_full_scope_candidate_handoff(result)
        if rollout_has_local_full_scope_completion(result):
            return True
        if rollout_has_repairable_near_miss(result):
            return True
        if self.config.rollout.keep_worktrees:
            return self._has_candidate_handoff_signal(result)
        return bool(getattr(result, "best_checkpoint_id", None))

    def _maybe_remove_completed_worktree(
        self,
        *,
        rollout_id: int,
        result: Optional[RolloutResult],
        worktree_path_by_rollout_id: dict[int, str],
        active_seed_worktree_paths: set[str],
    ) -> None:
        """Reclaim a finished rollout's worktree, gated on policy.

        Cleanup failures must not propagate — they would mask the rollout's
        own success/failure and crash the dispatcher. Log and continue.
        """
        if self._should_keep_worktree(result):
            if result is not None:
                self._persist_promoted_candidate_artifacts(result)
            return
        worktree_path = worktree_path_by_rollout_id.get(rollout_id)
        if not worktree_path:
            return
        if worktree_path in active_seed_worktree_paths:
            # A sibling request in this batch is still cloning from this path;
            # leaving this to cleanup_all() / finally is the safe choice.
            return
        # Decisive-Edge C.5 — pooled worktrees are returned to the pool
        # rather than removed. The pool's reset step (``git checkout .``
        # + ``git clean -fdx`` + ``git reset --hard {base_commit}``) is
        # the equivalent of remove + recreate but ~10x faster for the
        # common case (a sibling rollout will pick this slot up next).
        pooled = self._pooled_by_path.pop(worktree_path, None)
        if pooled is not None and self._worktree_pool is not None:
            try:
                confirm_patch_extracted = result is None or not result.patch
                if result is not None and result.patch:
                    confirm_patch_extracted = self._persist_promoted_candidate_artifacts(result)
                self._worktree_pool.release(
                    pooled,
                    reset=True,
                    confirm_patch_extracted=confirm_patch_extracted,
                )
                return
            except Exception as release_exc:  # noqa: BLE001 - degrade
                logger.warning(
                    "Failed to release pooled worktree for rollout %s at %s: %s",
                    rollout_id,
                    worktree_path,
                    release_exc,
                )
                # Fall through to legacy removal so the worktree slot
                # doesn't leak.
        try:
            self.worktree_manager.remove_worktree(Path(worktree_path))
        except Exception as cleanup_exc:  # noqa: BLE001
            logger.warning(
                "Failed to remove worktree for rollout %s at %s: %s",
                rollout_id,
                worktree_path,
                cleanup_exc,
            )

    # ------------------------------------------------------------------
    # Decisive-Edge C.5 — Worktree pool integration
    # ------------------------------------------------------------------

    def _maybe_init_worktree_pool(
        self,
        rollout_requests: list[RolloutRequest],
    ) -> None:
        """Lazy-construct the worktree pool for this batch when enabled.

        The pool is constructed once per ``execute_rollout_requests``
        invocation so the per-task safety contract holds (the source
        repo / baseline_commit must be stable for the pool's lifetime).
        Falls back silently to the legacy per-rollout worktree path on
        any pool construction failure.
        """
        rollout_cfg = getattr(self.config, "rollout", None)
        if not bool(getattr(rollout_cfg, "use_worktree_pool", False)):
            return
        # The pool relies on ``git worktree add`` for every entry; when
        # ``use_git_worktrees=False`` (snapshot-only mode used for
        # dirty source repos / non-git workspaces) we MUST stay on the
        # legacy path. The snapshot ``GitWorktreeManager`` codepath
        # produces deterministic baselines that pool reset can't
        # replicate.
        if not bool(getattr(rollout_cfg, "use_git_worktrees", True)):
            return
        # Worktree-seed handoff is incompatible with pool reuse — each
        # seed clones from a *different* baseline so there's no win
        # from pre-warming. Skip the pool when any request requests a
        # workspace_seed and let the legacy path handle it.
        if any(r.workspace_seed is not None for r in rollout_requests):
            return
        # Discard any stale pool from a prior task on this engine.
        if self._worktree_pool is not None:
            try:
                self._worktree_pool.cleanup()
            except Exception:  # noqa: BLE001
                logger.exception("Failed to clean up stale WorktreePool")
            self._worktree_pool = None
        self._pooled_by_path.clear()
        configured_size = max(0, int(getattr(rollout_cfg, "worktree_pool_size", 0) or 0))
        if configured_size <= 0:
            configured_size = len(rollout_requests)
        configured_size = max(1, configured_size)
        try:
            base_commit = self._resolve_pool_base_commit()
            self._worktree_pool = WorktreePool(
                source_repo=Path(self.repo_path),
                pool_size=configured_size,
                run_scope=self._run_id,
                base_commit=base_commit,
                pool_dir=Path(self._workspace_dir) / "_pool",
                eager_warmup=False,
            )
        except Exception as exc:  # noqa: BLE001 - degrade silently
            logger.warning(
                "WorktreePool construction failed (%s: %s); falling back to "
                "per-rollout worktree creation.",
                type(exc).__name__,
                exc,
            )
            self._worktree_pool = None

    def _resolve_pool_base_commit(self) -> Optional[str]:
        """Resolve the source repo's HEAD as the pool's pinned baseline."""
        try:
            return _resolve_head_commit(Path(self.repo_path)) or None
        except Exception:  # noqa: BLE001
            return None

    def _acquire_worktree_for_request(
        self,
        request: "RolloutRequest",
    ) -> tuple[Path, Optional[PooledWorktree]]:
        """Lease a worktree from the pool, falling back to the legacy path.

        Returns ``(path, pooled_entry_or_None)``. ``None`` signals to
        the cleanup path that the worktree was created via the
        ``GitWorktreeManager`` and should be torn down with
        ``remove_worktree`` rather than released back to the pool.
        """
        # Workspace-seed handoff always uses the legacy path — the pool
        # entries don't carry the seed's baseline.
        if request.workspace_seed is not None or self._worktree_pool is None:
            worktree_path = self._create_legacy_worktree_with_collision_retry(
                request,
            )
            return worktree_path, None
        try:
            pooled = self._worktree_pool.acquire(
                rollout_id=str(request.rollout_id),
                timeout=120.0,
            )
            return pooled.path, pooled
        except WorktreePoolExhausted:
            logger.warning(
                "WorktreePool exhausted for rollout %s; falling back to "
                "per-rollout worktree creation.",
                request.rollout_id,
            )
        except Exception as exc:  # noqa: BLE001 - degrade silently
            logger.warning(
                "WorktreePool acquire raised for rollout %s (%s: %s); "
                "falling back to per-rollout worktree creation.",
                request.rollout_id,
                type(exc).__name__,
                exc,
            )
        worktree_path = self._create_legacy_worktree_with_collision_retry(
            request,
        )
        return worktree_path, None

    def _create_legacy_worktree_with_collision_retry(
        self,
        request: "RolloutRequest",
    ) -> Path:
        last_error: Optional[ConcurrentWorktreeError] = None
        for attempt in range(4):
            rollout_key: Any = request.rollout_id
            if attempt:
                rollout_key = f"{request.rollout_id}_retry_{attempt}_{uuid.uuid4().hex[:8]}"
            try:
                worktree_path = self.worktree_manager.create_worktree(
                    rollout_key,
                    seed=request.workspace_seed,
                )
                if attempt:
                    logger.warning(
                        "Worktree lock collision for rollout %s recovered with workspace key %s.",
                        request.rollout_id,
                        rollout_key,
                    )
                return worktree_path
            except ConcurrentWorktreeError as exc:
                last_error = exc
                logger.warning(
                    "Worktree lock collision for rollout %s on attempt %s: %s",
                    request.rollout_id,
                    attempt + 1,
                    exc,
                )
                continue
        if last_error is not None:
            raise last_error
        raise RuntimeError(f"Failed to create worktree for rollout {request.rollout_id}")

    def cleanup(self) -> None:
        quarantined_paths = set(getattr(self, "_quarantined_worktree_paths", set()) or set())
        # Decisive-Edge C.5 — fold-in worktree pool teardown so a
        # caller that bypasses ``execute_rollout_requests`` (e.g. the
        # solve() teardown after an early-return) still reclaims pool
        # resources.
        if self._worktree_pool is not None:
            try:
                self._worktree_pool.cleanup()
            except Exception:  # noqa: BLE001
                logger.exception("Failed to clean up WorktreePool during engine cleanup")
            self._worktree_pool = None
            self._pooled_by_path.clear()
        if quarantined_paths:
            logger.warning(
                "Skipping RolloutEngine worktree cleanup because %s deadline-expired "
                "worker workspace(s) are quarantined: %s",
                len(quarantined_paths),
                sorted(quarantined_paths),
            )
        else:
            self.worktree_manager.cleanup_all()
        # Phase 2.5: drop scoped CLI registrations now that the worktrees
        # are gone. Termination already happens per-rollout on deadline,
        # so this is just bookkeeping.
        try:
            self._cli_registry.clear()
        except Exception:  # pragma: no cover - defensive bookkeeping
            logger.exception("Failed to clear per-rollout CLI registry")
        # Phase 2.1: if we minted a per-solve scratch directory in
        # __init__, remove it so /tmp doesn't accumulate one apex_solve_*
        # entry per RolloutEngine instance.
        if getattr(self, "_owns_workspace_dir", False):
            workspace_dir = getattr(self, "_workspace_dir", None)
            if workspace_dir:
                if quarantined_paths:
                    logger.warning(
                        "Leaving per-solve workspace %s on disk because it contains "
                        "quarantined deadline-expired worker paths.",
                        workspace_dir,
                    )
                else:
                    try:
                        shutil.rmtree(workspace_dir, ignore_errors=True)
                    except Exception:  # pragma: no cover - defensive cleanup
                        logger.exception(
                            "Failed to remove per-solve workspace %s",
                            workspace_dir,
                        )
